def pressure_from_altitude_air(altitude_m: float) -> float:
    """Atmospheric pressure for air/above-sea-level road/aircraft cases."""
    if altitude_m >= 0:
        return P0 * (1 - 2.25577e-5 * altitude_m) ** 5.25588
    # If the user enters a negative value for air, interpret it as below sea level.
    depth = abs(altitude_m)
    return P0 + 1.225 * G * depth


def pressure_from_depth_water(depth_m: float, water_density: float = 1025.0) -> float:
    """Hydrostatic water pressure using user depth relative to sea level."""
    return P0 + water_density * G * max(float(depth_m), 0.0)


def pressure_from_altitude(altitude_m: float) -> float:
    """Backward-compatible default pressure function."""
    if altitude_m >= 0:
        return pressure_from_altitude_air(altitude_m)
    return pressure_from_depth_water(abs(altitude_m), 1025.0)


def get_environment(altitude_m: float, fluid: str = "Air", simulation_mode: str = "Standard CFD Mode"):
    if simulation_mode == "Multi-Vehicle Mode":
        if fluid == "Air":
            if altitude_m > 0:
                return "Aircraft Vehicle Mode", "Air"
            return "Ground Vehicle Mode", "Air"
        if fluid == "Water":
            return "Submersible / Marine Vehicle Mode", "Water"
        return "Multi-Vehicle Mode", fluid
    return "Standard CFD Mode", fluid


def coolprop_fluid_name(fluid: str) -> str:
    return COOLPROP_NAME_MAP.get(fluid, fluid)


def get_fluid_properties(
    fluid: str,
    pressure_pa: float,
    temperature_k: float,
    property_basis: str = "Pressure",
    secondary_value: float | None = None,
    flow_area_m2: float | None = None,
    velocity_m_s: float | None = None,
):
    """
    Returns:
      rho, mu, property_source, resolved_pressure_pa

    Multi-Vehicle air/water path:
      - pressure comes from position relative to sea level.
      - properties use T + pressure.

    Standard CFD path:
      - position relative to sea level is ignored.
      - all fluids use temperature plus mass flow rate.
      - density is calculated from mass continuity:
            rho = m_dot / (V * A_flow)
        where A_flow is the projected/reference flow area once geometry is loaded.
    """
    fluid = str(fluid)
    temperature_k = max(float(temperature_k), 1e-9)
    pressure_pa = max(float(pressure_pa), 1e-9)
    property_basis = property_basis or "Pressure"

    # Handle seawater as a special water-like fallback/CoolProp hybrid.
    if fluid == "Seawater":
        base = FALLBACK_FLUID_PROPERTIES["Seawater"]
        return base["rho"], base["mu"], base["note"], pressure_pa

    cp_name = coolprop_fluid_name(fluid)

    if COOLPROP_AVAILABLE and fluid not in ["Diesel Fuel", "Gasoline", "Engine Oil", "Hydraulic Oil", "Natural Gas", "Seawater"]:
        try:
            if property_basis == "Mass Flow Rate":
                mdot = max(float(secondary_value), 0.0)
                area = max(float(flow_area_m2) if flow_area_m2 is not None else 0.0, 1e-18)
                vel = max(abs(float(velocity_m_s)) if velocity_m_s is not None else 0.0, 1e-18)
                rho_in = mdot / (vel * area)
                rho = max(rho_in, 1e-12)
                mu = PropsSI("V", "D", rho, "T", temperature_k, cp_name)
                p_resolved = PropsSI("P", "D", rho, "T", temperature_k, cp_name)
                return rho, mu, f"CoolProp lookup using T + mass flow rate for {fluid}; rho = mdot/(V*A_flow)", p_resolved

            if property_basis == "Density":
                rho_in = max(float(secondary_value), 1e-12)
                rho = rho_in
                mu = PropsSI("V", "D", rho_in, "T", temperature_k, cp_name)
                p_resolved = PropsSI("P", "D", rho_in, "T", temperature_k, cp_name)
                return rho, mu, f"CoolProp lookup using T + density for {fluid}", p_resolved

            # Specific gravity is converted to density using water reference density.
            if property_basis == "Specific Gravity":
                sg = max(float(secondary_value), 1e-12)
                rho_in = sg * 997.0
                rho = rho_in
                mu = PropsSI("V", "D", rho_in, "T", temperature_k, cp_name)
                p_resolved = PropsSI("P", "D", rho_in, "T", temperature_k, cp_name)
                return rho, mu, f"CoolProp lookup using T + specific gravity for {fluid}", p_resolved

            # Default pressure-basis lookup.
            p_in = max(float(secondary_value) if secondary_value is not None else pressure_pa, 1e-9)
            rho = PropsSI("D", "P", p_in, "T", temperature_k, cp_name)
            mu = PropsSI("V", "P", p_in, "T", temperature_k, cp_name)
            return rho, mu, f"CoolProp lookup using T + pressure for {fluid}", p_in

        except Exception as cp_error:
            # Fall back below instead of stopping the app.
            fallback_reason = f"CoolProp lookup failed for {fluid}: {cp_error}. Using fallback estimate."
    else:
        fallback_reason = "Fallback estimate"

    base = FALLBACK_FLUID_PROPERTIES.get(fluid, FALLBACK_FLUID_PROPERTIES["Air"]).copy()

    # Air ideal gas fallback should use actual pressure/temperature.
    if fluid == "Air":
        rho = pressure_pa / (R_AIR * temperature_k)
        mu = base["mu"]
        return rho, mu, "ideal-gas air fallback using sea-level position pressure", pressure_pa

    # Water pressure still uses sea-level/depth position; density/viscosity fallback.
    if fluid == "Water":
        rho = base["rho"]
        mu = base["mu"]
        return rho, mu, "liquid water fallback using sea-level/depth pressure", pressure_pa

    # Other fluids: mass flow rate is converted to density using rho = mdot/(V*A_flow).
    if property_basis == "Mass Flow Rate" and secondary_value is not None:
        mdot = max(float(secondary_value), 0.0)
        area = max(float(flow_area_m2) if flow_area_m2 is not None else 0.0, 1e-18)
        vel = max(abs(float(velocity_m_s)) if velocity_m_s is not None else 0.0, 1e-18)
        rho = max(mdot / (vel * area), 1e-12)
        mu = base["mu"]
        return rho, mu, f"{fallback_reason} Mass flow converted to density using rho = mdot/(V*A_flow); viscosity from {base['note']}", pressure_pa

    # Other fluids: if user supplied density or SG, honor it even without CoolProp.
    if property_basis == "Density" and secondary_value is not None:
        rho = max(float(secondary_value), 1e-12)
        mu = base["mu"]
        return rho, mu, f"{fallback_reason} Density provided by user; viscosity from {base['note']}", pressure_pa

    if property_basis == "Specific Gravity" and secondary_value is not None:
        rho = max(float(secondary_value), 1e-12) * 997.0
        mu = base["mu"]
        return rho, mu, f"{fallback_reason} Specific gravity provided by user; viscosity from {base['note']}", pressure_pa

    # Pressure-basis fallback: use table density/viscosity, keep entered pressure.
    p_in = max(float(secondary_value) if secondary_value is not None else pressure_pa, 1e-9)
    return base["rho"], base["mu"], f"{fallback_reason}: {base['note']}", p_in



