def estimate_cd(shape_type: str) -> float:
    cd_table = {
        "Streamlined body": 0.08,
        "Airfoil-like body": 0.05,
        "Car-like body": 0.30,
        "Sphere-like body": 0.47,
        "Cylinder-like body": 1.10,
        "Flat/blunt body": 1.20,
        "Custom/unknown uploaded geometry": 0.80,
    }
    return cd_table.get(shape_type, 0.80)


def equivalent_diameter_from_area(area: float) -> float:
    """
    Converts projected frontal area to equivalent circular diameter.

    A = pi D² / 4
    D = sqrt(4A/pi)
    """
    return float(np.sqrt(max(4.0 * area / np.pi, 1e-18)))


def drag_coefficient_sphere_from_re(re: float) -> float:
    """
    Empirical sphere Cd estimate.

    Valid as a practical first-pass estimate:
    - Re < 1: Stokes equivalent Cd = 24/Re
    - 1 <= Re < 1000: Schiller-Naumann style correction
    - Re >= 1000: approximate turbulent sphere Cd
    """
    re = max(float(re), 1e-12)

    if re < 1.0:
        return 24.0 / re
    if re < 1000.0:
        return (24.0 / re) * (1.0 + 0.15 * re**0.687)
    return 0.44


def corrected_cd_from_shape_and_re(shape_type: str, re: float, user_cd: float) -> tuple[float, str]:
    """
    Returns Cd and a note describing the source.

    For sphere-like objects, Cd is estimated from Reynolds number.
    For other objects, user/shape Cd is retained until CFD is added.
    """
    if shape_type == "Sphere-like body":
        return drag_coefficient_sphere_from_re(re), "Sphere Cd estimated from Reynolds number"

    return float(user_cd), "Shape/user Cd estimate"


def quadratic_drag_force(rho: float, velocity: float, coefficient: float, area: float) -> float:
    return 0.5 * rho * velocity**2 * coefficient * area


def stokes_drag_force(mu: float, velocity: float, equivalent_diameter: float) -> float:
    """
    Stokes drag for creeping flow around a sphere:
    F = 3*pi*mu*V*D

    For uploaded non-spherical geometry, D is an equivalent diameter from projected area.
    """
    return 3.0 * np.pi * mu * velocity * equivalent_diameter


def reynolds_number(rho: float, velocity: float, length: float, mu: float) -> float:
    return rho * velocity * length / max(mu, 1e-30)


def auto_select_turbulence_model(fluid: str, reynolds: float, is_external_flow: bool = True):
    """
    Automatically selects the CFD turbulence model using Reynolds number and application type.

    Rule of thumb:
      Re < 2,300      -> laminar
      Re >= 2,300     -> kOmegaSST for external/submerged bodies
      kEpsilon is reserved for internal duct/pipe-style flow.
    """
    re_val = max(float(reynolds), 0.0)
    fluid_name = str(fluid).lower()

    if re_val < 2300.0:
        return "laminar", "Re < 2,300: laminar flow selected."

    if is_external_flow or fluid_name in ["water", "seawater", "liquid", "liquid water"]:
        return "kOmegaSST", "Turbulent external/submerged body flow: kOmegaSST selected for drag, separation, and wake prediction."

    return "kEpsilon", "Turbulent internal/duct-style flow: kEpsilon selected."




def auto_cfd_mesh_settings(bounds: dict, faces=None, accuracy_mode: str = "accuracy_first"):
    """
    Automatically sizes OpenFOAM domain and mesh controls from uploaded object size.

    Accuracy-first intent:
      - no manual user mesh controls
      - domain grows with object size
      - base cells increase for larger objects
      - surface refinement increases for large/complex meshes
      - downstream domain is long enough for wake formation

    Safe behavior:
      - if no geometry is uploaded yet, return conservative defaults and do not raise a traceback.
    """
    if bounds is None:
        face_count = int(len(faces)) if faces is not None else 0
        return {
            "base_cell_count": 36,
            "refinement_level": 4,
            "domain_scale_upstream": 5.0,
            "domain_scale_downstream": 10.0,
            "domain_scale_cross": 5.0,
            "max_object_dimension_m": 1.0,
            "face_count": face_count,
            "note": "Waiting for geometry upload. Conservative CFD defaults are held in the background.",
        }

    max_dim = max(
        _numeric_from_value(bounds.get("x_length", 1.0), default=1.0),
        _numeric_from_value(bounds.get("y_length", 1.0), default=1.0),
        _numeric_from_value(bounds.get("z_length", 1.0), default=1.0),
        1e-9,
    )

    face_count = int(len(faces)) if faces is not None else 0

    upstream = 5.0
    downstream = 10.0
    cross = 5.0

    if max_dim < 0.05:
        base_cells = 24
        refinement = 3
    elif max_dim < 0.5:
        base_cells = 30
        refinement = 3
    elif max_dim < 2.0:
        base_cells = 36
        refinement = 4
    elif max_dim < 10.0:
        base_cells = 44
        refinement = 4
    else:
        base_cells = 50
        refinement = 5

    if face_count > 50000:
        refinement = max(refinement, 4)
    if face_count > 150000:
        refinement = 5

    return {
        "base_cell_count": int(base_cells),
        "refinement_level": int(refinement),
        "domain_scale_upstream": float(upstream),
        "domain_scale_downstream": float(downstream),
        "domain_scale_cross": float(cross),
        "max_object_dimension_m": float(max_dim),
        "face_count": int(face_count),
        "note": (
            f"Automated accuracy-first mesh: max object dimension={max_dim:.4g} m, "
            f"faces={face_count:,}, base cells={base_cells}, refinement={refinement}, "
            f"domain={upstream}x upstream / {downstream}x downstream / {cross}x crossflow."
        ),
    }


def select_drag_model(
    fluid: str,
    rho: float,
    mu: float,
    velocity: float,
    area: float,
    length: float,
    shape_type: str,
    user_cd: float,
):
    """
    Selects the drag model.

    Air:
      Uses quadratic drag F = 1/2 rho V² Cd A

    Liquid / water:
      Uses Stokes law only for creeping flow, Re < 1.
      Uses quadratic drag for Re >= 1.

    Returns a dictionary with force, Cd, Re, model name, and equivalent diameter.
    """
    area = max(float(area), 1e-18)
    length = max(float(length), 1e-12)
    equivalent_diameter = equivalent_diameter_from_area(area)

    # For Stokes, characteristic length should be the equivalent diameter.
    stokes_re = reynolds_number(rho, velocity, equivalent_diameter, mu)
    general_re = reynolds_number(rho, velocity, length, mu)

    is_liquid = fluid.lower() in ["water", "seawater", "liquid", "liquid water"]

    if is_liquid and stokes_re < 1.0:
        fd = stokes_drag_force(mu, velocity, equivalent_diameter)
        cd_equiv = 24.0 / max(stokes_re, 1e-12)

        return {
            "drag_force": fd,
            "cd_used": cd_equiv,
            "reynolds": stokes_re,
            "model": "Stokes drag: F = 3πμVD",
            "model_note": "Valid for creeping liquid flow, Re < 1. D is equivalent diameter from projected area.",
            "equivalent_diameter": equivalent_diameter,
        }

    cd_used, cd_note = corrected_cd_from_shape_and_re(shape_type, general_re, user_cd)
    fd = quadratic_drag_force(rho, velocity, cd_used, area)

    if is_liquid:
        model = "Quadratic hydrodynamic drag: F = 1/2 ρV²CdA"
        note = "Liquid flow Re ≥ 1, so Stokes law is not valid; using quadratic drag."
    else:
        model = "Quadratic aerodynamic drag: F = 1/2 ρV²CdA"
        note = "Air mode uses dynamic-pressure drag. " + cd_note

    return {
        "drag_force": fd,
        "cd_used": cd_used,
        "reynolds": general_re,
        "model": model,
        "model_note": note,
        "equivalent_diameter": equivalent_diameter,
    }



def terminal_velocity(
    fluid: str,
    rho: float,
    mu: float,
    mass_kg: float,
    volume_m3: float,
    area_m2: float,
    length_m: float,
    shape_type: str,
    user_cd: float,
):
    """
    Calculates terminal velocity from net force balance.

    Downward effective force:
      W_eff = mg - buoyancy

    If W_eff <= 0:
      object is neutrally buoyant or buoyant in the selected fluid.

    For liquid creeping flow:
      W_eff = 3*pi*mu*V*D

    Otherwise:
      W_eff = 1/2*rho*V²*Cd*A
    """
    mass_kg = max(float(mass_kg), 0.0)
    volume_m3 = max(float(volume_m3), 0.0)
    area_m2 = max(float(area_m2), 1e-18)
    length_m = max(float(length_m), 1e-12)

    weight_n = mass_kg * G
    buoyancy_n = rho * G * volume_m3
    effective_weight_n = weight_n - buoyancy_n

    equivalent_diameter = equivalent_diameter_from_area(area_m2)
    is_liquid = fluid.lower() in ["water", "seawater", "liquid", "liquid water"]

    if effective_weight_n <= 0:
        return {
            "terminal_velocity": 0.0,
            "weight_n": weight_n,
            "buoyancy_n": buoyancy_n,
            "effective_weight_n": effective_weight_n,
            "model": "No downward terminal velocity",
            "note": "Buoyancy is greater than or equal to weight. The object is neutrally buoyant or rises.",
            "cd_used": 0.0,
            "reynolds_terminal": 0.0,
            "equivalent_diameter": equivalent_diameter,
        }

    # First check liquid Stokes terminal speed.
    if is_liquid:
        vt_stokes = effective_weight_n / max(3.0 * np.pi * mu * equivalent_diameter, 1e-30)
        re_stokes = reynolds_number(rho, vt_stokes, equivalent_diameter, mu)

        if re_stokes < 1.0:
            cd_equiv = 24.0 / max(re_stokes, 1e-12)
            return {
                "terminal_velocity": vt_stokes,
                "weight_n": weight_n,
                "buoyancy_n": buoyancy_n,
                "effective_weight_n": effective_weight_n,
                "model": "Stokes terminal velocity",
                "note": "Liquid creeping-flow terminal velocity. Valid because Re < 1.",
                "cd_used": cd_equiv,
                "reynolds_terminal": re_stokes,
                "equivalent_diameter": equivalent_diameter,
            }

    # Quadratic terminal speed. Cd for a sphere can be iterated because Cd depends on Re.
    cd_guess = max(float(user_cd), 1e-6)

    if shape_type == "Sphere-like body":
        vt = np.sqrt(2.0 * effective_weight_n / max(rho * cd_guess * area_m2, 1e-30))

        for _ in range(12):
            re = reynolds_number(rho, vt, length_m, mu)
            cd_guess = drag_coefficient_sphere_from_re(re)
            vt = np.sqrt(2.0 * effective_weight_n / max(rho * cd_guess * area_m2, 1e-30))

        re_terminal = reynolds_number(rho, vt, length_m, mu)
        cd_used = cd_guess
        cd_note = "Sphere Cd iterated from Reynolds number."
    else:
        cd_used = max(float(user_cd), 1e-6)
        vt = np.sqrt(2.0 * effective_weight_n / max(rho * cd_used * area_m2, 1e-30))
        re_terminal = reynolds_number(rho, vt, length_m, mu)
        cd_note = "Cd is shape/user estimate."

    return {
        "terminal_velocity": vt,
        "weight_n": weight_n,
        "buoyancy_n": buoyancy_n,
        "effective_weight_n": effective_weight_n,
        "model": "Quadratic terminal velocity",
        "note": cd_note,
        "cd_used": cd_used,
        "reynolds_terminal": re_terminal,
        "equivalent_diameter": equivalent_diameter,
    }


def net_force_at_velocity(
    drag_force_n: float,
    mass_kg: float,
    volume_m3: float,
    rho: float,
):
    """
    Net vertical force for a falling object with drag opposing motion:
      F_net_down = W - B - D

    Positive means object still accelerates downward.
    Negative means drag/buoyancy exceed weight.
    """
    weight_n = max(float(mass_kg), 0.0) * G
    buoyancy_n = rho * G * max(float(volume_m3), 0.0)
    return weight_n - buoyancy_n - drag_force_n


def altitude_for_terminal_velocity_air(
    velocity: float,
    mass_kg: float,
    volume_m3: float,
    cd: float,
    area_m2: float,
    temperature_k: float,
):
    """
    Estimates the altitude where the input velocity equals terminal velocity in air.

    Uses:
      rho_required = 2(W - B_air)/(Cd A V²)

    Buoyancy is small in air. We include it approximately by solving with W only
    for stability, then compare required density to sea-level density.

    Barometric inversion:
      P/P0 = (1 - 2.25577e-5 h)^5.25588
      rho = P/(R*T)
    """
    velocity = max(float(velocity), 1e-12)
    area_m2 = max(float(area_m2), 1e-18)
    cd = max(float(cd), 1e-8)
    weight_n = max(float(mass_kg), 0.0) * G

    if weight_n <= 0:
        return None, "Mass is zero; no terminal altitude can be calculated."

    rho_required = 2.0 * weight_n / (cd * area_m2 * velocity**2)
    rho_sea_level = P0 / (R_AIR * temperature_k)

    if rho_required <= 0:
        return None, "Required air density is nonphysical."

    pressure_required = rho_required * R_AIR * temperature_k
    ratio = pressure_required / P0

    if ratio <= 0:
        return None, "Required pressure is nonphysical."

    # If ratio > 1, required density is greater than sea-level air density at this temperature.
    if ratio > 1.0:
        return None, (
            "The required air density is greater than sea-level density. "
            "At this velocity, drag is too low at normal altitude; terminal balance would require denser air."
        )

    altitude = (1.0 - ratio ** (1.0 / 5.25588)) / 2.25577e-5
    return float(altitude), f"Required air density = {rho_required:.6g} kg/m³."


def buoyancy_force(rho: float, volume: float) -> float:
    return rho * G * volume

# -----------------------------
# Unit and direction functions
# -----------------------------
def unit_scale_to_meters(unit_name: str) -> float:
    scale_map = {
        "Meters": 1.0,
        "Millimeters": 0.001,
        "Centimeters": 0.01,
        "Inches": 0.0254,
        "Feet": 0.3048,
    }
    return scale_map.get(unit_name, 0.001)


def front_vector(front_selection: str) -> np.ndarray:
    vectors = {
        "+X front": np.array([1.0, 0.0, 0.0]),
        "-X front": np.array([-1.0, 0.0, 0.0]),
        "+Y front": np.array([0.0, 1.0, 0.0]),
        "-Y front": np.array([0.0, -1.0, 0.0]),
        "+Z front": np.array([0.0, 0.0, 1.0]),
        "-Z front": np.array([0.0, 0.0, -1.0]),
    }
    return vectors.get(front_selection, np.array([1.0, 0.0, 0.0]))


def flow_vector_from_front(front_selection: str) -> np.ndarray:
    # Flow moves into the selected front face.
    return -front_vector(front_selection)


def selected_axis(front_selection: str) -> str:
    if "X" in front_selection:
        return "X"
    if "Y" in front_selection:
        return "Y"
    return "Z"


def characteristic_length_from_bounds(bounds: dict, front_selection: str) -> float:
    axis = selected_axis(front_selection)
    if axis == "X":
        return max(abs(bounds["x_length"]), 1e-12)
    if axis == "Y":
        return max(abs(bounds["y_length"]), 1e-12)
    return max(abs(bounds["z_length"]), 1e-12)


# -----------------------------
# Mesh geometry math
# -----------------------------
def bounds_from_coords(coords: np.ndarray) -> dict:
    bounds = {
        "x_min": float(coords[:, 0].min()),
        "x_max": float(coords[:, 0].max()),
        "y_min": float(coords[:, 1].min()),
        "y_max": float(coords[:, 1].max()),
        "z_min": float(coords[:, 2].min()),
        "z_max": float(coords[:, 2].max()),
    }
    bounds["x_length"] = bounds["x_max"] - bounds["x_min"]
    bounds["y_length"] = bounds["y_max"] - bounds["y_min"]
    bounds["z_length"] = bounds["z_max"] - bounds["z_min"]
    return bounds


def face_area_vectors(coords_m: np.ndarray, faces: np.ndarray):
    tri = coords_m[faces]
    v1 = tri[:, 1, :] - tri[:, 0, :]
    v2 = tri[:, 2, :] - tri[:, 0, :]
    area_vectors = 0.5 * np.cross(v1, v2)
    areas = np.linalg.norm(area_vectors, axis=1)

    normals = np.zeros_like(area_vectors)
    valid = areas > 0
    normals[valid] = area_vectors[valid] / areas[valid, None]

    centroids = np.mean(tri, axis=1)
    return areas, area_vectors, normals, centroids


def projected_mesh_area(coords_m: np.ndarray, faces: np.ndarray, front_selection: str) -> float:
    _, area_vectors, _, _ = face_area_vectors(coords_m, faces)
    n_front = front_vector(front_selection)
    return float(np.sum(np.abs(area_vectors @ n_front)) / 2.0)


def front_oriented_surface_area(coords_m: np.ndarray, faces: np.ndarray, front_selection: str) -> float:
    areas, _, normals, _ = face_area_vectors(coords_m, faces)
    exposure = normals @ front_vector(front_selection)
    mask = exposure > 0.15
    return float(np.sum(areas[mask]))


def mesh_quality_status(mesh_obj):
    return {
        "is_watertight": bool(mesh_obj.is_watertight),
        "is_winding_consistent": bool(mesh_obj.is_winding_consistent),
        "euler_number": mesh_obj.euler_number,
        "faces": int(len(mesh_obj.faces)),
        "vertices": int(len(mesh_obj.vertices)),
    }


# -----------------------------
# File loading and cleaning
# -----------------------------
def save_uploaded_file(uploaded_file, suffix: str):
    with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
        tmp.write(uploaded_file.getbuffer())
        return tmp.name


def clean_trimesh_mesh(mesh_obj):
    mesh_obj = mesh_obj.copy()

    try:
        mesh_obj.remove_duplicate_faces()
    except Exception:
        pass

    try:
        mesh_obj.remove_degenerate_faces()
    except Exception:
        pass

    try:
        mesh_obj.remove_unreferenced_vertices()
    except Exception:
        pass

    try:
        mesh_obj.merge_vertices()
    except Exception:
        pass

    try:
        mesh_obj.fix_normals()
    except Exception:
        pass

    return mesh_obj


def load_mesh_file(uploaded_file, file_units: str, clean_mesh: bool):
    if not TRIMESH_AVAILABLE:
        raise RuntimeError("trimesh is not installed. Run: python -m pip install trimesh")

    ext = os.path.splitext(uploaded_file.name.lower())[1]

    if ext not in [".stl", ".obj", ".ply"]:
        raise RuntimeError("Unsupported file type. Accuracy mode only supports STL, OBJ, and PLY.")

    path = save_uploaded_file(uploaded_file, ext)
    unit_scale_m = unit_scale_to_meters(file_units)

    try:
        loaded = trimesh.load(path, force="mesh")

        if isinstance(loaded, trimesh.Scene):
            loaded = trimesh.util.concatenate(tuple(loaded.geometry.values()))

        if loaded.vertices is None or loaded.faces is None or len(loaded.vertices) == 0 or len(loaded.faces) == 0:
            raise RuntimeError("No mesh geometry found in uploaded file.")

        raw_mesh = loaded.copy()
        mesh = clean_trimesh_mesh(loaded) if clean_mesh else loaded

        clean_vertices_native = np.asarray(mesh.vertices, dtype=float)
        coords_m = clean_vertices_native * unit_scale_m
        faces = np.asarray(mesh.faces, dtype=int)

        native_bounds = bounds_from_coords(clean_vertices_native)
        bounds_m = bounds_from_coords(coords_m)

        surface_area_m2 = float(mesh.area) * unit_scale_m**2

        if mesh.is_watertight:
            volume_m3 = abs(float(mesh.volume)) * unit_scale_m**3
            volume_source = "trimesh watertight volume"
        else:
            volume_m3 = abs(bounds_m["x_length"] * bounds_m["y_length"] * bounds_m["z_length"])
            volume_source = "bounding-box fallback volume"

        quality = mesh_quality_status(mesh)
        raw_quality = mesh_quality_status(raw_mesh)

        return {
            "coords_m": coords_m,
            "faces": faces,
            "native_bounds": native_bounds,
            "bounds_m": bounds_m,
            "surface_area_m2": surface_area_m2,
            "volume_m3": volume_m3,
            "volume_source": volume_source,
            "quality": quality,
            "raw_quality": raw_quality,
            "unit_scale_m": unit_scale_m,
        }

    finally:
        try:
            os.remove(path)
        except Exception:
            pass


# -----------------------------
# Visualization field models
# -----------------------------
def front_face_mask(coords_m: np.ndarray, faces: np.ndarray, front_selection: str, threshold: float):
    _, _, normals, centroids = face_area_vectors(coords_m, faces)
    n_front = front_vector(front_selection)
    exposure = normals @ n_front
    mask = exposure > threshold

    if np.sum(mask) < 3:
        axis = selected_axis(front_selection)
        idx = {"X": 0, "Y": 1, "Z": 2}[axis]
        coord = centroids[:, idx]
        if front_selection.startswith("+"):
            cutoff = np.percentile(coord, 95)
            mask = coord >= cutoff
        else:
            cutoff = np.percentile(coord, 5)
            mask = coord <= cutoff

    return mask


def qualitative_pressure_field(coords_m, faces, front_selection, rho, velocity, static_pressure):
    n_front = front_vector(front_selection)
    q = 0.5 * rho * velocity**2

    _, _, normals, centroids = face_area_vectors(coords_m, faces)
    exposure = np.maximum(normals @ n_front, 0.0)

    if float(np.max(exposure)) < 0.1:
        exposure = np.abs(normals @ n_front)

    pressure = static_pressure + q * exposure**1.5
    return pressure


def qualitative_velocity_field(coords_m, faces, front_selection, velocity):
    n_front = front_vector(front_selection)
    flow_vec = flow_vector_from_front(front_selection)

    _, _, normals, centroids = face_area_vectors(coords_m, faces)

    stagnation = np.maximum(normals @ n_front, 0.0)
    tangential = np.sqrt(np.maximum(1.0 - stagnation**2, 0.0))

    # Fast sides, slow stagnation front. This is not CFD, but useful visually.
    local_speed = velocity * (0.18 + 1.25 * tangential)
    local_speed = np.clip(local_speed, 0.0, 1.45 * max(velocity, 1e-9))

    return local_speed


def vertex_values_from_faces(coords_m, faces, face_values):
    vertex_values = np.zeros(len(coords_m))
    count = np.zeros(len(coords_m))

    for face, val in zip(faces, face_values):
        for idx in face:
            vertex_values[idx] += val
            count[idx] += 1

    count[count == 0] = 1
    return vertex_values / count



# -----------------------------
# Level 2 panel-style solver
# -----------------------------
def panel_solver_cp(coords_m, faces, front_selection, rho, velocity, static_pressure):
    """
    Fast inviscid panel-style pressure coefficient estimate.

    This is not a full vortex/source panel method yet. It treats each mesh triangle
    as a panel, estimates local pressure coefficient from flow incidence, then
    integrates pressure force over the mesh.

    Outputs:
      Cp per face
      pressure per face
      pressure force vector
      drag/lift force components
    """
    flow_vec = flow_vector_from_front(front_selection)
    n_front = front_vector(front_selection)

    areas, area_vectors, normals, centroids = face_area_vectors(coords_m, faces)

    q = 0.5 * rho * velocity**2

    # Exposure to incoming flow. Front/stagnation panels have exposure near 1.
    exposure = np.maximum(normals @ n_front, 0.0)

    # Tangential speed estimate: stagnation at front, accelerated along sides.
    # Cp = 1 - (V_local/V_inf)^2
    v_ratio = np.sqrt(np.maximum(1.0 - exposure**2, 0.0))
    v_ratio = np.clip(v_ratio * 1.15, 0.0, 1.35)

    cp = 1.0 - v_ratio**2

    # Back-side wake suction approximation for separated blunt-body flow.
    back_exposure = np.maximum(normals @ (-n_front), 0.0)
    cp = cp - 0.25 * back_exposure

    # Clamp to a practical visualization/engineering first-pass range.
    cp = np.clip(cp, -1.2, 1.0)

    pressure = static_pressure + q * cp

    # Pressure force on body from fluid:
    # Force = - integral((p - p_inf) n dA)
    gauge_pressure = q * cp
    panel_forces = -gauge_pressure[:, None] * normals * areas[:, None]
    total_force = np.sum(panel_forces, axis=0)

    drag_force_panel = float(np.dot(total_force, flow_vec))

    # Pick display lift direction perpendicular to flow.
    lift_dir = np.array([0.0, 0.0, 1.0])
    if abs(np.dot(lift_dir, flow_vec)) > 0.8:
        lift_dir = np.array([0.0, 1.0, 0.0])

    lift_force_panel = float(np.dot(total_force, lift_dir))

    moment_center = np.array([
        np.mean(coords_m[:, 0]),
        np.mean(coords_m[:, 1]),
        np.mean(coords_m[:, 2]),
    ])

    moments = np.cross(centroids - moment_center[None, :], panel_forces)
    total_moment = np.sum(moments, axis=0)

    return {
        "cp_face": cp,
        "pressure_face": pressure,
        "panel_forces": panel_forces,
        "total_force_vector": total_force,
        "drag_force": drag_force_panel,
        "lift_force": lift_force_panel,
        "moment_vector": total_moment,
        "cp_min": float(np.min(cp)),
        "cp_max": float(np.max(cp)),
        "pressure_min": float(np.min(pressure)),
        "pressure_max": float(np.max(pressure)),
        "q": q,
    }


def vertex_values_from_faces_weighted(coords_m, faces, face_values):
    vertex_values = np.zeros(len(coords_m))
    count = np.zeros(len(coords_m))

    for face, val in zip(faces, face_values):
        for idx in face:
            vertex_values[idx] += val
            count[idx] += 1

    count[count == 0] = 1
    return vertex_values / count


def make_panel_cp_figure(coords_m, faces, bounds, front_selection, panel_result, show_streamlines=True, show_wake=True):
    cp_vertex = vertex_values_from_faces_weighted(coords_m, faces, panel_result["cp_face"])

    fig = go.Figure()

    fig.add_trace(
        go.Mesh3d(
            x=coords_m[:, 0],
            y=coords_m[:, 1],
            z=coords_m[:, 2],
            i=faces[:, 0],
            j=faces[:, 1],
            k=faces[:, 2],
            intensity=cp_vertex,
            colorscale=[
                [0.0, "blue"],
                [0.25, "cyan"],
                [0.50, "lime"],
                [0.75, "yellow"],
                [1.0, "red"],
            ],
            cmin=-1.2,
            cmax=1.0,
            colorbar=dict(title="Object pressure coefficient Cp"),
            opacity=0.96,
            flatshading=True,
            name="Cp surface",
        )
    )

    if show_wake:
        fig.add_trace(make_wake_cone(bounds, front_selection))

    if show_streamlines:
        for trace in make_streamlines(bounds, front_selection, streamline_count=9):
            fig.add_trace(trace)

    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])

    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    flow_vec = flow_vector_from_front(front_selection)
    force_vec = panel_result["total_force_vector"]

    force_mag = np.linalg.norm(force_vec)
    if force_mag > 0:
        force_dir = force_vec / force_mag
        fig.add_trace(
            go.Cone(
                x=[center[0]],
                y=[center[1]],
                z=[center[2]],
                u=[force_dir[0]],
                v=[force_dir[1]],
                w=[force_dir[2]],
                sizemode="absolute",
                sizeref=0.35 * max_len,
                anchor="tail",
                name="Integrated pressure force",
                showscale=False,
            )
        )

    flow_start = center - flow_vec * 1.8 * max_len
    fig.add_trace(
        go.Cone(
            x=[flow_start[0]],
            y=[flow_start[1]],
            z=[flow_start[2]],
            u=[flow_vec[0]],
            v=[flow_vec[1]],
            w=[flow_vec[2]],
            sizemode="absolute",
            sizeref=0.25 * max_len,
            anchor="tail",
            name="Incoming flow",
            showscale=False,
        )
    )

    fig.update_layout(
        title=f"Level 2 Panel-Style Cp Solver — Front: {front_selection}",
        scene=dict(xaxis_title="X [m]", yaxis_title="Y [m]", zaxis_title="Z [m]", aspectmode="data"),
        height=760,
        margin=dict(l=0, r=0, t=40, b=0),
        showlegend=False,
    )

    return fig


# -----------------------------
# Level 1 3D visualization figures
# -----------------------------
def make_geometry_figure(coords_m, faces, bounds, front_selection, highlight_threshold):
    mask = front_face_mask(coords_m, faces, front_selection, highlight_threshold)
    front_faces = faces[mask]

    fig = go.Figure()

    fig.add_trace(
        go.Mesh3d(
            x=coords_m[:, 0],
            y=coords_m[:, 1],
            z=coords_m[:, 2],
            i=faces[:, 0],
            j=faces[:, 1],
            k=faces[:, 2],
            opacity=float(0.10 + 0.35 * streamline_pronounce),
            flatshading=True,
            name="Object mesh",
            color="lightgray",
        )
    )

    if len(front_faces) > 0:
        fig.add_trace(
            go.Mesh3d(
                x=coords_m[:, 0],
                y=coords_m[:, 1],
                z=coords_m[:, 2],
                i=front_faces[:, 0],
                j=front_faces[:, 1],
                k=front_faces[:, 2],
                opacity=0.95,
                flatshading=True,
                name="Front-oriented diagnostic faces",
                color="red",
            )
        )

    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])
    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    flow_vec = flow_vector_from_front(front_selection)
    cone_pos = center - flow_vec * 1.3 * max_len

    fig.add_trace(
        go.Cone(
            x=[cone_pos[0]],
            y=[cone_pos[1]],
            z=[cone_pos[2]],
            u=[flow_vec[0]],
            v=[flow_vec[1]],
            w=[flow_vec[2]],
            sizemode="absolute",
            sizeref=0.25 * max_len,
            anchor="tail",
            name="Flow direction",
            showscale=False,
        )
    )

    fig.update_layout(
        title=f"3D Viewer — Selected Front: {front_selection}",
        scene=dict(xaxis_title="X [m]", yaxis_title="Y [m]", zaxis_title="Z [m]", aspectmode="data"),
        height=700,
        margin=dict(l=0, r=0, t=40, b=0),
        showlegend=True,
    )

    return fig


def make_streamlines(bounds, front_selection, streamline_count=9, streamline_spread=1.6, bend_strength=0.45, wake_strength=0.35):
    flow_vec = flow_vector_from_front(front_selection)

    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])

    lengths = np.array([max(bounds["x_length"], 1e-9), max(bounds["y_length"], 1e-9), max(bounds["z_length"], 1e-9)])
    max_len = float(np.max(lengths))
    domain_pad = 2.8 * max_len

    if abs(flow_vec[0]) > 0.5:
        a = np.array([0.0, 1.0, 0.0])
        b = np.array([0.0, 0.0, 1.0])
    elif abs(flow_vec[1]) > 0.5:
        a = np.array([1.0, 0.0, 0.0])
        b = np.array([0.0, 0.0, 1.0])
    else:
        a = np.array([1.0, 0.0, 0.0])
        b = np.array([0.0, 1.0, 0.0])

    cross_size = max_len * streamline_spread
    offsets = np.linspace(-cross_size, cross_size, int(streamline_count))
    stream_traces = []

    t = np.linspace(-domain_pad, domain_pad, 150)
    body_radius = 0.55 * max_len

    for oa in offsets:
        for ob in offsets:
            if abs(oa) < 0.18 * cross_size and abs(ob) < 0.18 * cross_size:
                continue

            base = center + oa * a + ob * b
            pts = base[None, :] + t[:, None] * flow_vec[None, :]

            rel = pts - center[None, :]
            axial = rel @ flow_vec
            radial_vec = rel - axial[:, None] * flow_vec[None, :]
            radial_dist = np.linalg.norm(radial_vec, axis=1)
            radial_dir = radial_vec / np.maximum(radial_dist[:, None], 1e-9)

            # Bend around body near center.
            influence = np.exp(-(axial / (0.7 * max_len))**2) * np.exp(-(radial_dist / (1.2 * body_radius))**2)
            bend = body_radius * bend_strength * influence
            pts = pts + radial_dir * bend[:, None]

            # Wake spreading downstream of object.
            downstream = axial > 0
            wake_influence = downstream * np.exp(-np.maximum(axial, 0.0) / (1.4 * max_len)) * np.exp(-(radial_dist / (1.0 * body_radius))**2)
            pts = pts + radial_dir * (wake_strength * body_radius * wake_influence)[:, None]

            stream_traces.append(
                go.Scatter3d(
                    x=pts[:, 0],
                    y=pts[:, 1],
                    z=pts[:, 2],
                    mode="lines",
                    line=dict(width=3),
                    opacity=0.42,
                    name="Streamline",
                    showlegend=False,
                )
            )

    return stream_traces


def make_wake_cone(bounds, front_selection, wake_length_factor=2.0, wake_radius_factor=0.55):
    flow_vec = flow_vector_from_front(front_selection)

    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])

    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    start = center + flow_vec * 0.55 * max_len
    end = center + flow_vec * wake_length_factor * max_len

    if abs(flow_vec[0]) > 0.5:
        a = np.array([0.0, 1.0, 0.0])
        b = np.array([0.0, 0.0, 1.0])
    elif abs(flow_vec[1]) > 0.5:
        a = np.array([1.0, 0.0, 0.0])
        b = np.array([0.0, 0.0, 1.0])
    else:
        a = np.array([1.0, 0.0, 0.0])
        b = np.array([0.0, 1.0, 0.0])

    theta = np.linspace(0, 2 * np.pi, 36)
    zeta = np.linspace(0, 1, 16)

    xs, ys, zs = [], [], []
    radius0 = wake_radius_factor * max_len

    for s in zeta:
        point = start * (1 - s) + end * s
        radius = radius0 * (0.55 + 0.75 * s)
        ring = point[None, :] + radius * np.cos(theta)[:, None] * a[None, :] + radius * np.sin(theta)[:, None] * b[None, :]
        xs.append(ring[:, 0])
        ys.append(ring[:, 1])
        zs.append(ring[:, 2])

    return go.Surface(
        x=np.array(xs),
        y=np.array(ys),
        z=np.array(zs),
        opacity=0.18,
        showscale=False,
        name="Wake region",
    )


def make_boundary_layer_shell(coords_m, faces, bounds, thickness_factor=0.035):
    areas, _, normals, _ = face_area_vectors(coords_m, faces)
    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    shell_coords = coords_m + normals_for_vertices(coords_m, faces) * thickness_factor * max_len

    return go.Mesh3d(
        x=shell_coords[:, 0],
        y=shell_coords[:, 1],
        z=shell_coords[:, 2],
        i=faces[:, 0],
        j=faces[:, 1],
        k=faces[:, 2],
        opacity=0.13,
        flatshading=True,
        name="Boundary layer shell",
        color="cyan",
        showscale=False,
    )


def normals_for_vertices(coords_m, faces):
    areas, area_vectors, normals, _ = face_area_vectors(coords_m, faces)
    vnorm = np.zeros_like(coords_m)
    count = np.zeros(len(coords_m))

    for face, normal in zip(faces, normals):
        for idx in face:
            vnorm[idx] += normal
            count[idx] += 1

    mag = np.linalg.norm(vnorm, axis=1)
    mag[mag == 0] = 1.0
    return vnorm / mag[:, None]


def make_level1_flow_figure(
    coords_m,
    faces,
    bounds,
    front_selection,
    rho,
    velocity,
    static_pressure,
    show_pressure=True,
    show_velocity=False,
    show_streamlines=True,
    show_wake=True,
    show_boundary_layer=True,
    streamline_count=9,
):
    face_pressure = qualitative_pressure_field(coords_m, faces, front_selection, rho, velocity, static_pressure)
    vertex_pressure = vertex_values_from_faces(coords_m, faces, face_pressure)

    face_speed = qualitative_velocity_field(coords_m, faces, front_selection, velocity)
    vertex_speed = vertex_values_from_faces(coords_m, faces, face_speed)

    fig = go.Figure()

    if show_velocity:
        intensity = vertex_speed
        colorscale = [
            [0.0, "blue"],
            [0.25, "cyan"],
            [0.55, "lime"],
            [0.80, "yellow"],
            [1.0, "red"],
        ]
        colorbar_title = "Speed [m/s]"
        title = "Velocity Map"
    else:
        intensity = vertex_pressure
        colorscale = [
            [0.0, "blue"],
            [0.35, "cyan"],
            [0.55, "lime"],
            [0.75, "yellow"],
            [1.0, "red"],
        ]
        colorbar_title = "Pressure [Pa]"
        title = "Pressure Map"

    fig.add_trace(
        go.Mesh3d(
            x=coords_m[:, 0],
            y=coords_m[:, 1],
            z=coords_m[:, 2],
            i=faces[:, 0],
            j=faces[:, 1],
            k=faces[:, 2],
            intensity=intensity,
            colorscale=colorscale,
            colorbar=dict(title=colorbar_title),
            opacity=0.94,
            flatshading=True,
            name=title,
        )
    )

    if show_boundary_layer:
        fig.add_trace(make_boundary_layer_shell(coords_m, faces, bounds))

    if show_wake:
        fig.add_trace(make_wake_cone(bounds, front_selection))

    if show_streamlines:
        for trace in make_streamlines(bounds, front_selection, streamline_count=streamline_count):
            fig.add_trace(trace)

    # Flow arrow
    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])
    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    flow_vec = flow_vector_from_front(front_selection)
    cone_pos = center - flow_vec * 1.8 * max_len

    fig.add_trace(
        go.Cone(
            x=[cone_pos[0]],
            y=[cone_pos[1]],
            z=[cone_pos[2]],
            u=[flow_vec[0]],
            v=[flow_vec[1]],
            w=[flow_vec[2]],
            sizemode="absolute",
            sizeref=0.25 * max_len,
            anchor="tail",
            name="Incoming flow",
            showscale=False,
        )
    )

    fig.update_layout(
        title=f"Level 1 Flow Visualization — {title} — Front: {front_selection}",
        scene=dict(xaxis_title="X [m]", yaxis_title="Y [m]", zaxis_title="Z [m]", aspectmode="data"),
        height=760,
        margin=dict(l=0, r=0, t=40, b=0),
        showlegend=False,
    )

    return fig, float(np.min(vertex_pressure)), float(np.max(vertex_pressure)), float(np.min(vertex_speed)), float(np.max(vertex_speed))



# -----------------------------
# CFD Design Optimization Mode
# -----------------------------
def _axis_index_from_front(front_selection: str) -> int:
    if "X" in str(front_selection):
        return 0
    if "Y" in str(front_selection):
        return 1
    return 2


def _optimization_variant_geometry(area, length, volume, front_selection, scale_flow=1.0, scale_cross=1.0, scale_vertical=1.0):
    axis = _axis_index_from_front(front_selection)
    scales = np.array([scale_cross, scale_cross, scale_vertical], dtype=float)
    scales[axis] = scale_flow
    non_flow = [i for i in range(3) if i != axis]
    area_new = max(float(area) * float(scales[non_flow[0]] * scales[non_flow[1]]), 1e-18)
    length_new = max(float(length) * float(scales[axis]), 1e-12)
    volume_new = max(float(volume) * float(np.prod(scales)), 0.0)
    return area_new, length_new, volume_new


def _design_cd_factor(objective, scale_flow, scale_cross, scale_vertical, angle_deg):
    angle = abs(float(angle_deg))
    slenderness = max(float(scale_flow), 1e-9) / max(float(scale_cross), 1e-9)
    drag_shape_factor = 1.0 / (1.0 + 0.38 * max(slenderness - 1.0, 0.0))
    angle_penalty = 1.0 + 0.012 * angle + 0.0009 * angle**2
    vertical_lift_factor = 1.0 + 0.55 * max(float(scale_vertical) - 1.0, 0.0)

    if objective == "Minimize Drag":
        cd_factor = drag_shape_factor * angle_penalty
        lift_factor = 0.10 * np.sin(np.radians(angle))
    elif objective == "Maximize Lift":
        cd_factor = drag_shape_factor * (1.0 + 0.45 * abs(np.sin(np.radians(angle))))
        lift_factor = max(0.05, np.sin(np.radians(angle)) * vertical_lift_factor)
    elif objective == "Maximize Downforce":
        cd_factor = drag_shape_factor * (1.0 + 0.55 * abs(np.sin(np.radians(angle))))
        lift_factor = -max(0.05, np.sin(np.radians(angle)) * vertical_lift_factor)
    elif objective == "Minimize Pressure Load":
        cd_factor = 0.70 * drag_shape_factor + 0.30 * (1.0 / max(float(scale_cross * scale_vertical), 1e-9))
        lift_factor = 0.0
    else:
        cd_factor = drag_shape_factor
        lift_factor = 0.0

    return max(float(cd_factor), 0.05), float(lift_factor)


def run_cfd_design_optimization(objective, area, length, volume, rho, mu, velocity, mass_kg, front_selection, base_cd, max_variants=45, include_angle_sweep=True):
    objective = str(objective)
    max_variants = int(max(5, min(max_variants, 250)))

    scale_flow_values = [0.75, 0.90, 1.00, 1.15, 1.35, 1.60]
    scale_cross_values = [0.75, 0.90, 1.00, 1.10, 1.25]
    scale_vertical_values = [0.75, 0.90, 1.00, 1.15, 1.35]
    angle_values = [-12, -6, 0, 6, 12] if include_angle_sweep else [0]

    rows = []
    base_area = max(float(area), 1e-18)
    base_len = max(float(length), 1e-12)
    base_vol = max(float(volume), 0.0)
    base_cd = max(float(base_cd), 0.02)

    for sf in scale_flow_values:
        for sc in scale_cross_values:
            for sv in scale_vertical_values:
                for angle in angle_values:
                    a_new, l_new, v_new = _optimization_variant_geometry(base_area, base_len, base_vol, front_selection, sf, sc, sv)
                    cd_factor, cl_est = _design_cd_factor(objective, sf, sc, sv, angle)
                    cd_est_opt = max(base_cd * cd_factor, 0.02)

                    q = 0.5 * float(rho) * float(velocity) ** 2
                    re_opt = reynolds_number(float(rho), float(velocity), l_new, float(mu))
                    drag_n = quadratic_drag_force(float(rho), float(velocity), cd_est_opt, a_new)
                    lift_n = quadratic_drag_force(float(rho), float(velocity), cl_est, a_new)
                    buoy_n = buoyancy_force(float(rho), v_new)
                    weight_n = max(float(mass_kg), 0.0) * G
                    net_down = weight_n - buoy_n - drag_n
                    pressure_load = q * cd_est_opt
                    pressure_load_total = pressure_load * a_new

                    if objective == "Minimize Drag":
                        score = drag_n
                    elif objective == "Maximize Lift":
                        score = -lift_n
                    elif objective == "Maximize Downforce":
                        score = lift_n
                    elif objective == "Minimize Pressure Load":
                        score = pressure_load_total
                    else:
                        score = drag_n

                    rows.append({
                        "Rank Score": score,
                        "Design Change": f"Flow length x{sf:.2f}, width x{sc:.2f}, height x{sv:.2f}, angle {angle:+.0f}°",
                        "Flow Length Scale": sf,
                        "Width/Crossflow Scale": sc,
                        "Height/Vertical Scale": sv,
                        "Angle [deg]": angle,
                        "Projected Area [m²]": a_new,
                        "Characteristic Length [m]": l_new,
                        "Volume [m³]": v_new,
                        "Estimated Cd": cd_est_opt,
                        "Estimated Cl": cl_est,
                        "Drag Force [N]": drag_n,
                        "Lift(+)/Downforce(-) [N]": lift_n,
                        "Pressure Load [N]": pressure_load_total,
                        "Reynolds Number": re_opt,
                        "Net Downward Force [N]": net_down,
                    })

    df = pd.DataFrame(rows)
    if df.empty:
        return df
    df = df.sort_values("Rank Score", ascending=True).head(max_variants).reset_index(drop=True)
    df.insert(0, "Rank", np.arange(1, len(df) + 1))
    return df


def make_design_optimization_figure(opt_df, objective):
    fig = go.Figure()
    if opt_df is None or len(opt_df) == 0:
        fig.update_layout(title="CFD Design Optimization Results")
        return fig

    top = opt_df.head(12).copy()
    if objective == "Minimize Drag":
        y_name = "Drag Force [N]"
    elif objective in ["Maximize Lift", "Maximize Downforce"]:
        y_name = "Lift(+)/Downforce(-) [N]"
    elif objective == "Minimize Pressure Load":
        y_name = "Pressure Load [N]"
    else:
        y_name = "Drag Force [N]"

    fig.add_trace(go.Bar(
        x=top["Rank"].astype(str),
        y=top[y_name],
        text=[f"#{r}" for r in top["Rank"]],
        hovertext=top["Design Change"],
        hovertemplate="Rank %{x}<br>" + y_name + ": %{y:.6g}<br>%{hovertext}<extra></extra>",
        name=y_name,
    ))
    fig.update_layout(
        title=f"CFD Design Optimization — {objective}",
        xaxis_title="Candidate Rank",
        yaxis_title=y_name,
        height=460,
        margin=dict(l=10, r=10, t=55, b=45),
    )
    return fig


def make_optimized_geometry_preview(coords_m, faces, bounds, front_selection, best_row):
    coords = np.asarray(coords_m, dtype=float)
    tri = np.asarray(faces, dtype=int)
    axis = _axis_index_from_front(front_selection)
    scales = np.array([
        float(best_row.get("Width/Crossflow Scale", 1.0)),
        float(best_row.get("Width/Crossflow Scale", 1.0)),
        float(best_row.get("Height/Vertical Scale", 1.0)),
    ], dtype=float)
    scales[axis] = float(best_row.get("Flow Length Scale", 1.0))

    ctr = np.mean(coords, axis=0)
    scaled = ctr + (coords - ctr) * scales[None, :]

    fig = go.Figure()
    fig.add_trace(go.Mesh3d(
        x=coords[:, 0], y=coords[:, 1], z=coords[:, 2],
        i=tri[:, 0], j=tri[:, 1], k=tri[:, 2],
        color="lightgray", opacity=0.22, name="Original geometry",
        flatshading=True, showscale=False,
    ))
    fig.add_trace(go.Mesh3d(
        x=scaled[:, 0], y=scaled[:, 1], z=scaled[:, 2],
        i=tri[:, 0], j=tri[:, 1], k=tri[:, 2],
        color="limegreen", opacity=0.82, name="Optimized candidate preview",
        flatshading=True, showscale=False,
    ))

    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)
    center = np.mean(coords, axis=0)
    flow_vec = flow_vector_from_front(front_selection)
    upstream = center - flow_vec * 1.6 * max_len
    fig.add_trace(go.Cone(
        x=[upstream[0]], y=[upstream[1]], z=[upstream[2]],
        u=[flow_vec[0]], v=[flow_vec[1]], w=[flow_vec[2]],
        sizemode="absolute", sizeref=0.25 * max_len,
        anchor="tail", colorscale=[[0, "cyan"], [1, "cyan"]],
        name="Incoming flow", showscale=False,
    ))
    fig.update_layout(
        title="Optimized Geometry Preview — Original vs Candidate",
        scene=dict(xaxis_title="X [m]", yaxis_title="Y [m]", zaxis_title="Z [m]", aspectmode="data"),
        height=640,
        margin=dict(l=0, r=0, t=45, b=0),
        showlegend=True,
    )
    return fig



def make_force_vector_figure(coords_m, faces, bounds, front_selection, fd, fl, rho=None, velocity=None, static_pressure=None, side_force=0.0):
    """
    Force-vector customer view.

    V3.84 correction:
    The surface pressure/loading colors are now scaled from the same calculated
    drag, lift, and side-force values displayed in the results panel. Earlier
    versions colored the object from an independent pressure heuristic, so the
    red/blue regions did not correspond to the reported force values.
    """
    fig = go.Figure()

    rho_v = _numeric_from_value(rho, keys=["rho", "density"], default=1.225)
    velocity_v = _numeric_from_value(velocity, keys=["velocity", "speed", "V"], default=30.0)
    pressure_v = _numeric_from_value(static_pressure, keys=["pressure", "p"], default=P0)

    coords = np.asarray(coords_m, dtype=float)
    tri = np.asarray(faces, dtype=int)

    center = np.array([
        0.5 * (bounds["x_min"] + bounds["x_max"]),
        0.5 * (bounds["y_min"] + bounds["y_max"]),
        0.5 * (bounds["z_min"] + bounds["z_max"]),
    ])
    max_len = max(bounds["x_length"], bounds["y_length"], bounds["z_length"], 1e-9)

    flow_vec = flow_vector_from_front(front_selection)
    drag_vec = flow_vec / max(np.linalg.norm(flow_vec), 1e-12)

    lift_vec = np.array([0.0, 0.0, 1.0])
    if abs(np.dot(drag_vec, lift_vec)) > 0.8:
        lift_vec = np.array([0.0, 1.0, 0.0])

    side_vec = np.cross(drag_vec, lift_vec)
    side_vec = side_vec / max(np.linalg.norm(side_vec), 1e-12)

    fd_v = _numeric_from_value(fd, default=0.0)
    fl_v = _numeric_from_value(fl, default=0.0)
    side_v = _numeric_from_value(side_force, default=0.0)

    desired_force = fd_v * drag_vec + fl_v * lift_vec + side_v * side_vec
    desired_mag = float(np.linalg.norm(desired_force))

    areas, _, normals, centroids = face_area_vectors(coords, tri)

    # ---------------------------------------------------------------------
    # Build a displayed face loading field that is mathematically tied to the
    # reported calculated force vector.
    #
    # For each surface face, positive load acts inward: dF_i = -p_load_i A_i n_i.
    # A face receives loading when its inward normal aligns with the calculated
    # resultant force direction. The pressure scale is solved so that the
    # integrated displayed loads match the calculated resultant as closely as the
    # coarse uploaded mesh allows.
    # ---------------------------------------------------------------------
    load_pa = np.zeros(len(tri), dtype=float)
    integrated_visual_force = np.zeros(3, dtype=float)

    if desired_mag > 1e-18 and len(tri) > 0:
        force_dir = desired_force / desired_mag
        alignment = np.maximum(0.0, np.dot(-normals, force_dir))

        # Avoid a completely blank map if a coarse mesh orientation gives weak alignment.
        if float(np.max(alignment)) <= 1e-12:
            alignment = np.maximum(0.0, np.dot(normals, force_dir))

        base_force = np.sum((-normals) * (areas * alignment)[:, None], axis=0)
        denom = float(np.dot(base_force, base_force))

        if denom > 1e-30:
            scale_pa = max(float(np.dot(desired_force, base_force) / denom), 0.0)
        else:
            scale_pa = 0.0

        load_pa = scale_pa * alignment
        integrated_visual_force = np.sum((-normals) * (areas * load_pa)[:, None], axis=0)

    # Colorbar represents pressure loading above ambient, not a separate heuristic.
    # Blue = low load, lime/yellow = moderate, red = highest load.
    vertex_load_pa = vertex_values_from_faces_weighted(coords, tri, load_pa)
    max_load = float(np.nanmax(load_pa)) if load_pa.size else 0.0
    cmax = max(max_load, 1e-12)

    fig.add_trace(
        go.Mesh3d(
            x=coords[:, 0],
            y=coords[:, 1],
            z=coords[:, 2],
            i=tri[:, 0],
            j=tri[:, 1],
            k=tri[:, 2],
            intensity=vertex_load_pa,
            colorscale=[
                [0.0, "blue"],
                [0.35, "cyan"],
                [0.60, "limegreen"],
                [0.82, "yellow"],
                [1.0, "red"],
            ],
            cmin=0.0,
            cmax=cmax,
            colorbar=dict(
                title="Calculated pressure<br>loading [Pa]<br>scaled to forces",
                x=1.02,
                len=0.70,
                thickness=18,
            ),
            opacity=0.98,
            flatshading=True,
            name="Calculated pressure loading",
            hovertemplate=(
                "Displayed pressure loading: %{intensity:.6g} Pa<br>"
                f"Ambient/static pressure: {pressure_v:.6g} Pa<br>"
                "This field is scaled to the reported drag/lift/side forces.<extra></extra>"
            ),
        )
    )

    # Black wireframe / outline for clarity.
    try:
        fig.add_trace(
            go.Mesh3d(
                x=coords[:, 0],
                y=coords[:, 1],
                z=coords[:, 2],
                i=tri[:, 0],
                j=tri[:, 1],
                k=tri[:, 2],
                color="rgba(0,0,0,0.05)",
                opacity=0.05,
                flatshading=True,
                name="Object outline",
                showscale=False,
            )
        )
    except Exception:
        pass

    # Local pressure load arrows — use the same load_pa field, so arrows match colors.
    try:
        if load_pa.size and float(np.nanmax(load_pa)) > 1e-12:
            threshold = np.nanpercentile(load_pa, 70)
            candidate = np.where(load_pa >= threshold)[0]
            if candidate.size > 0:
                candidate = candidate[np.linspace(0, candidate.size - 1, min(28, candidate.size)).astype(int)]
                arrow_start = centroids[candidate] + normals[candidate] * (0.11 * max_len)
                arrow_dir = -normals[candidate]
                intensity = load_pa[candidate]

                fig.add_trace(
                    go.Cone(
                        x=arrow_start[:, 0],
                        y=arrow_start[:, 1],
                        z=arrow_start[:, 2],
                        u=arrow_dir[:, 0],
                        v=arrow_dir[:, 1],
                        w=arrow_dir[:, 2],
                        sizemode="absolute",
                        sizeref=0.14 * max_len,
                        anchor="tail",
                        colorscale=[
                            [0.0, "limegreen"],
                            [0.55, "yellow"],
                            [1.0, "red"],
                        ],
                        cmin=0.0,
                        cmax=cmax,
                        showscale=False,
                        opacity=0.88,
                        name="Local pressure load arrows",
                        hovertemplate="Local pressure load arrow<br>load=%{u:.3g}, %{v:.3g}, %{w:.3g}<extra></extra>",
                    )
                )
    except Exception:
        pass

    # Resultant force vectors. These use the exact calculated values.
    mag_ref = max(abs(fd_v), abs(fl_v), abs(side_v), 1e-9)
    drag_scale = 0.95 * max_len * np.sign(fd_v if abs(fd_v) > 1e-30 else 1.0) * min(abs(fd_v) / mag_ref, 1.0)
    lift_scale = 0.95 * max_len * np.sign(fl_v if abs(fl_v) > 1e-30 else 1.0) * min(abs(fl_v) / mag_ref, 1.0)
    side_scale = 0.95 * max_len * np.sign(side_v if abs(side_v) > 1e-30 else 1.0) * min(abs(side_v) / mag_ref, 1.0)

    fig.add_trace(
        go.Cone(
            x=[center[0]], y=[center[1]], z=[center[2]],
            u=[drag_vec[0] * drag_scale],
            v=[drag_vec[1] * drag_scale],
            w=[drag_vec[2] * drag_scale],
            sizemode="absolute",
            sizeref=0.28 * max_len,
            anchor="tail",
            colorscale=[[0, "red"], [1, "red"]],
            name=f"Calculated drag = {fd_v:.6g} N",
            showscale=False,
        )
    )

    if abs(fl_v) > 1e-12:
        fig.add_trace(
            go.Cone(
                x=[center[0]], y=[center[1]], z=[center[2]],
                u=[lift_vec[0] * lift_scale],
                v=[lift_vec[1] * lift_scale],
                w=[lift_vec[2] * lift_scale],
                sizemode="absolute",
                sizeref=0.22 * max_len,
                anchor="tail",
                colorscale=[[0, "cyan"], [1, "cyan"]],
                name=f"Calculated lift/downforce = {fl_v:.6g} N",
                showscale=False,
            )
        )

    if abs(side_v) > 1e-12:
        fig.add_trace(
            go.Cone(
                x=[center[0]], y=[center[1]], z=[center[2]],
                u=[side_vec[0] * side_scale],
                v=[side_vec[1] * side_scale],
                w=[side_vec[2] * side_scale],
                sizemode="absolute",
                sizeref=0.22 * max_len,
                anchor="tail",
                colorscale=[[0, "orange"], [1, "orange"]],
                name=f"Calculated side force = {side_v:.6g} N",
                showscale=False,
            )
        )

    # Incoming flow arrow shown upstream.
    upstream = center - drag_vec * 1.7 * max_len
    fig.add_trace(
        go.Cone(
            x=[upstream[0]],
            y=[upstream[1]],
            z=[upstream[2]],
            u=[drag_vec[0]],
            v=[drag_vec[1]],
            w=[drag_vec[2]],
            sizemode="absolute",
            sizeref=0.30 * max_len,
            anchor="tail",
            colorscale=[[0, "white"], [1, "white"]],
            name=f"Incoming flow direction, V = {velocity_v:.6g} m/s",
            showscale=False,
            opacity=0.70,
        )
    )

    # Figure metadata allows future PDF/report validation.
    try:
        fig.update_layout(
            meta=dict(
                calculated_drag_N=fd_v,
                calculated_lift_N=fl_v,
                calculated_side_N=side_v,
                displayed_integrated_force_N=integrated_visual_force.tolist(),
                max_display_pressure_loading_Pa=max_load,
                dynamic_pressure_Pa=0.5 * rho_v * velocity_v ** 2,
            )
        )
    except Exception:
        pass

    fig.update_layout(
        title="Dynamic Force Visualization — Calculated Pressure Loading + Force Vectors",
        scene=dict(
            xaxis_title="X [m]",
            yaxis_title="Y [m]",
            zaxis_title="Z [m]",
            aspectmode="data",
            camera=dict(eye=dict(x=1.45, y=1.35, z=0.9)),
        ),
        height=760,
        margin=dict(l=0, r=0, t=45, b=0),
        showlegend=True,
        legend=dict(x=0.01, y=0.98, bgcolor="rgba(0,0,0,0.55)"),
    )

    return fig



def render_step_by_step_equations(
    mode,
    fluid,
    altitude_m,
    temperature_k,
    pressure_pa,
    rho,
    mu,
    velocity,
    area,
    length,
    volume,
    mass_kg,
    cd_used,
    cl,
    q_dynamic,
    re,
    fd,
    fl,
    power_required,
    terminal_result,
    net_force_down,
    drag_result,
    turbulence_model,
    turbulence_note,
    cfd_auto_settings=None,
):
    """
    Customer-facing transparent calculation sheet for Simulation Results.
    Shows formulas and numerical substitution for every major reported variable.
    """
    with st.expander("Step-by-step equations used in this simulation", expanded=False):
        st.markdown("### 1. Environment pressure")

        if altitude_m >= 0:
            pressure_formula = "P = P₀(1 - 2.25577×10⁻⁵ h)^5.25588"
            st.latex(r"P = P_0(1 - 2.25577\times10^{-5}h)^{5.25588}")
            st.write(
                f"Using h = {altitude_m:,.4g} m and P₀ = {P0:,.2f} Pa:"
            )
            st.code(
                f"P = {P0:,.2f} * (1 - 2.25577e-5 * {altitude_m:,.6g})^5.25588\n"
                f"P = {pressure_pa:,.6g} Pa"
            )
        else:
            depth = abs(altitude_m)
            st.latex(r"P = P_0 + \rho g h")
            st.write(
                f"Using depth h = {depth:,.4g} m, estimated water density ≈ 1025 kg/m³, and g = {G:.5g} m/s²:"
            )
            st.code(
                f"P = {P0:,.2f} + 1025 * {G:.5g} * {depth:,.6g}\n"
                f"P = {pressure_pa:,.6g} Pa"
            )

        st.markdown("### 2. Fluid properties")
        if simulation_mode == "Standard CFD Mode":
            st.write("In Standard CFD Mode, mass flow rate is converted to density before property lookup.")
            st.latex(r"\rho = \frac{\dot{m}}{V A_{flow}}")

        if fluid == "Air":
            st.latex(r"\rho = \frac{P}{RT}")
            st.code(
                f"ρ = P / (R*T)\n"
                f"ρ = {pressure_pa:,.6g} / ({R_AIR:.5g} * {temperature_k:,.6g})\n"
                f"ρ = {rho:,.6g} kg/m³\n"
                f"μ = {mu:.6e} Pa·s"
            )
        else:
            st.code(
                f"Fluid = {fluid}\n"
                f"ρ = {rho:,.6g} kg/m³\n"
                f"μ = {mu:.6e} Pa·s"
            )

        st.markdown("### 3. Geometry values")
        st.latex(r"D_{eq}=\sqrt{\frac{4A}{\pi}}")
        eq_d = equivalent_diameter_from_area(area)
        st.code(
            f"Projected/reference area A = {area:,.6g} m²\n"
            f"Characteristic length L = {length:,.6g} m\n"
            f"Displaced volume V_obj = {volume:,.6g} m³\n"
            f"D_eq = sqrt(4*A/pi) = sqrt(4*{area:,.6g}/pi) = {eq_d:,.6g} m"
        )

        st.markdown("### 4. Dynamic pressure")
        st.latex(r"q = \frac{1}{2}\rho V^2")
        st.code(
            f"q = 0.5 * {rho:,.6g} * ({velocity:,.6g})²\n"
            f"q = {q_dynamic:,.6g} Pa"
        )

        st.markdown("### 5. Reynolds number")
        st.latex(r"Re = \frac{\rho V L}{\mu}")
        st.code(
            f"Re = ρ*V*L/μ\n"
            f"Re = {rho:,.6g} * {velocity:,.6g} * {length:,.6g} / {mu:.6e}\n"
            f"Re = {re:,.6g}"
        )

        st.markdown("### 6. Non-CFD drag estimate / fallback")
        st.write(f"Selected non-CFD drag model: **{drag_result['model']}**")
        st.write(drag_result["model_note"])

        if "Stokes" in drag_result["model"]:
            st.latex(r"F_D = 3\pi\mu V D")
            st.code(
                f"F_D = 3*pi*μ*V*D_eq\n"
                f"F_D = 3*pi*{mu:.6e}*{velocity:,.6g}*{eq_d:,.6g}\n"
                f"F_D = {fd:,.6g} N"
            )
        else:
            st.latex(r"F_D = \frac{1}{2}\rho V^2 C_D A")
            st.code(
                f"F_D = 0.5*ρ*V²*C_D*A\n"
                f"F_D = 0.5*{rho:,.6g}*({velocity:,.6g})²*{cd_used:,.6g}*{area:,.6g}\n"
                f"F_D = {fd:,.6g} N"
            )

        st.markdown("### 7. Lift / downforce")
        st.latex(r"F_L = \frac{1}{2}\rho V^2 C_L A")
        st.code(
            f"F_L = 0.5*ρ*V²*C_L*A\n"
            f"F_L = 0.5*{rho:,.6g}*({velocity:,.6g})²*{cl:,.6g}*{area:,.6g}\n"
            f"F_L = {fl:,.6g} N"
        )

        st.markdown("### 8. Buoyancy, effective weight, and net force")
        st.latex(r"F_B = \rho g V_{obj}")
        st.latex(r"W = mg")
        st.latex(r"F_{net} = W - F_B - F_D")
        weight_n = mass_kg * G
        buoyancy_n = rho * G * volume
        st.code(
            f"W = m*g = {mass_kg:,.6g}*{G:.6g} = {weight_n:,.6g} N\n"
            f"F_B = ρ*g*V_obj = {rho:,.6g}*{G:.6g}*{volume:,.6g} = {buoyancy_n:,.6g} N\n"
            f"W - F_B = {terminal_result['effective_weight_n']:,.6g} N\n"
            f"F_net = W - F_B - F_D = {net_force_down:,.6g} N"
        )

        st.markdown("### 9. Terminal velocity")
        if "Stokes" in terminal_result["model"]:
            st.latex(r"V_t = \frac{W-F_B}{3\pi\mu D}")
            st.code(
                f"V_t = (W-F_B)/(3*pi*μ*D_eq)\n"
                f"V_t = {terminal_result['effective_weight_n']:,.6g}/(3*pi*{mu:.6e}*{eq_d:,.6g})\n"
                f"V_t = {terminal_result['terminal_velocity']:,.6g} m/s"
            )
        elif terminal_result["effective_weight_n"] <= 0:
            st.code(
                "W - F_B <= 0, so the object is neutrally buoyant or buoyant.\n"
                f"Terminal velocity = {terminal_result['terminal_velocity']:,.6g} m/s"
            )
        else:
            st.latex(r"V_t = \sqrt{\frac{2(W-F_B)}{\rho C_D A}}")
            st.code(
                f"V_t = sqrt(2*(W-F_B)/(ρ*C_D*A))\n"
                f"V_t = sqrt(2*{terminal_result['effective_weight_n']:,.6g}/({rho:,.6g}*{terminal_result['cd_used']:,.6g}*{area:,.6g}))\n"
                f"V_t = {terminal_result['terminal_velocity']:,.6g} m/s"
            )

        st.markdown("### 10. Power to overcome drag")
        st.latex(r"P_{power}=F_D V")
        st.code(
            f"Power = F_D*V\n"
            f"Power = {fd:,.6g}*{velocity:,.6g}\n"
            f"Power = {power_required:,.6g} W"
        )

        st.markdown("### 11. CFD drag/lift coefficient calculation after OpenFOAM")
        st.latex(r"C_D=\frac{F_D}{qA_{ref}}")
        st.latex(r"C_L=\frac{F_L}{qA_{ref}}")
        st.write(
            "When an OpenFOAM run completes, the app calculates Cd and Cl from the integrated pressure force over the object surface. "
            "The engineering fallback Cd is not used for final CFD coefficients."
        )

        st.markdown("### 12. Background CFD automation")
        st.code(
            f"Turbulence model = {turbulence_model}\n"
            f"Reason = {turbulence_note}\n"
            f"All-face pressure gradient = active in every mode\n"
            f"Front face selection = used to define incoming flow direction"
        )

        if cfd_auto_settings is not None:
            st.code(
                f"Automated mesh/domain sizing:\n"
                f"Max object dimension = {cfd_auto_settings.get('max_object_dimension_m', 0):,.6g} m\n"
                f"Face count = {cfd_auto_settings.get('face_count', 0):,}\n"
                f"Base cells per direction = {cfd_auto_settings.get('base_cell_count', 'auto')}\n"
                f"Surface refinement level = {cfd_auto_settings.get('refinement_level', 'auto')}\n"
                f"Upstream domain = {cfd_auto_settings.get('domain_scale_upstream', 'auto')} × object size\n"
                f"Downstream domain = {cfd_auto_settings.get('domain_scale_downstream', 'auto')} × object size\n"
                f"Crossflow padding = {cfd_auto_settings.get('domain_scale_cross', 'auto')} × object size"
            )



