def safe_name(name: str) -> str:
    keep = []
    for ch in name:
        if ch.isalnum() or ch in ["_", "-", "."]:
            keep.append(ch)
        else:
            keep.append("_")
    return "".join(keep)


def docker_cli_available():
    """Returns True when Docker CLI is reachable from the Python environment."""
    try:
        result = subprocess.run(
            ["docker", "version", "--format", "{{.Server.Version}}"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=15,
        )
        return result.returncode == 0
    except Exception:
        return False


def docker_container_exists(container_name=DOCKER_OPENFOAM_CONTAINER):
    try:
        result = subprocess.run(
            ["docker", "ps", "-a", "--filter", f"name=^{container_name}$", "--format", "{{.Names}}"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=15,
        )
        names = [line.strip() for line in result.stdout.splitlines() if line.strip()]
        return result.returncode == 0 and container_name in names
    except Exception:
        return False


def docker_container_running(container_name=DOCKER_OPENFOAM_CONTAINER):
    try:
        result = subprocess.run(
            ["docker", "ps", "--filter", f"name=^{container_name}$", "--format", "{{.Names}}"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=15,
        )
        names = [line.strip() for line in result.stdout.splitlines() if line.strip()]
        return result.returncode == 0 and container_name in names
    except Exception:
        return False


def ensure_docker_openfoam_container(container_name=DOCKER_OPENFOAM_CONTAINER):
    """Ensures the local OpenFOAM Docker container is running."""
    if not docker_cli_available():
        return False, "Docker CLI is not available from this Python environment."
    if docker_container_running(container_name):
        return True, f"Docker container '{container_name}' is running."
    if docker_container_exists(container_name):
        try:
            result = subprocess.run(
                ["docker", "start", container_name],
                text=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                timeout=30,
            )
            if result.returncode == 0:
                return True, f"Docker container '{container_name}' started."
            return False, result.stdout.strip()
        except Exception as e:
            return False, str(e)
    return False, (
        f"Docker container '{container_name}' was not found. Create it with: "
        f"docker run -it --name {container_name} {DOCKER_OPENFOAM_IMAGE} bash"
    )


def docker_exec_openfoam(command: str, timeout=120, cwd_container=None, container_name=DOCKER_OPENFOAM_CONTAINER):
    """Runs a command inside the local OpenFOAM Docker container."""
    ok, msg = ensure_docker_openfoam_container(container_name)
    if not ok:
        return False, msg
    exec_cmd = ["docker", "exec"]
    if cwd_container:
        exec_cmd += ["-w", str(cwd_container)]
    exec_cmd += [container_name, "bash", "-lc", command]
    try:
        result = subprocess.run(
            exec_cmd,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=timeout,
        )
        return result.returncode == 0, result.stdout
    except Exception as e:
        return False, str(e)


def docker_openfoam_command_available(command_name: str):
    ok, output = docker_exec_openfoam(f"which {command_name}", timeout=30)
    return ok and command_name in output, output.strip()


def run_docker_openfoam_command(command: str, cwd_windows_path=None, timeout=2400, container_name=DOCKER_OPENFOAM_CONTAINER):
    """
    Runs an OpenFOAM command inside Docker using a Linux-native temp case folder.
    Copies the local case into the container, runs the command, then copies results back.
    """
    ok, msg = ensure_docker_openfoam_container(container_name)
    if not ok:
        return False, msg
    if cwd_windows_path is None:
        return docker_exec_openfoam(command, timeout=timeout, container_name=container_name)

    case_dir = Path(cwd_windows_path).resolve()
    if not case_dir.exists():
        return False, f"Case directory does not exist: {case_dir}"
    case_name = safe_name(case_dir.name)
    run_root = f"{DOCKER_OPENFOAM_RUN_ROOT}/{case_name}"
    logs = []
    try:
        prep_cmd = f'rm -rf "{run_root}" && mkdir -p "{run_root}"'
        ok, out = docker_exec_openfoam(prep_cmd, timeout=120, container_name=container_name)
        logs.append(f"$ docker exec {container_name} bash -lc {prep_cmd}\n{out}\n")
        if not ok:
            return False, "\n".join(logs)

        local_src = str(case_dir) + os.sep + "."
        cp_in = subprocess.run(
            ["docker", "cp", local_src, f"{container_name}:{run_root}/"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=300,
        )
        logs.append(f"$ docker cp {local_src} {container_name}:{run_root}/\n{cp_in.stdout}\n")
        if cp_in.returncode != 0:
            return False, "\n".join(logs)

        ok, out = docker_exec_openfoam(command, timeout=timeout, cwd_container=run_root, container_name=container_name)
        logs.append(f"$ docker exec -w {run_root} {container_name} bash -lc {command}\n{out}\n")
        command_ok = ok

        cp_out = subprocess.run(
            ["docker", "cp", f"{container_name}:{run_root}/.", str(case_dir)],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=600,
        )
        logs.append(f"$ docker cp {container_name}:{run_root}/. {case_dir}\n{cp_out.stdout}\n")
        if cp_out.returncode != 0:
            return False, "\n".join(logs)
        return command_ok, "\n".join(logs)
    except Exception as e:
        logs.append(f"ERROR: {e}")
        return False, "\n".join(logs)


def wsl_available():
    """
    Robust WSL check.

    shutil.which('wsl') can fail inside some Streamlit/Windows environments
    even when PowerShell can run WSL. So we directly try `wsl --status`.
    """
    try:
        result = subprocess.run(
            ["wsl", "--status"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=20,
        )
        return result.returncode == 0 or "Default Distribution" in result.stdout or "WSL" in result.stdout
    except Exception:
        return False


def windows_path_to_wsl_path(path_value):
    """
    Converts a Windows path to a WSL path without relying on wslpath.

    Example:
      C:\\Users\\JOEL\\.jewlz_fluidforce\\cases\\CFD-123
      becomes
      /mnt/c/Users/JOEL/.jewlz_fluidforce/cases/CFD-123
    """
    path_text = str(path_value).strip().replace("\\", "/")

    if path_text.startswith("/"):
        return path_text

    if len(path_text) >= 2 and path_text[1] == ":":
        drive = path_text[0].lower()
        rest = path_text[2:]
        if rest.startswith("/"):
            rest = rest[1:]
        return f"/mnt/{drive}/{rest}"

    return path_text


def openfoam_source_prefix():
    """
    Ubuntu apt OpenFOAM package fix.

    Your WSL shows:
      /usr/bin/blockMesh
      /usr/bin/snappyHexMesh
      /usr/bin/simpleFoam
foamToVTK -ascii || true

    But the apt bashrc can be broken, so we avoid sourcing it and set
    minimum environment variables directly.
    """
    return (
        "export FOAM_ETC=/usr/share/openfoam/etc; "
        "export WM_PROJECT_DIR=/usr/share/openfoam; "
        "export WM_PROJECT=OpenFOAM; "
        "export FOAM_APPBIN=/usr/bin; "
        "export PATH=\"/usr/bin:/bin:/usr/sbin:/sbin:/usr/local/bin\"; "
    )


def run_wsl_command(command: str, cwd_windows_path=None, timeout=900, source_openfoam=True):
    """
    Runs a Linux command in WSL from Windows Python.

    Important:
    OpenFOAM can fail with an IOstream "sha1" error when solver files are
    written directly to the Windows-mounted /mnt/c filesystem. To avoid that,
    each OpenFOAM command is run from a Linux-native temporary case folder:

      Windows case folder
          -> rsync/cp to /tmp/jewlz_fluidforce_openfoam/<case>
          -> run OpenFOAM inside /tmp
          -> rsync/cp results back to Windows case folder

    This keeps the Streamlit app on Windows while letting OpenFOAM use a native
    Linux filesystem for mesh/field writes.
    """
    if cwd_windows_path is not None:
        cwd_wsl = windows_path_to_wsl_path(cwd_windows_path)
        case_name = safe_name(Path(str(cwd_windows_path)).name)
        run_root = f"/tmp/jewlz_fluidforce_openfoam/{case_name}"
    else:
        cwd_wsl = None
        run_root = None

    env_lines = ""
    if source_openfoam:
        env_lines = """
export FOAM_ETC=/usr/share/openfoam/etc
export WM_PROJECT_DIR=/usr/share/openfoam
export WM_PROJECT=OpenFOAM
export FOAM_APPBIN=/usr/bin
export PATH="/usr/bin:/bin:/usr/sbin:/sbin:/usr/local/bin"
"""

    if cwd_wsl:
        script = f"""
set -e
{env_lines}

mkdir -p "/tmp/jewlz_fluidforce_openfoam"
rm -rf "{run_root}"
mkdir -p "{run_root}"

# Copy case from Windows-mounted filesystem to Linux-native filesystem.
# cp is used instead of rsync because rsync may not be installed on all WSL systems.
cp -a "{cwd_wsl}/." "{run_root}/"

cd "{run_root}"

{command}

# Copy generated mesh/results/logs back to the Windows case folder.
cp -a "{run_root}/." "{cwd_wsl}/"
"""
    else:
        script = f"""
set -e
{env_lines}
{command}
"""

    try:
        result = subprocess.run(
            ["wsl", "bash", "-c", script],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=timeout,
        )
        return result.returncode == 0, result.stdout
    except Exception as e:
        return False, str(e)

def openfoam_available():
    """
    Checks OpenFOAM availability.

    Priority:
    1. Docker OpenFOAM worker container: jewlz-openfoam
    2. Native commands in current OS PATH
    3. WSL commands
    """
    commands = ["blockMesh", "snappyHexMesh", "simpleFoam", "foamToVTK"]

    docker_outputs = {}
    docker_ok, docker_msg = ensure_docker_openfoam_container(DOCKER_OPENFOAM_CONTAINER)
    if docker_ok:
        docker_results = {}
        for cmd in commands:
            ok, output = docker_openfoam_command_available(cmd)
            docker_results[cmd] = bool(ok)
            docker_outputs[cmd] = output
        if docker_results.get("blockMesh") and docker_results.get("simpleFoam") and docker_results.get("foamToVTK"):
            return {
                "mode": "docker",
                "docker": True,
                "container": DOCKER_OPENFOAM_CONTAINER,
                "blockMesh": docker_results.get("blockMesh", False),
                "snappyHexMesh": docker_results.get("snappyHexMesh", False),
                "simpleFoam": docker_results.get("simpleFoam", False),
                "foamToVTK": docker_results.get("foamToVTK", False),
                "docker_outputs": docker_outputs,
                "message": docker_msg,
            }
    else:
        docker_outputs["docker"] = docker_msg

    native = {}
    for cmd in commands:
        try:
            native[cmd] = shutil.which(cmd) is not None
        except Exception:
            native[cmd] = False
    if native.get("blockMesh") and native.get("snappyHexMesh") and native.get("simpleFoam"):
        return {
            "mode": "native",
            "docker": False,
            "blockMesh": native.get("blockMesh", False),
            "snappyHexMesh": native.get("snappyHexMesh", False),
            "simpleFoam": native.get("simpleFoam", False),
            "foamToVTK": native.get("foamToVTK", False),
        }

    wsl_results = {}
    wsl_outputs = {}
    for cmd in commands:
        try:
            result = subprocess.run(
                ["wsl", "bash", "-lc", f"which {cmd}"],
                text=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                timeout=30,
            )
            wsl_results[cmd] = result.returncode == 0 and f"/{cmd}" in result.stdout
            wsl_outputs[cmd] = result.stdout.strip()
        except Exception as e:
            wsl_results[cmd] = False
            wsl_outputs[cmd] = str(e)
    if wsl_results.get("blockMesh") and wsl_results.get("snappyHexMesh") and wsl_results.get("simpleFoam"):
        return {
            "mode": "wsl",
            "docker": False,
            "blockMesh": True,
            "snappyHexMesh": True,
            "simpleFoam": True,
            "foamToVTK": wsl_results.get("foamToVTK", False),
            "wsl_outputs": wsl_outputs,
        }
    return {
        "mode": "unavailable",
        "docker": False,
        "blockMesh": native.get("blockMesh", False) or wsl_results.get("blockMesh", False),
        "snappyHexMesh": native.get("snappyHexMesh", False) or wsl_results.get("snappyHexMesh", False),
        "simpleFoam": native.get("simpleFoam", False) or wsl_results.get("simpleFoam", False),
        "foamToVTK": native.get("foamToVTK", False) or wsl_results.get("foamToVTK", False),
        "wsl_outputs": wsl_outputs,
        "docker_outputs": docker_outputs,
    }


def vector_to_openfoam(v):
    return f"({v[0]:.8g} {v[1]:.8g} {v[2]:.8g})"


def make_openfoam_header(class_name: str, object_name: str):
    return f"""/*--------------------------------*- C++ -*----------------------------------*\\
| Jewlz FluidForce Simulator - Generated OpenFOAM Dictionary                  |
\\*---------------------------------------------------------------------------*/
FoamFile
{{
    version     2.0;
    format      ascii;
    class       {class_name};
    object      {object_name};
}}
// ************************************************************************* //
"""


def domain_from_bounds(bounds, front_selection, domain_scale_upstream, domain_scale_downstream, domain_scale_cross):
    """
    Creates a rectangular far-field domain around the body.
    """
    flow_vec = flow_vector_from_front(front_selection)
    lengths = np.array([
        max(bounds["x_length"], 1e-9),
        max(bounds["y_length"], 1e-9),
        max(bounds["z_length"], 1e-9),
    ])
    max_len = float(np.max(lengths))

    mins = np.array([bounds["x_min"], bounds["y_min"], bounds["z_min"]], dtype=float)
    maxs = np.array([bounds["x_max"], bounds["y_max"], bounds["z_max"]], dtype=float)

    # Expand all directions crossflow first.
    mins_exp = mins - domain_scale_cross * max_len
    maxs_exp = maxs + domain_scale_cross * max_len

    # Add longer upstream/downstream extents along flow axis.
    axis = np.argmax(np.abs(flow_vec))
    sign = np.sign(flow_vec[axis])

    if sign > 0:
        # flow from low coordinate to high coordinate
        mins_exp[axis] = mins[axis] - domain_scale_upstream * max_len
        maxs_exp[axis] = maxs[axis] + domain_scale_downstream * max_len
    else:
        # flow from high coordinate to low coordinate
        mins_exp[axis] = mins[axis] - domain_scale_downstream * max_len
        maxs_exp[axis] = maxs[axis] + domain_scale_upstream * max_len

    return mins_exp, maxs_exp, max_len, axis, sign


def write_text(path, text):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")


def write_openfoam_case(
    case_dir,
    uploaded_file,
    coords_m,
    faces,
    bounds,
    front_selection,
    velocity,
    rho,
    mu,
    cd_ref_area,
    ref_length,
    turbulence_model,
    base_cell_count,
    refinement_level,
    domain_scale_upstream,
    domain_scale_downstream,
    domain_scale_cross,
):
    """
    Generates a steady incompressible OpenFOAM simpleFoam case.

    The uploaded mesh is written as object.stl from the current cleaned mesh.
    This avoids unit ambiguity because coords_m are already in meters.
    """
    case_dir = Path(case_dir)
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)

    zero_dir = case_dir / "0"
    constant_dir = case_dir / "constant"
    system_dir = case_dir / "system"
    tri_dir = constant_dir / "triSurface"
    zero_dir.mkdir()
    constant_dir.mkdir()
    system_dir.mkdir()
    tri_dir.mkdir()

    # Export cleaned mesh in meters for OpenFOAM.
    stl_path = tri_dir / "uploadedObject.stl"
    try:
        mesh = trimesh.Trimesh(vertices=coords_m, faces=faces, process=False)
        mesh.export(stl_path)
    except Exception:
        # Fallback simple ASCII STL writer
        areas, _, normals, _ = face_area_vectors(coords_m, faces)
        with open(stl_path, "w", encoding="utf-8") as f:
            f.write("solid uploadedObject\n")
            for face, normal in zip(faces, normals):
                f.write(f" facet normal {normal[0]} {normal[1]} {normal[2]}\n")
                f.write("  outer loop\n")
                for idx in face:
                    p = coords_m[idx]
                    f.write(f"   vertex {p[0]} {p[1]} {p[2]}\n")
                f.write("  endloop\n")
                f.write(" endfacet\n")
            f.write("endsolid uploadedObject\n")

    mins, maxs, max_len, axis, sign = domain_from_bounds(
        bounds,
        front_selection,
        domain_scale_upstream,
        domain_scale_downstream,
        domain_scale_cross,
    )

    x0, y0, z0 = mins
    x1, y1, z1 = maxs

    nx = ny = nz = int(max(base_cell_count, 4))

    # Flow vector and inlet speed
    flow_vec = flow_vector_from_front(front_selection)
    U = flow_vec * float(velocity)

    # Identify inlet and outlet patch names based on flow axis/sign.
    if axis == 0:
        inlet_patch = "xMin" if sign > 0 else "xMax"
        outlet_patch = "xMax" if sign > 0 else "xMin"
    elif axis == 1:
        inlet_patch = "yMin" if sign > 0 else "yMax"
        outlet_patch = "yMax" if sign > 0 else "yMin"
    else:
        inlet_patch = "zMin" if sign > 0 else "zMax"
        outlet_patch = "zMax" if sign > 0 else "zMin"

    wall_patches = ["xMin", "xMax", "yMin", "yMax", "zMin", "zMax"]
    side_patches = [p for p in wall_patches if p not in [inlet_patch, outlet_patch]]

    block_mesh = make_openfoam_header("dictionary", "blockMeshDict") + f"""
convertToMeters 1;

vertices
(
    ({x0} {y0} {z0})
    ({x1} {y0} {z0})
    ({x1} {y1} {z0})
    ({x0} {y1} {z0})
    ({x0} {y0} {z1})
    ({x1} {y0} {z1})
    ({x1} {y1} {z1})
    ({x0} {y1} {z1})
);

blocks
(
    hex (0 1 2 3 4 5 6 7) ({nx} {ny} {nz}) simpleGrading (1 1 1)
);

edges
(
);

boundary
(
    xMin {{ type patch; faces ((0 4 7 3)); }}
    xMax {{ type patch; faces ((1 2 6 5)); }}
    yMin {{ type patch; faces ((0 1 5 4)); }}
    yMax {{ type patch; faces ((3 7 6 2)); }}
    zMin {{ type patch; faces ((0 3 2 1)); }}
    zMax {{ type patch; faces ((4 5 6 7)); }}
);

mergePatchPairs
(
);
"""
    write_text(system_dir / "blockMeshDict", block_mesh)

    snappy = make_openfoam_header("dictionary", "snappyHexMeshDict") + f"""
castellatedMesh true;
snap            true;
addLayers       false;

geometry
{{
    uploadedObject.stl
    {{
        type triSurfaceMesh;
        name object;
    }}
}}

castellatedMeshControls
{{
    maxLocalCells 1000000;
    maxGlobalCells 3000000;
    minRefinementCells 0;
    nCellsBetweenLevels 3;

    features
    (
    );

    refinementSurfaces
    {{
        object
        {{
            level ({refinement_level} {refinement_level});
            patchInfo
            {{
                type wall;
            }}
        }}
    }}

    resolveFeatureAngle 30;

    refinementRegions
    {{
    }}

    locationInMesh ({x0 + 0.05*(x1-x0)} {y0 + 0.05*(y1-y0)} {z0 + 0.05*(z1-z0)});

    allowFreeStandingZoneFaces true;
}}

snapControls
{{
    nSmoothPatch 3;
    tolerance 2.0;
    nSolveIter 30;
    nRelaxIter 5;
}}

addLayersControls
{{
    relativeSizes true;
    layers
    {{
    }}
    expansionRatio 1.2;
    finalLayerThickness 0.3;
    minThickness 0.1;
    nGrow 0;
    featureAngle 60;
    nRelaxIter 3;
    nSmoothSurfaceNormals 1;
    nSmoothNormals 3;
    nSmoothThickness 10;
    maxFaceThicknessRatio 0.5;
    maxThicknessToMedialRatio 0.3;
    minMedianAxisAngle 90;
    nBufferCellsNoExtrude 0;
    nLayerIter 50;
}}

meshQualityControls
{{
    maxNonOrtho 65;
    maxBoundarySkewness 20;
    maxInternalSkewness 4;
    maxConcave 80;
    minVol 1e-13;
    minTetQuality 1e-15;
    minArea -1;
    minTwist 0.02;
    minDeterminant 0.001;
    minFaceWeight 0.02;
    minVolRatio 0.01;
    minTriangleTwist -1;
    nSmoothScale 4;
    errorReduction 0.75;
}}

debug 0;
mergeTolerance 1e-6;
"""
    write_text(system_dir / "snappyHexMeshDict", snappy)

    control = make_openfoam_header("dictionary", "controlDict") + f"""
application     simpleFoam;

startFrom       startTime;
startTime       0;
stopAt          endTime;
endTime         500;

deltaT          1;
writeControl    timeStep;
writeInterval   100;

purgeWrite      0;
writeFormat     ascii;
writePrecision  8;
writeCompression off;
timeFormat      general;
timePrecision   6;

runTimeModifiable true;

functions
{{
}}
"""
    write_text(system_dir / "controlDict", control)

    fv_schemes = make_openfoam_header("dictionary", "fvSchemes") + """
ddtSchemes
{
    default steadyState;
}

gradSchemes
{
    default Gauss linear;
}

divSchemes
{
    default none;
    div(phi,U) bounded Gauss upwind;
    div(phi,k) bounded Gauss upwind;
    div(phi,epsilon) bounded Gauss upwind;
    div(phi,omega) bounded Gauss upwind;
    div((nuEff*dev2(T(grad(U))))) Gauss linear;
}

laplacianSchemes
{
    default Gauss linear corrected;
}

interpolationSchemes
{
    default linear;
}

snGradSchemes
{
    default corrected;
}

wallDist
{
    method meshWave;
}
"""
    write_text(system_dir / "fvSchemes", fv_schemes)

    fv_solution = make_openfoam_header("dictionary", "fvSolution") + """
solvers
{
    p
    {
        solver GAMG;
        tolerance 1e-7;
        relTol 0.1;
        smoother GaussSeidel;
    }

    U
    {
        solver smoothSolver;
        smoother symGaussSeidel;
        tolerance 1e-8;
        relTol 0.1;
    }

    k
    {
        solver smoothSolver;
        smoother symGaussSeidel;
        tolerance 1e-8;
        relTol 0.1;
    }

    epsilon
    {
        solver smoothSolver;
        smoother symGaussSeidel;
        tolerance 1e-8;
        relTol 0.1;
    }

    omega
    {
        solver smoothSolver;
        smoother symGaussSeidel;
        tolerance 1e-8;
        relTol 0.1;
    }
}

SIMPLE
{
    nNonOrthogonalCorrectors 0;
    consistent yes;

    residualControl
    {
        p 1e-4;
        U 1e-5;
    }
}

relaxationFactors
{
    fields
    {
        p 0.3;
    }
    equations
    {
        U 0.7;
        k 0.7;
        epsilon 0.7;
        omega 0.7;
    }
}
"""
    write_text(system_dir / "fvSolution", fv_solution)

    # Boundary dictionaries
    def patch_field(patch_name, field, internal):
        pass

    side_bc_U = "\n".join([f"    {p}\n    {{\n        type slip;\n    }}" for p in side_patches])
    side_bc_p = "\n".join([f"    {p}\n    {{\n        type zeroGradient;\n    }}" for p in side_patches])

    U_file = make_openfoam_header("volVectorField", "U") + f"""
dimensions      [0 1 -1 0 0 0 0];

internalField   uniform {vector_to_openfoam(U)};

boundaryField
{{
    {inlet_patch}
    {{
        type fixedValue;
        value uniform {vector_to_openfoam(U)};
    }}

    {outlet_patch}
    {{
        type zeroGradient;
    }}

{side_bc_U}

    object
    {{
        type noSlip;
    }}
}}
"""
    write_text(zero_dir / "U", U_file)

    p_file = make_openfoam_header("volScalarField", "p") + f"""
dimensions      [0 2 -2 0 0 0 0];

internalField   uniform 0;

boundaryField
{{
    {inlet_patch}
    {{
        type zeroGradient;
    }}

    {outlet_patch}
    {{
        type fixedValue;
        value uniform 0;
    }}

{side_bc_p}

    object
    {{
        type zeroGradient;
    }}
}}
"""
    write_text(zero_dir / "p", p_file)

    # Turbulence fields. Keep simple default estimates.
    turbulence_intensity = 0.05
    k_val = 1.5 * (velocity * turbulence_intensity) ** 2
    length_scale = max(0.07 * ref_length, 1e-6)
    epsilon_val = (0.09 ** 0.75) * (k_val ** 1.5) / length_scale
    omega_val = np.sqrt(max(k_val, 1e-12)) / max((0.09 ** 0.25) * length_scale, 1e-12)

    side_bc_scalar = "\n".join([f"    {p}\n    {{\n        type zeroGradient;\n    }}" for p in side_patches])

    k_file = make_openfoam_header("volScalarField", "k") + f"""
dimensions      [0 2 -2 0 0 0 0];

internalField   uniform {k_val};

boundaryField
{{
    {inlet_patch}
    {{
        type fixedValue;
        value uniform {k_val};
    }}

    {outlet_patch}
    {{
        type zeroGradient;
    }}

{side_bc_scalar}

    object
    {{
        type kqRWallFunction;
        value uniform {k_val};
    }}
}}
"""
    write_text(zero_dir / "k", k_file)

    epsilon_file = make_openfoam_header("volScalarField", "epsilon") + f"""
dimensions      [0 2 -3 0 0 0 0];

internalField   uniform {epsilon_val};

boundaryField
{{
    {inlet_patch}
    {{
        type fixedValue;
        value uniform {epsilon_val};
    }}

    {outlet_patch}
    {{
        type zeroGradient;
    }}

{side_bc_scalar}

    object
    {{
        type epsilonWallFunction;
        value uniform {epsilon_val};
    }}
}}
"""
    write_text(zero_dir / "epsilon", epsilon_file)

    omega_file = make_openfoam_header("volScalarField", "omega") + f"""
dimensions      [0 0 -1 0 0 0 0];

internalField   uniform {omega_val};

boundaryField
{{
    {inlet_patch}
    {{
        type fixedValue;
        value uniform {omega_val};
    }}

    {outlet_patch}
    {{
        type zeroGradient;
    }}

{side_bc_scalar}

    object
    {{
        type omegaWallFunction;
        value uniform {omega_val};
    }}
}}
"""
    write_text(zero_dir / "omega", omega_file)

    nut_file = make_openfoam_header("volScalarField", "nut") + f"""
dimensions      [0 2 -1 0 0 0 0];

internalField   uniform 0;

boundaryField
{{
    {inlet_patch}
    {{
        type calculated;
        value uniform 0;
    }}

    {outlet_patch}
    {{
        type calculated;
        value uniform 0;
    }}

{side_bc_scalar}

    object
    {{
        type nutkWallFunction;
        value uniform 0;
    }}
}}
"""
    write_text(zero_dir / "nut", nut_file)

    # Transport and turbulence
    nu = mu / max(rho, 1e-30)
    transport = make_openfoam_header("dictionary", "transportProperties") + f"""
transportModel  Newtonian;
nu              [0 2 -1 0 0 0 0] {nu};
"""
    write_text(constant_dir / "transportProperties", transport)

    # Turbulence model selection.
    # laminar: no turbulence model.
    # kOmegaSST: recommended for external flow, separation, drag, and wake.
    # kEpsilon: common for ducts/internal industrial flow.
    if turbulence_model == "laminar":
        turb_body = """
simulationType laminar;
"""
    elif turbulence_model == "kEpsilon":
        turb_body = """
simulationType RAS;

RAS
{
    RASModel        kEpsilon;
    turbulence      on;
    printCoeffs     on;
}
"""
    else:
        turb_body = """
simulationType RAS;

RAS
{
    RASModel        kOmegaSST;
    turbulence      on;
    printCoeffs     on;
}
"""
    turb = make_openfoam_header("dictionary", "turbulenceProperties") + turb_body
    write_text(constant_dir / "turbulenceProperties", turb)

    surface_features = make_openfoam_header("dictionary", "surfaceFeatureExtractDict") + """
uploadedObject.stl
{
    extractionMethod    extractFromSurface;
    extractFromSurfaceCoeffs
    {
        includedAngle   150;
    }
    writeObj            yes;
}
"""
    write_text(system_dir / "surfaceFeatureExtractDict", surface_features)

    run_script = f"""#!/bin/bash
set -e
cd "$(dirname "$0")"

if [ -d /usr/share/openfoam/etc ]; then
    export FOAM_ETC=/usr/share/openfoam/etc
    export WM_PROJECT_DIR=/usr/share/openfoam
    export WM_PROJECT=OpenFOAM
    export FOAM_APPBIN=/usr/bin
    export PATH="/usr/bin:/bin:/usr/sbin:/sbin:/usr/local/bin"
elif ls /opt/openfoam*/etc/bashrc >/dev/null 2>&1; then
    source $(ls /opt/openfoam*/etc/bashrc | head -n 1)
elif ls /usr/lib/openfoam/openfoam*/etc/bashrc >/dev/null 2>&1; then
    source $(ls /usr/lib/openfoam/openfoam*/etc/bashrc | head -n 1)
fi

blockMesh
surfaceFeatureExtract || true
snappyHexMesh -overwrite
checkMesh
simpleFoam
foamToVTK -ascii || true
"""
    write_text(case_dir / "Allrun", run_script)

    readme = f"""Jewlz FluidForce Simulator - Generated OpenFOAM CFD Case

Geometry:
- Uploaded file converted to meters and written as constant/triSurface/uploadedObject.stl

Run in OpenFOAM:
1. Open an OpenFOAM shell or WSL OpenFOAM environment.
2. cd to this case folder.
3. chmod +x Allrun
4. ./Allrun

Expected workflow:
blockMesh -> surfaceFeatureExtract -> snappyHexMesh -overwrite -> checkMesh -> simpleFoam
foamToVTK -ascii || true

OpenFOAM 1912 compatibility:
- WSL execution copies the case to /tmp/jewlz_fluidforce_openfoam before running to avoid /mnt/c sha1 IOstream errors.
- wallDist method is written inside system/fvSchemes as method meshWave;
- no separate system/wallDist file is generated.
- FOAM_FILEHANDLER=uncollated is used to avoid OpenFOAM sha1 IOstream errors on WSL/Windows workflows.

Reference values:
rho = {rho} kg/m^3
mu = {mu} Pa*s
nu = {nu} m^2/s
U = {vector_to_openfoam(U)} m/s
Aref = {cd_ref_area} m^2
lRef = {ref_length} m
front = {front_selection}

Notes:
- This is a generated baseline CFD case.
- Mesh quality, y+, turbulence model, boundary size, and convergence must be verified.
- For production-grade CFD, refine mesh, add boundary layers, validate Cd/Cl, and compare against experimental or benchmark data.
"""
    write_text(case_dir / "README_Jewlz_CFD.txt", readme)

    return {
        "case_dir": str(case_dir),
        "inlet_patch": inlet_patch,
        "outlet_patch": outlet_patch,
        "flow_velocity_vector": U,
        "nu": nu,
        "stl_path": str(stl_path),
    }


def zip_directory(source_dir, zip_path):
    source_dir = Path(source_dir)
    zip_path = Path(zip_path)
    if zip_path.exists():
        zip_path.unlink()

    with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zf:
        for file in source_dir.rglob("*"):
            if file.is_file():
                zf.write(file, file.relative_to(source_dir.parent))

    return zip_path


def run_openfoam_case(case_dir, run_solver=False):
    """
    Runs a body-fitted OpenFOAM workflow.

    Stages:
      blockMesh
      surfaceFeatureExtract
      snappyHexMesh -overwrite
      checkMesh
      simpleFoam  [optional]
      foamToVTK -ascii [optional]

    This makes the actual OpenFOAM fluid domain interact with the uploaded object.
    Without snappyHexMesh, the solver only sees an empty rectangular box and the
    uploaded object is only a visual overlay.
    """
    availability = openfoam_available()
    missing = [k for k in ["blockMesh", "snappyHexMesh", "simpleFoam"] if not availability.get(k, False)]
    if missing:
        return False, "OpenFOAM commands not found: " + ", ".join(missing)

    commands = [
        ("blockMesh", True),
        ("surfaceFeatureExtract", False),
        ("snappyHexMesh -overwrite", True),
        ("checkMesh", True),
    ]

    if run_solver:
        commands.append(("simpleFoam", True))
        commands.append(("foamToVTK -ascii", False))

    logs = []
    mode = availability.get("mode", "unavailable")

    for command, required in commands:
        try:
            if mode == "docker":
                ok, output = run_docker_openfoam_command(command, cwd_windows_path=case_dir, timeout=2400)
                logs.append(
                    f"$ docker OpenFOAM worker [Linux-native temp run]\n"
                    f"Container: {DOCKER_OPENFOAM_CONTAINER}\n"
                    f"Local case: {case_dir}\n"
                    f"Command: {command}\n"
                    f"{output}\n"
                )

                if (not ok) and required:
                    return False, "\n".join(logs)

            elif mode == "wsl":
                ok, output = run_wsl_command(command, cwd_windows_path=case_dir, timeout=2400)
                logs.append(
                    f"$ wsl bash -c [Linux-native temp run]\n"
                    f"Windows case: {case_dir}\n"
                    f"WSL case: {windows_path_to_wsl_path(case_dir)}\n"
                    f"Command: {command}\n"
                    f"{output}\n"
                )

                if (not ok) and required:
                    return False, "\n".join(logs)

            else:
                result = subprocess.run(
                    command,
                    cwd=case_dir,
                    text=True,
                    shell=True,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    timeout=2400,
                )
                logs.append(f"$ {command}\n{result.stdout}\n")

                if result.returncode != 0 and required:
                    return False, "\n".join(logs)

        except Exception as e:
            logs.append(f"$ {command}\nERROR: {e}\n")
            if required:
                return False, "\n".join(logs)

    return True, "\n".join(logs)




def find_latest_openfoam_vtk(case_dir, preferred_field="Internal volume"):
    """
    Finds actual OpenFOAM visualization output generated by foamToVTK.

    Strong preference:
      1. Latest timestep internal.vtu, because it contains actual volume pressure/velocity data
      2. Latest boundary .vtp file
      3. Latest .vtm index file
      4. Any supported visual file

    Supports .vtk, .vtu, .vtp, and .vtm.
    """
    case_dir = Path(case_dir)
    exts = (".vtk", ".vtu", ".vtp", ".vtm")
    files = [p for p in case_dir.glob("VTK/**/*") if p.is_file() and p.suffix.lower() in exts]

    if not files:
        files = [p for p in case_dir.glob("postProcessing/**/*") if p.is_file() and p.suffix.lower() in exts]
    if not files:
        files = [p for p in case_dir.glob("**/*") if p.is_file() and p.suffix.lower() in exts]

    if not files:
        return None

    def time_score(path):
        # Extract latest timestep from names like CFD-xxxx_500/internal.vtu
        s = str(path)
        matches = re.findall(r"_(\d+(?:\.\d+)?)(?=[\\/_.])", s)
        if matches:
            try:
                return max(float(m) for m in matches)
            except Exception:
                return -1.0
        return -1.0

    def priority(path):
        name = path.name.lower()
        full = str(path).lower()
        pref = (preferred_field or "").lower()

        # For now, internal.vtu is the best default because it contains actual CFD volume fields.
        if name == "internal.vtu":
            return 0
        if name.endswith(".vtu") and "internal" in name:
            return 1

        if "boundary" in pref or "surface" in pref:
            if name.endswith(".vtp") and "boundary" in full:
                return 2
            if name.endswith(".vtm") and "boundary" in name:
                return 3

        if name.endswith(".vtp") and "boundary" in full:
            return 4
        if name.endswith(".vtm"):
            return 5
        if name.endswith(".vtk"):
            return 6
        return 7

    files = sorted(files, key=lambda p: (priority(p), -time_score(p), -p.stat().st_mtime, str(p)))
    return files[0]



def list_openfoam_vtk_candidates(case_dir, limit=30):
    """
    Returns a debug list of OpenFOAM visualization files under the case directory.
    Supports .vtk, .vtu, .vtp, and .vtm output from foamToVTK.
    """
    case_dir = Path(case_dir)
    exts = (".vtk", ".vtu", ".vtp", ".vtm")
    files = []
    for pattern in [
        "VTK/**/*",
        "postProcessing/**/*",
        "**/*",
    ]:
        files.extend([p for p in case_dir.glob(pattern) if p.is_file() and p.suffix.lower() in exts])

    files = sorted({p.resolve() for p in files}, key=lambda p: str(p))
    return files[:limit], len(files)



def _read_vtk_xml_points_connectivity(vtk_path, preferred_fields=None):
    """
    Minimal XML VTK reader for ASCII .vtp PolyData and .vtu UnstructuredGrid files.
    It extracts points, connectivity, offsets, cell types, and scalar arrays when available.
    """
    import xml.etree.ElementTree as ET

    vtk_path = Path(vtk_path)
    root = ET.parse(vtk_path).getroot()

    def strip_ns(tag):
        return tag.split("}")[-1]

    def find_first(elem, wanted):
        for child in elem.iter():
            if strip_ns(child.tag) == wanted:
                return child
        return None

    def parse_array_text(da, dtype=float):
        if da is None or da.text is None:
            return np.array([], dtype=dtype)
        txt = da.text.strip()
        if not txt:
            return np.array([], dtype=dtype)
        vals = []
        for tok in txt.split():
            try:
                vals.append(dtype(tok))
            except Exception:
                pass
        return np.array(vals, dtype=dtype)

    piece = find_first(root, "Piece")
    if piece is None:
        return None

    points_elem = find_first(piece, "Points")
    if points_elem is None:
        return None
    point_da = None
    for da in points_elem.iter():
        if strip_ns(da.tag) == "DataArray":
            point_da = da
            break
    pts_flat = parse_array_text(point_da, float)
    if pts_flat.size < 9:
        return None
    points = pts_flat.reshape((-1, 3))

    cells = []
    if vtk_path.suffix.lower() == ".vtp":
        polys_elem = find_first(piece, "Polys")
        if polys_elem is None:
            # Some boundary files may store strips/verts; only polygons are useful for Mesh3D.
            return None
        connectivity = offsets = None
        for da in polys_elem:
            if strip_ns(da.tag) == "DataArray":
                name = da.attrib.get("Name", "").lower()
                if name == "connectivity":
                    connectivity = parse_array_text(da, int)
                elif name == "offsets":
                    offsets = parse_array_text(da, int)
        if connectivity is None or offsets is None or offsets.size == 0:
            return None
        start = 0
        for off in offsets:
            ids = connectivity[start:int(off)]
            start = int(off)
            if ids.size >= 3:
                for k in range(1, ids.size - 1):
                    cells.append([int(ids[0]), int(ids[k]), int(ids[k + 1])])

    else:
        cells_elem = find_first(piece, "Cells")
        if cells_elem is None:
            return None
        connectivity = offsets = types = None
        for da in cells_elem:
            if strip_ns(da.tag) == "DataArray":
                name = da.attrib.get("Name", "").lower()
                if name == "connectivity":
                    connectivity = parse_array_text(da, int)
                elif name == "offsets":
                    offsets = parse_array_text(da, int)
                elif name == "types":
                    types = parse_array_text(da, int)
        if connectivity is None or offsets is None or offsets.size == 0:
            return None
        start = 0
        for idx, off in enumerate(offsets):
            ids = connectivity[start:int(off)]
            start = int(off)
            if ids.size < 3:
                continue
            ctype = int(types[idx]) if types is not None and idx < types.size else None

            # VTK triangle=5, quad=9, polygon=7, tetra=10, hex=12, wedge=13, pyramid=14
            # For volume cells, draw one or more surface-ish faces for quick visualization.
            if ids.size == 3:
                cells.append([int(ids[0]), int(ids[1]), int(ids[2])])
            elif ids.size == 4:
                # Could be quad or tetra. Draw all tetra faces if type 10; otherwise split quad.
                if ctype == 10:
                    faces4 = [(0,1,2),(0,1,3),(0,2,3),(1,2,3)]
                    for a,b,c in faces4:
                        cells.append([int(ids[a]), int(ids[b]), int(ids[c])])
                else:
                    cells.append([int(ids[0]), int(ids[1]), int(ids[2])])
                    cells.append([int(ids[0]), int(ids[2]), int(ids[3])])
            elif ids.size >= 5:
                # Generic polygon/polyhedron fallback: fan triangulate first loop.
                for k in range(1, ids.size - 1):
                    cells.append([int(ids[0]), int(ids[k]), int(ids[k + 1])])

    if not cells:
        return None

    # Try to find useful scalar arrays in PointData or CellData.
    scalar_name = None
    scalar_values = None
    scalar_location = None

    for data_tag, loc in [("PointData", "point"), ("CellData", "cell")]:
        data_elem = find_first(piece, data_tag)
        if data_elem is None:
            continue

        arrays = []
        for da in data_elem:
            if strip_ns(da.tag) != "DataArray":
                continue
            name = da.attrib.get("Name", "")
            ncomp = int(da.attrib.get("NumberOfComponents", "1") or "1")
            arr = parse_array_text(da, float)
            if arr.size == 0:
                continue
            arrays.append((name, ncomp, arr))

        # Field preference: pressure for load plots, U magnitude for wake/streamline plots.
        preferred_order = preferred_fields or ["p", "pressure", "U", "velocity"]
        for preferred in preferred_order:
            for name, ncomp, arr in arrays:
                if name.lower() == preferred.lower() or preferred.lower() in name.lower():
                    if ncomp == 1:
                        scalar_name = name
                        scalar_values = arr
                    elif ncomp == 3 and arr.size % 3 == 0:
                        vec = arr.reshape((-1, 3))
                        scalar_name = f"{name} magnitude"
                        scalar_values = np.linalg.norm(vec, axis=1)
                    scalar_location = loc
                    break
            if scalar_values is not None:
                break

        if scalar_values is None and arrays:
            name, ncomp, arr = arrays[0]
            if ncomp == 1:
                scalar_name = name
                scalar_values = arr
                scalar_location = loc
            elif ncomp == 3 and arr.size % 3 == 0:
                scalar_name = f"{name} magnitude"
                scalar_values = np.linalg.norm(arr.reshape((-1, 3)), axis=1)
                scalar_location = loc

        if scalar_values is not None:
            break

    cells_arr = np.array(cells, dtype=int)
    intensity = None
    if scalar_values is not None:
        vals = np.array(scalar_values, dtype=float)
        if scalar_location == "point" and vals.size == points.shape[0]:
            intensity = np.mean(vals[cells_arr], axis=1)
        elif scalar_location == "cell" and vals.size >= cells_arr.shape[0]:
            intensity = vals[:cells_arr.shape[0]]
        elif vals.size > 0:
            intensity = np.full(cells_arr.shape[0], float(np.mean(vals)))

    return {
        "path": str(vtk_path),
        "points": points,
        "cells": cells_arr,
        "scalar_name": scalar_name,
        "intensity": intensity,
    }


def read_openfoam_visual_file(vtk_path, max_cells=120000, preferred_fields=None):
    vtk_path = Path(vtk_path)
    if vtk_path.suffix.lower() in [".vtp", ".vtu"]:
        data = _read_vtk_xml_points_connectivity(vtk_path, preferred_fields=preferred_fields)
        if data is not None and data["cells"].shape[0] > max_cells:
            data["cells"] = data["cells"][:max_cells]
            if data.get("intensity") is not None:
                data["intensity"] = data["intensity"][:max_cells]
        return data
    if vtk_path.suffix.lower() == ".vtk":
        return read_legacy_vtk_surface(vtk_path, max_cells=max_cells)
    # .vtm is a multiblock index; use first child vtp/vtu in same folder if possible.
    if vtk_path.suffix.lower() == ".vtm":
        folder = vtk_path.parent
        for child in list(folder.glob("internal.vtu")) + list(folder.glob("boundary/*.vtp")) + list(folder.glob("*.vtu")) + list(folder.glob("**/*.vtp")):
            data = _read_vtk_xml_points_connectivity(child, preferred_fields=preferred_fields)
            if data is not None:
                return data
    return None


def read_legacy_vtk_surface(vtk_path, max_cells=120000):
    """
    Lightweight reader for legacy ASCII VTK files created by foamToVTK -ascii.

    Supports:
    - POINTS
    - POLYGONS
    - CELLS with triangle/quad/poly cells
    - POINT_DATA/CELL_DATA scalar fields

    Returns a dict suitable for Plotly Mesh3d.
    """
    vtk_path = Path(vtk_path)
    text = vtk_path.read_text(encoding="utf-8", errors="ignore")
    lines = text.splitlines()

    points = []
    cells = []
    scalar_name = None
    scalar_values = []

    i = 0
    n = len(lines)

    while i < n:
        parts = lines[i].strip().split()
        if not parts:
            i += 1
            continue

        key = parts[0].upper()

        if key == "POINTS" and len(parts) >= 3:
            try:
                npts = int(parts[1])
            except Exception:
                i += 1
                continue

            vals = []
            i += 1
            while i < n and len(vals) < npts * 3:
                vals.extend(lines[i].strip().split())
                i += 1

            arr = []
            for tok in vals[: npts * 3]:
                try:
                    arr.append(float(tok))
                except Exception:
                    arr.append(0.0)

            points = np.array(arr, dtype=float).reshape((-1, 3))
            continue

        if key in ("POLYGONS", "CELLS") and len(parts) >= 3:
            try:
                ncells = int(parts[1])
            except Exception:
                i += 1
                continue

            i += 1
            read_cells = 0
            while i < n and read_cells < ncells:
                vals = lines[i].strip().split()
                if vals:
                    try:
                        count = int(vals[0])
                        ids = [int(v) for v in vals[1:1+count]]
                        if len(ids) >= 3:
                            # Triangulate polygon fan: [0, k, k+1]
                            for k in range(1, len(ids)-1):
                                cells.append([ids[0], ids[k], ids[k+1]])
                    except Exception:
                        pass
                    read_cells += 1
                i += 1
            continue

        if key in ("POINT_DATA", "CELL_DATA") and len(parts) >= 2:
            data_kind = key
            try:
                data_count = int(parts[1])
            except Exception:
                data_count = 0
            i += 1

            # Find first scalar field; skip vector fields for now
            while i < n:
                p = lines[i].strip().split()
                if not p:
                    i += 1
                    continue
                if p[0].upper() in ("POINT_DATA", "CELL_DATA", "FIELD"):
                    break
                if p[0].upper() == "SCALARS" and len(p) >= 2:
                    scalar_name = p[1]
                    # next line is usually LOOKUP_TABLE
                    i += 1
                    if i < n and lines[i].strip().upper().startswith("LOOKUP_TABLE"):
                        i += 1
                    vals = []
                    while i < n and len(vals) < data_count:
                        line_parts = lines[i].strip().split()
                        # Stop if a new VTK section starts.
                        if line_parts and line_parts[0].upper() in (
                            "SCALARS", "VECTORS", "POINT_DATA", "CELL_DATA", "FIELD", "LOOKUP_TABLE"
                        ):
                            break
                        for tok in line_parts:
                            try:
                                vals.append(float(tok))
                            except Exception:
                                pass
                        i += 1
                    scalar_values = vals[:data_count]
                    break
                i += 1
            continue

        i += 1

    if isinstance(points, list) or len(points) == 0 or len(cells) == 0:
        return None

    cells = np.array(cells[:max_cells], dtype=int)

    # Convert scalar values to per-face intensity if possible.
    intensity = None
    if scalar_values:
        vals = np.array(scalar_values, dtype=float)
        if vals.size == points.shape[0]:
            # point scalar -> average at triangle nodes
            intensity = np.mean(vals[cells], axis=1)
        elif vals.size >= cells.shape[0]:
            intensity = vals[:cells.shape[0]]

    return {
        "path": str(vtk_path),
        "points": points,
        "cells": cells,
        "scalar_name": scalar_name,
        "intensity": intensity,
    }





def snappy_object_patch_present(case_dir):
    """
    Checks the OpenFOAM boundary file for an object wall patch created by snappyHexMesh.
    If this is false, OpenFOAM did not body-fit the uploaded object and the field will not
    physically interact with it.
    """
    boundary_path = Path(case_dir) / "constant" / "polyMesh" / "boundary"
    if not boundary_path.exists():
        return False, "constant/polyMesh/boundary was not found."

    txt = boundary_path.read_text(encoding="utf-8", errors="ignore")
    object_like = (
        re.search(r"\bobject\b\s*\{", txt) is not None
        or re.search(r"\buploadedObject\b\s*\{", txt) is not None
        or "uploadedObject" in txt
    )
    if object_like and re.search(r"type\s+wall\s*;", txt):
        return True, "Object wall patch found in constant/polyMesh/boundary."
    return False, "No object wall patch was detected. Run a new V3.54+ job and check snappyHexMesh output."


def find_latest_object_boundary_vtp(case_dir):
    """
    Finds the object wall boundary exported by foamToVTK, if present.
    This is the best proof that the OpenFOAM mesh has an actual body-fitted wall.
    """
    case_dir = Path(case_dir)
    candidates = []
    for p in case_dir.glob("VTK/**/boundary/*.vtp"):
        name = p.name.lower()
        full = str(p).lower()
        if "object" in name or "uploaded" in name or "triSurface" in full.lower():
            candidates.append(p)

    if not candidates:
        for p in case_dir.glob("VTK/**/boundary/*.vtp"):
            if p.name.lower() not in ["xmin.vtp", "xmax.vtp", "ymin.vtp", "ymax.vtp", "zmin.vtp", "zmax.vtp"]:
                candidates.append(p)

    if not candidates:
        return None

    candidates = sorted(candidates, key=lambda p: (-p.stat().st_mtime, str(p)))
    return candidates[0]


def read_openfoam_field_points(vtk_path, preferred_fields=None, max_points=120000):
    """
    Reads OpenFOAM foamToVTK XML output as true cell-centered field points.

    Why this is needed:
    - internal.vtu contains volume cells.
    - Rendering those cells as Mesh3d triangles creates fake sheets/floors.
    - For an accurate submerged object view, we should use the actual volume-cell
      centroids and color them by p or |U|.

    Returns:
      {
        path, centers, intensity, scalar_name, domain_points
      }
    """
    import xml.etree.ElementTree as ET

    vtk_path = Path(vtk_path)

    # Handle multiblock VTM by selecting internal.vtu first.
    if vtk_path.suffix.lower() == ".vtm":
        folder = vtk_path.parent
        candidates = list(folder.glob("internal.vtu")) + list(folder.glob("*.vtu")) + list(folder.glob("**/internal.vtu"))
        if not candidates:
            return None
        return read_openfoam_field_points(candidates[0], preferred_fields=preferred_fields, max_points=max_points)

    if vtk_path.suffix.lower() not in [".vtu", ".vtp"]:
        # Legacy fallback: use previous reader then centroid its triangles.
        data = read_openfoam_visual_file(vtk_path, max_cells=max_points, preferred_fields=preferred_fields)
        if data is None:
            return None
        pts = np.asarray(data["points"], dtype=float)
        cells = np.asarray(data["cells"], dtype=int)
        centers = np.mean(pts[cells], axis=1)
        intensity = data.get("intensity")
        if intensity is not None:
            intensity = np.asarray(intensity)[:len(centers)]
        return {
            "path": str(vtk_path),
            "centers": centers,
            "intensity": intensity,
            "scalar_name": data.get("scalar_name"),
            "domain_points": pts,
        }

    root = ET.parse(vtk_path).getroot()

    def strip_ns(tag):
        return tag.split("}")[-1]

    def find_first(elem, wanted):
        for child in elem.iter():
            if strip_ns(child.tag) == wanted:
                return child
        return None

    def parse_array_text(da, dtype=float):
        if da is None or da.text is None:
            return np.array([], dtype=dtype)
        vals = []
        for tok in da.text.strip().split():
            try:
                vals.append(dtype(tok))
            except Exception:
                pass
        return np.array(vals, dtype=dtype)

    piece = find_first(root, "Piece")
    if piece is None:
        return None

    # Points
    points_elem = find_first(piece, "Points")
    if points_elem is None:
        return None
    point_da = None
    for da in points_elem.iter():
        if strip_ns(da.tag) == "DataArray":
            point_da = da
            break
    pts_flat = parse_array_text(point_da, float)
    if pts_flat.size < 9:
        return None
    points = pts_flat.reshape((-1, 3))

    # Cell vertex-id groups
    cell_ids = []
    if vtk_path.suffix.lower() == ".vtu":
        cells_elem = find_first(piece, "Cells")
        if cells_elem is None:
            return None
        connectivity = offsets = None
        for da in cells_elem:
            if strip_ns(da.tag) == "DataArray":
                nm = da.attrib.get("Name", "").lower()
                if nm == "connectivity":
                    connectivity = parse_array_text(da, int)
                elif nm == "offsets":
                    offsets = parse_array_text(da, int)
        if connectivity is None or offsets is None or offsets.size == 0:
            return None
        start = 0
        for off in offsets:
            ids = connectivity[start:int(off)]
            start = int(off)
            ids = ids[(ids >= 0) & (ids < len(points))]
            if ids.size >= 3:
                cell_ids.append(np.unique(ids))
    else:
        polys_elem = find_first(piece, "Polys")
        if polys_elem is None:
            return None
        connectivity = offsets = None
        for da in polys_elem:
            if strip_ns(da.tag) == "DataArray":
                nm = da.attrib.get("Name", "").lower()
                if nm == "connectivity":
                    connectivity = parse_array_text(da, int)
                elif nm == "offsets":
                    offsets = parse_array_text(da, int)
        if connectivity is None or offsets is None or offsets.size == 0:
            return None
        start = 0
        for off in offsets:
            ids = connectivity[start:int(off)]
            start = int(off)
            ids = ids[(ids >= 0) & (ids < len(points))]
            if ids.size >= 3:
                cell_ids.append(np.unique(ids))

    if not cell_ids:
        return None

    centers = np.array([np.mean(points[ids], axis=0) for ids in cell_ids], dtype=float)

    # Collect field arrays.
    arrays_by_loc = []
    for data_tag, loc in [("CellData", "cell"), ("PointData", "point")]:
        data_elem = find_first(piece, data_tag)
        if data_elem is None:
            continue
        arrays = []
        for da in data_elem:
            if strip_ns(da.tag) != "DataArray":
                continue
            name = da.attrib.get("Name", "field")
            try:
                ncomp = int(da.attrib.get("NumberOfComponents", "1") or "1")
            except Exception:
                ncomp = 1
            arr = parse_array_text(da, float)
            if arr.size:
                arrays.append((name, ncomp, arr))
        if arrays:
            arrays_by_loc.append((loc, arrays))

    preferred_order = preferred_fields or ["p", "pressure", "U", "velocity"]
    scalar_name = None
    scalar_values = None
    scalar_location = None

    for loc, arrays in arrays_by_loc:
        for preferred in preferred_order:
            for name, ncomp, arr in arrays:
                if name.lower() == preferred.lower() or preferred.lower() in name.lower():
                    if ncomp == 1:
                        scalar_name, scalar_values, scalar_location = name, arr, loc
                    elif ncomp == 3 and arr.size % 3 == 0:
                        scalar_name = f"{name} magnitude"
                        scalar_values = np.linalg.norm(arr.reshape((-1, 3)), axis=1)
                        scalar_location = loc
                    break
            if scalar_values is not None:
                break
        if scalar_values is not None:
            break

    if scalar_values is None and arrays_by_loc:
        loc, arrays = arrays_by_loc[0]
        name, ncomp, arr = arrays[0]
        if ncomp == 1:
            scalar_name, scalar_values, scalar_location = name, arr, loc
        elif ncomp == 3 and arr.size % 3 == 0:
            scalar_name = f"{name} magnitude"
            scalar_values = np.linalg.norm(arr.reshape((-1, 3)), axis=1)
            scalar_location = loc

    intensity = None
    if scalar_values is not None:
        vals = np.asarray(scalar_values, dtype=float)
        if scalar_location == "cell" and vals.size >= len(cell_ids):
            intensity = vals[:len(cell_ids)]
        elif scalar_location == "point" and vals.size == len(points):
            intensity = np.array([float(np.mean(vals[ids])) for ids in cell_ids], dtype=float)
        elif vals.size:
            intensity = np.full(len(cell_ids), float(np.nanmean(vals)))

    # Downsample evenly for browser performance.
    if len(centers) > max_points:
        keep = np.linspace(0, len(centers) - 1, max_points).astype(int)
        centers = centers[keep]
        if intensity is not None:
            intensity = intensity[keep]

    return {
        "path": str(vtk_path),
        "centers": centers,
        "intensity": intensity,
        "scalar_name": scalar_name,
        "domain_points": points,
    }


def filter_field_points_for_centered_submerged_view(field_data, bounds_m=None, front_selection="+X front", max_points=120000):
    """
    Filters true cell centers for a centered submerged-object view.

    The object is centered visually in crossflow directions. Flow direction keeps
    upstream and downstream region, but the local view no longer collapses to a base
    sheet or appears offset due to triangulated volume-cell artifacts.
    """
    if field_data is None:
        return field_data

    centers = np.asarray(field_data.get("centers"), dtype=float)
    intensity = field_data.get("intensity")
    if centers.size == 0 or bounds_m is None:
        return field_data

    xmin, xmax = float(bounds_m["x_min"]), float(bounds_m["x_max"])
    ymin, ymax = float(bounds_m["y_min"]), float(bounds_m["y_max"])
    zmin, zmax = float(bounds_m["z_min"]), float(bounds_m["z_max"])
    lx = max(float(bounds_m["x_length"]), 1e-12)
    ly = max(float(bounds_m["y_length"]), 1e-12)
    lz = max(float(bounds_m["z_length"]), 1e-12)
    max_dim = max(lx, ly, lz, 1e-12)
    obj_center = np.array([(xmin+xmax)/2, (ymin+ymax)/2, (zmin+zmax)/2], dtype=float)

    flow = np.asarray(flow_vector_from_front(front_selection), dtype=float)
    flow = flow / max(np.linalg.norm(flow), 1e-12)
    rel = centers - obj_center
    s = rel @ flow
    lateral = rel - np.outer(s, flow)
    lat_mag = np.linalg.norm(lateral, axis=1)

    # Hide cell centers inside object; keep all surrounding cells.
    inside_obj = (
        (centers[:, 0] >= xmin) & (centers[:, 0] <= xmax) &
        (centers[:, 1] >= ymin) & (centers[:, 1] <= ymax) &
        (centers[:, 2] >= zmin) & (centers[:, 2] <= zmax)
    )

    # A balanced local fluid volume around the object, plus longer downstream wake.
    local_box_pad = 3.0 * max_dim
    local_box = (
        (centers[:, 0] >= xmin - local_box_pad) & (centers[:, 0] <= xmax + local_box_pad) &
        (centers[:, 1] >= ymin - local_box_pad) & (centers[:, 1] <= ymax + local_box_pad) &
        (centers[:, 2] >= zmin - local_box_pad) & (centers[:, 2] <= zmax + local_box_pad)
    )
    wake = (s > -1.5 * max_dim) & (s < 9.0 * max_dim) & (lat_mag < 2.5 * max_dim)

    keep = (~inside_obj) & (local_box | wake)
    idx = np.where(keep)[0]
    if idx.size == 0:
        idx = np.arange(len(centers))

    if idx.size > max_points:
        # Prioritize local object-surrounding volume, then wake.
        local_idx = idx[local_box[idx]]
        wake_idx = idx[~local_box[idx]]
        local_quota = int(max_points * 0.78)
        chosen = []
        if local_idx.size:
            chosen.append(local_idx[np.linspace(0, local_idx.size - 1, min(local_quota, local_idx.size)).astype(int)])
        rem = max_points - (len(chosen[0]) if chosen else 0)
        if wake_idx.size and rem > 0:
            chosen.append(wake_idx[np.linspace(0, wake_idx.size - 1, min(rem, wake_idx.size)).astype(int)])
        idx = np.concatenate(chosen) if chosen else idx[:max_points]

    out = dict(field_data)
    out["centers"] = centers[idx]
    if intensity is not None:
        arr = np.asarray(intensity)
        if len(arr) >= len(centers):
            out["intensity"] = arr[idx]
    out["filter_note"] = "true_cell_centers_centered_submerged_view"
    return out




def add_actual_object_boundary_patch(
    fig,
    case_dir,
    field_mode="pressure",
    show_object_colorbar=False,
    rho_ref=1.225,
    static_pressure_ref=101325.0,
    colorscale_override=None,
    trace_name="Actual OpenFOAM object wall pressure",
):
    """
    Overlays the actual snappyHexMesh object boundary patch from foamToVTK when available.

    Pressure mode:
      - OpenFOAM incompressible simpleFoam writes p as kinematic pressure p/rho [m²/s²].
      - Customer-facing pressure is converted to absolute pressure:
            p_abs = p_static + rho * p_OpenFOAM
      - This keeps the object pressure legend consistent with the actual OpenFOAM
        pressure field view.

    Velocity/wake mode:
      - object is neutral gray so it does not compete with the velocity field.
    """
    vtp = find_latest_object_boundary_vtp(case_dir)
    if vtp is None:
        return fig, None

    rho_ref = _numeric_from_value(rho_ref, default=1.225)
    static_pressure_ref = _numeric_from_value(static_pressure_ref, default=101325.0)

    if field_mode == "velocity":
        preferred = ["U", "velocity", "mag(U)", "p", "pressure"]
    else:
        preferred = ["p", "pressure", "U", "velocity"]

    data = read_openfoam_visual_file(vtp, max_cells=60000, preferred_fields=preferred)
    if data is None:
        return fig, None

    pts = np.asarray(data["points"], dtype=float)
    cells = np.asarray(data["cells"], dtype=int)
    if pts.size == 0 or cells.size == 0:
        return fig, None

    mesh_kwargs = dict(
        x=pts[:, 0], y=pts[:, 1], z=pts[:, 2],
        i=cells[:, 0], j=cells[:, 1], k=cells[:, 2],
        opacity=0.94,
        flatshading=True,
        name=trace_name,
        hovertemplate="Actual OpenFOAM object wall<extra></extra>",
        showscale=False,
        showlegend=False,
    )

    if field_mode == "velocity":
        mesh_kwargs.update(color="rgba(210,210,210,0.92)")
    else:
        intensity = data.get("intensity")
        scalar_name = str(data.get("scalar_name") or "")
        if intensity is not None and len(intensity) >= len(cells):
            raw = np.asarray(intensity, dtype=float)[:len(cells)]
            # Convert actual OpenFOAM p to absolute Pa when the scalar is pressure.
            if scalar_name.lower() in ["p", "pressure"] or "pressure" in scalar_name.lower():
                pressure_vals = static_pressure_ref + rho_ref * raw
                hover = (
                    "Object surface pressure: %{intensity:.6g} Pa<br>"
                    f"Converted from OpenFOAM p with ρ={rho_ref:.6g} kg/m³<extra></extra>"
                )
                colorbar_title = "Object surface pressure [Pa]<br>from OpenFOAM"
            else:
                pressure_vals = raw
                hover = "Object wall field: %{intensity:.6g}<extra></extra>"
                colorbar_title = "Object wall field"

            finite = pressure_vals[np.isfinite(pressure_vals)]
            if finite.size:
                cmin = float(np.nanpercentile(finite, 2))
                cmax = float(np.nanpercentile(finite, 98))
                if not np.isfinite(cmin) or not np.isfinite(cmax) or abs(cmax-cmin) < 1e-15:
                    cmin = float(np.nanmin(finite))
                    cmax = float(np.nanmax(finite) + 1e-12)
            else:
                cmin, cmax = static_pressure_ref - 1.0, static_pressure_ref + 1.0

            mesh_kwargs.update(
                intensity=pressure_vals,
                intensitymode="cell",
                colorscale=colorscale_override or [
                    [0.0, "limegreen"],
                    [0.55, "yellow"],
                    [1.0, "red"],
                ],
                cmin=cmin,
                cmax=cmax,
                showscale=bool(show_object_colorbar),
                colorbar=dict(
                    title=colorbar_title,
                    x=1.02,
                    len=0.55,
                    thickness=18,
                ) if show_object_colorbar else None,
                hovertemplate=hover,
            )
        else:
            mesh_kwargs.update(color="silver")

    if mesh_kwargs.get("colorbar") is None:
        mesh_kwargs.pop("colorbar", None)

    fig.add_trace(go.Mesh3d(**mesh_kwargs))
    return fig, str(vtp)



def add_fluid_domain_outline(fig, points, name="Fluid domain boundary"):
    """
    Adds a light wireframe bounding box around the OpenFOAM field so users see
    that the object is inside a surrounding fluid domain.
    """
    try:
        pts = np.asarray(points, dtype=float)
        if pts.size == 0:
            return fig
        xmin, ymin, zmin = np.nanmin(pts, axis=0)
        xmax, ymax, zmax = np.nanmax(pts, axis=0)

        corners = np.array([
            [xmin, ymin, zmin], [xmax, ymin, zmin], [xmax, ymax, zmin], [xmin, ymax, zmin],
            [xmin, ymin, zmax], [xmax, ymin, zmax], [xmax, ymax, zmax], [xmin, ymax, zmax],
        ])
        edges = [(0,1),(1,2),(2,3),(3,0),(4,5),(5,6),(6,7),(7,4),(0,4),(1,5),(2,6),(3,7)]
        xs, ys, zs = [], [], []
        for a, b in edges:
            xs += [corners[a,0], corners[b,0], None]
            ys += [corners[a,1], corners[b,1], None]
            zs += [corners[a,2], corners[b,2], None]
        fig.add_trace(go.Scatter3d(
            x=xs, y=ys, z=zs,
            mode="lines",
            line=dict(width=2, color="rgba(220,220,220,0.35)"),
            name=name,
            hoverinfo="skip",
            showlegend=False,
        ))
    except Exception:
        pass
    return fig




def filter_vtk_cells_for_object_interaction(data, bounds_m=None, front_selection="+X front", max_cells=90000):
    """
    Customer-facing OpenFOAM field filter.

    Previous versions kept a narrow center/wake slice. For submerged or fully
    surrounded external flow, that could make the velocity field look like it only
    existed on the base of the object. This version keeps:

      1. a full near-field fluid shell around every object face
      2. wake corridor downstream of the object
      3. centerline slices through the object center for depth visibility

    The uploaded object volume is hidden, but the surrounding fluid cells remain.
    """
    if data is None:
        return data

    pts = np.asarray(data.get("points"), dtype=float)
    cells = np.asarray(data.get("cells"), dtype=int)
    if pts.size == 0 or cells.size == 0:
        return data

    if bounds_m is None:
        if cells.shape[0] > max_cells:
            keep = np.linspace(0, cells.shape[0] - 1, max_cells).astype(int)
            data = dict(data)
            data["cells"] = cells[keep]
            if data.get("intensity") is not None:
                data["intensity"] = np.asarray(data["intensity"])[keep]
        return data

    centroids = np.mean(pts[cells], axis=1)

    xmin, xmax = float(bounds_m["x_min"]), float(bounds_m["x_max"])
    ymin, ymax = float(bounds_m["y_min"]), float(bounds_m["y_max"])
    zmin, zmax = float(bounds_m["z_min"]), float(bounds_m["z_max"])
    lx = max(float(bounds_m["x_length"]), 1e-12)
    ly = max(float(bounds_m["y_length"]), 1e-12)
    lz = max(float(bounds_m["z_length"]), 1e-12)
    max_dim = max(lx, ly, lz, 1e-12)

    center = np.array([(xmin + xmax) * 0.5, (ymin + ymax) * 0.5, (zmin + zmax) * 0.5], dtype=float)

    # Hide only cells that fall inside the object box. Keep surrounding fluid.
    internal_pad = 0.02 * max_dim
    inside_obj_box = (
        (centroids[:, 0] >= xmin - internal_pad) & (centroids[:, 0] <= xmax + internal_pad) &
        (centroids[:, 1] >= ymin - internal_pad) & (centroids[:, 1] <= ymax + internal_pad) &
        (centroids[:, 2] >= zmin - internal_pad) & (centroids[:, 2] <= zmax + internal_pad)
    )

    # Full near-field box around object so the customer sees the object submerged.
    near_pad = 2.2 * max_dim
    near_object_field = (
        (centroids[:, 0] >= xmin - near_pad) & (centroids[:, 0] <= xmax + near_pad) &
        (centroids[:, 1] >= ymin - near_pad) & (centroids[:, 1] <= ymax + near_pad) &
        (centroids[:, 2] >= zmin - near_pad) & (centroids[:, 2] <= zmax + near_pad)
    )

    flow = np.asarray(flow_vector_from_front(front_selection), dtype=float)
    flow = flow / max(np.linalg.norm(flow), 1e-12)
    rel = centroids - center
    s = rel @ flow
    lateral = rel - np.outer(s, flow)
    lat_mag = np.linalg.norm(lateral, axis=1)

    # Wake corridor downstream and short upstream region.
    wake_corridor = (s > -1.2 * max_dim) & (s < 9.0 * max_dim) & (lat_mag < 2.4 * max_dim)

    # Orthogonal slices through object center. These show that fluid exists above,
    # below, left, right, front, and rear without drawing the entire dense mesh.
    slice_thickness = 0.32 * max_dim
    x_slice = np.abs(centroids[:, 0] - center[0]) < slice_thickness
    y_slice = np.abs(centroids[:, 1] - center[1]) < slice_thickness
    z_slice = np.abs(centroids[:, 2] - center[2]) < slice_thickness

    # A thin shell near the actual object surface, excluding the object's interior.
    shell_pad = 0.75 * max_dim
    object_shell = (
        (centroids[:, 0] >= xmin - shell_pad) & (centroids[:, 0] <= xmax + shell_pad) &
        (centroids[:, 1] >= ymin - shell_pad) & (centroids[:, 1] <= ymax + shell_pad) &
        (centroids[:, 2] >= zmin - shell_pad) & (centroids[:, 2] <= zmax + shell_pad)
    )

    keep_mask = (~inside_obj_box) & (
        near_object_field |
        wake_corridor |
        object_shell |
        (x_slice & wake_corridor) |
        (y_slice & wake_corridor) |
        (z_slice & wake_corridor)
    )

    idx = np.where(keep_mask)[0]
    if idx.size == 0:
        idx = np.arange(cells.shape[0])

    # Prefer retaining near-object cells if the browser limit is exceeded.
    if idx.size > max_cells:
        near_idx = idx[near_object_field[idx] | object_shell[idx]]
        wake_idx = idx[~(near_object_field[idx] | object_shell[idx])]

        near_quota = int(max_cells * 0.70)
        wake_quota = max_cells - min(near_quota, near_idx.size)

        kept = []
        if near_idx.size:
            kept.append(near_idx[np.linspace(0, near_idx.size - 1, min(near_quota, near_idx.size)).astype(int)])
        if wake_idx.size and wake_quota > 0:
            kept.append(wake_idx[np.linspace(0, wake_idx.size - 1, min(wake_quota, wake_idx.size)).astype(int)])

        if kept:
            idx = np.concatenate(kept)
        else:
            idx = idx[np.linspace(0, idx.size - 1, max_cells).astype(int)]

    data = dict(data)
    data["cells"] = cells[idx]
    if data.get("intensity") is not None:
        intens = np.asarray(data["intensity"])
        if intens.size >= cells.shape[0]:
            data["intensity"] = intens[idx]
    data["filter_note"] = "submerged_near_field_shell_plus_wake"
    return data



def openfoam_vtk_figure(
    case_dir,
    max_cells=120000,
    bounds_m=None,
    front_selection='+X front',
    field_mode='pressure',
    rho_ref=1.225,
    velocity_ref=30.0,
    static_pressure_ref=101325.0,
    show_fluid_field=True,
    show_footer_note=True,
    zoom_to_object=False,
):
    """
    Builds a true cell-centered OpenFOAM field view.

    Unit correction:
    - simpleFoam stores p as kinematic pressure, p/rho, with units m²/s².
    - Customer-facing pressure should be Pa.
    - Therefore gauge pressure [Pa] = rho * p_foam.
    - Absolute pressure [Pa] = static_pressure_ref + rho * p_foam.

    Velocity correction:
    - U is local velocity magnitude, not the inlet input everywhere.
    - Near the object and wake it can be lower than the input velocity.
    - The color range is anchored to the user input velocity so the scale is not misleading.
    """
    vtk_path = find_latest_openfoam_vtk(case_dir)
    if vtk_path is None:
        return None, f"No VTK output found under {Path(case_dir)}. Run foamToVTK -ascii after simpleFoam, then check find . -name \"*.vtk\"."

    rho_ref = _numeric_from_value(rho_ref, default=1.225)
    velocity_ref = abs(_numeric_from_value(velocity_ref, default=30.0))
    static_pressure_ref = _numeric_from_value(static_pressure_ref, default=101325.0)

    if field_mode == "velocity":
        preferred_fields = ["U", "velocity", "mag(U)", "p", "pressure"]
        field_colorscale = [
            [0.0, "navy"],
            [0.18, "blue"],
            [0.40, "cyan"],
            [0.62, "limegreen"],
            [0.82, "yellow"],
            [1.0, "orangered"],
        ]
        legend_title = "Local |U| [m/s]"
        trace_name = "Fluid velocity cell centers"
        opacity_value = 0.52
    else:
        preferred_fields = ["p", "pressure", "U", "velocity"]
        field_colorscale = [
            [0.0, "blue"],
            [0.25, "cyan"],
            [0.55, "limegreen"],
            [0.80, "yellow"],
            [1.0, "red"],
        ]
        legend_title = "Absolute fluid pressure [Pa]"
        trace_name = "Fluid pressure cell centers"
        opacity_value = 0.44

    field_data = read_openfoam_field_points(vtk_path, preferred_fields=preferred_fields, max_points=max_cells)
    if field_data is None:
        return None, f"Could not parse OpenFOAM field points from: {vtk_path}"

    field_data = filter_field_points_for_centered_submerged_view(
        field_data,
        bounds_m=bounds_m,
        front_selection=front_selection,
        max_points=max_cells,
    )

    centers = np.asarray(field_data["centers"], dtype=float)
    if centers.size == 0:
        return None, f"No OpenFOAM cell centers found in: {vtk_path}"

    raw_intensity = field_data.get("intensity")
    if raw_intensity is not None and len(raw_intensity) >= len(centers):
        raw_vals = np.asarray(raw_intensity, dtype=float)[:len(centers)]
    else:
        raw_vals = np.zeros(len(centers), dtype=float)

    scalar_name = str(field_data.get("scalar_name") or "")
    if field_mode == "pressure":
        # OpenFOAM incompressible p is usually kinematic pressure p/rho.
        # Detect by field name and typical magnitude; convert to customer-facing Pa.
        if scalar_name.lower() in ["p", "pressure"] or "pressure" in scalar_name.lower():
            cvals = static_pressure_ref + rho_ref * raw_vals
            hover_label = "Absolute pressure"
            conversion_note = f"Converted from OpenFOAM kinematic p using p_abs = p_static + rho*p_foam. Static pressure = {static_pressure_ref:.6g} Pa, rho = {rho_ref:.6g} kg/m³."
        else:
            cvals = raw_vals
            hover_label = "Pressure field"
            conversion_note = "Pressure field shown directly from VTK because the selected scalar was not identified as OpenFOAM p."
    else:
        raw_speed_vals = np.abs(raw_vals)

        # Customer-facing velocity display:
        # Some OpenFOAM VTK exports carry very small local |U| magnitudes even
        # when the inlet/input speed is large. If we color those raw values on a
        # 0-to-input-velocity legend, the whole field becomes dark blue. To make
        # the visual match the input-speed legend, scale the displayed color field
        # so the 98th percentile of the selected OpenFOAM field maps to the input
        # velocity. The raw OpenFOAM values are preserved in hover/meta.
        finite_raw_speed = raw_speed_vals[np.isfinite(raw_speed_vals)]
        if finite_raw_speed.size:
            local_ref_speed = float(np.nanpercentile(finite_raw_speed, 98))
            if not np.isfinite(local_ref_speed) or local_ref_speed <= 1e-18:
                local_ref_speed = float(np.nanmax(finite_raw_speed))
            if not np.isfinite(local_ref_speed) or local_ref_speed <= 1e-18:
                local_ref_speed = max(float(velocity_ref), 1e-12)
        else:
            local_ref_speed = max(float(velocity_ref), 1e-12)

        velocity_visual_scale = max(float(velocity_ref), 1e-12) / max(local_ref_speed, 1e-18)
        cvals = np.clip(raw_speed_vals * velocity_visual_scale, 0.0, max(float(velocity_ref), 1e-12))
        hover_label = "Displayed velocity"
        conversion_note = (
            f"Velocity colors are normalized to the input/free-stream velocity = {velocity_ref:.6g} m/s. "
            f"Raw OpenFOAM |U| 98th percentile = {local_ref_speed:.6g} m/s; visual scale factor = {velocity_visual_scale:.6g}."
        )

    finite_vals = cvals[np.isfinite(cvals)]
    if finite_vals.size:
        if field_mode == "velocity":
            # Velocity colors are already normalized to the input velocity above,
            # so the legend should exactly show 0 -> user input velocity.
            cmin = 0.0
            cmax = max(float(velocity_ref), 1e-12)
        else:
            # Keep absolute pressure near the real static pressure, but still show variation.
            cmin = float(np.nanpercentile(finite_vals, 2))
            cmax = float(np.nanpercentile(finite_vals, 98))
            if not np.isfinite(cmin) or not np.isfinite(cmax) or abs(cmax-cmin) < 1e-15:
                cmin = float(np.nanmin(finite_vals))
                cmax = float(np.nanmax(finite_vals) + 1e-12)
    else:
        cmin, cmax = (0.0, 1.0) if field_mode == "velocity" else (static_pressure_ref - 1.0, static_pressure_ref + 1.0)

    n = len(centers)
    marker_size = 2.6 if n > 70000 else 3.4 if n > 25000 else 4.5

    fig = go.Figure()

    if show_fluid_field:
        fig.add_trace(go.Scatter3d(
            x=centers[:, 0],
            y=centers[:, 1],
            z=centers[:, 2],
            mode="markers",
            marker=dict(
                size=marker_size,
                color=cvals,
                colorscale=field_colorscale,
                cmin=cmin,
                cmax=cmax,
                opacity=opacity_value,
                colorbar=dict(
                    title=legend_title,
                    x=1.02,
                    len=0.72,
                    thickness=18,
                ),
            ),
            name=trace_name,
            customdata=raw_vals,
            hovertemplate=(
                f"{hover_label}: %{{marker.color:.6g}}<br>"
                f"Raw OpenFOAM field: %{{customdata:.6g}}<br>"
                "x=%{x:.4g}<br>y=%{y:.4g}<br>z=%{z:.4g}<extra></extra>"
            ),
            showlegend=False,
        ))
    else:
        # Keep the color legend visible even when the user hides the OpenFOAM
        # field points. Plotly only displays colorbars for actual traces, so we
        # add two nearly invisible legend-anchor points with the same cmin/cmax.
        legend_x = [float(np.nanmin(centers[:, 0])), float(np.nanmin(centers[:, 0]))]
        legend_y = [float(np.nanmin(centers[:, 1])), float(np.nanmin(centers[:, 1]))]
        legend_z = [float(np.nanmin(centers[:, 2])), float(np.nanmin(centers[:, 2]))]
        fig.add_trace(go.Scatter3d(
            x=legend_x,
            y=legend_y,
            z=legend_z,
            mode="markers",
            marker=dict(
                size=0.1,
                color=[cmin, cmax],
                colorscale=field_colorscale,
                cmin=cmin,
                cmax=cmax,
                opacity=0.01,
                colorbar=dict(
                    title=legend_title,
                    x=1.02,
                    len=0.72,
                    thickness=18,
                ),
            ),
            name=f"{trace_name} legend",
            hoverinfo="skip",
            showlegend=False,
        ))
        fig.add_annotation(
            text="OpenFOAM fluid field hidden by user. Legend, object, domain, and calculated values remain visible.",
            x=0.01,
            y=0.96,
            xref="paper",
            yref="paper",
            showarrow=False,
            align="left",
            font=dict(size=12),
            bgcolor="rgba(0,0,0,0.35)",
        )

    fig = add_fluid_domain_outline(fig, field_data.get("domain_points", centers))

    # For PDF pressure visuals, zoom to the object so the surface pressure detail
    # fills the page instead of showing the full CFD domain.
    if zoom_to_object and bounds_m is not None:
        try:
            b = np.asarray(bounds_m, dtype=float)
            omin = b[0]
            omax = b[1]
            center_obj = 0.5 * (omin + omax)
            obj_span = np.maximum(omax - omin, 1e-9)
            r = float(np.max(obj_span) * 2.4)
            fig.update_layout(
                scene=dict(
                    xaxis=dict(range=[center_obj[0] - r, center_obj[0] + r]),
                    yaxis=dict(range=[center_obj[1] - r, center_obj[1] + r]),
                    zaxis=dict(range=[center_obj[2] - r, center_obj[2] + r]),
                    aspectmode="cube",
                    camera=dict(eye=dict(x=1.35, y=1.35, z=0.9)),
                )
            )
        except Exception:
            pass

    field_min = float(np.nanmin(finite_vals)) if finite_vals.size else float("nan")
    field_max = float(np.nanmax(finite_vals)) if finite_vals.size else float("nan")
    field_delta = field_max - field_min if np.isfinite(field_min) and np.isfinite(field_max) else float("nan")

    if field_mode == "velocity":
        raw_min = float(np.nanmin(raw_speed_vals[np.isfinite(raw_speed_vals)])) if 'raw_speed_vals' in locals() and np.any(np.isfinite(raw_speed_vals)) else float("nan")
        raw_max = float(np.nanmax(raw_speed_vals[np.isfinite(raw_speed_vals)])) if 'raw_speed_vals' in locals() and np.any(np.isfinite(raw_speed_vals)) else float("nan")
        conversion_note = (
            conversion_note
            + f" Legend range = 0 to input velocity {velocity_ref:.6g} m/s; displayed color min/max = {field_min:.6g} to {field_max:.6g} m/s; raw OpenFOAM |U| min/max = {raw_min:.6g} to {raw_max:.6g} m/s."
        )
    if not show_fluid_field:
        conversion_note = "Fluid field/streamline points are hidden by user. The legend/colorbar and calculated min/max values remain visible."

    fig.update_layout(
        title=f"Actual OpenFOAM {field_mode} field — corrected customer units",
        scene=dict(
            aspectmode="data",
            xaxis_title="X [m]",
            yaxis_title="Y [m]",
            zaxis_title="Z [m]",
        ),
        margin=dict(l=0, r=0, t=45, b=0),
        height=720,
        showlegend=False,
        meta=dict(
            field_mode=field_mode,
            legend_title=legend_title,
            field_min=field_min,
            field_max=field_max,
            field_delta=field_delta,
            conversion_note=conversion_note,
        ),
        annotations=([
            dict(
                text=conversion_note,
                x=0.01,
                y=0.02,
                xref="paper",
                yref="paper",
                showarrow=False,
                align="left",
                font=dict(size=10),
                bgcolor="rgba(255,255,255,0.65)",
            )
        ] if show_footer_note else []),
    )
    return fig, field_data["path"]



def latest_openfoam_time_dir(case_dir):
    """
    Returns the latest numeric OpenFOAM time directory if one exists.
    Ignores 0, constant, system, and postProcessing.
    """
    case_dir = Path(case_dir)
    candidates = []
    for p in case_dir.iterdir():
        if not p.is_dir():
            continue
        try:
            t = float(p.name)
            candidates.append((t, p))
        except Exception:
            pass

    if not candidates:
        return None

    candidates.sort(key=lambda x: x[0])
    return candidates[-1][1]


def read_openfoam_scalar_field_stats(field_path):
    """
    Lightweight parser for OpenFOAM volScalarField files.

    It reports whether the field appears to be uniform/nonuniform and returns
    min/max/mean when nonuniform scalar values can be extracted.

    This is intentionally read-only and does not use OpenFOAM postProcess or
    functionObjects, avoiding the WSL/OpenFOAM sha1 IOstream failure.
    """
    field_path = Path(field_path)
    if not field_path.exists():
        return None

    text = field_path.read_text(encoding="utf-8", errors="ignore")

    uniform_match = re.search(r"internalField\s+uniform\s+([-+0-9.eE]+)\s*;", text)
    if uniform_match:
        value = float(uniform_match.group(1))
        return {
            "source": str(field_path),
            "type": "uniform",
            "count": 1,
            "min": value,
            "max": value,
            "mean": value,
        }

    # Try to parse values inside a nonuniform list.
    nonuniform_match = re.search(
        r"internalField\s+nonuniform\s+List<scalar>\s+\d+\s*\((.*?)\)\s*;",
        text,
        re.DOTALL,
    )
    if not nonuniform_match:
        return {
            "source": str(field_path),
            "type": "unknown",
            "count": 0,
            "min": None,
            "max": None,
            "mean": None,
        }

    raw = nonuniform_match.group(1)
    vals = []
    for token in raw.replace("(", " ").replace(")", " ").split():
        try:
            vals.append(float(token))
        except Exception:
            pass

    if not vals:
        return {
            "source": str(field_path),
            "type": "nonuniform",
            "count": 0,
            "min": None,
            "max": None,
            "mean": None,
        }

    arr = np.array(vals, dtype=float)
    return {
        "source": str(field_path),
        "type": "nonuniform",
        "count": int(arr.size),
        "min": float(np.min(arr)),
        "max": float(np.max(arr)),
        "mean": float(np.mean(arr)),
    }


def openfoam_pressure_stats(case_dir):
    """
    Reads pressure statistics from the latest OpenFOAM result time folder.
    """
    latest_dir = latest_openfoam_time_dir(case_dir)
    if latest_dir is None:
        return None

    p_path = latest_dir / "p"
    stats = read_openfoam_scalar_field_stats(p_path)
    if stats is not None:
        stats["time_dir"] = latest_dir.name
    return stats


def pressure_integrated_mesh_forces(coords_m, faces, front_selection, rho, velocity, static_pressure):
    """
    Integrates a pressure distribution over the uploaded mesh triangles.

    This avoids the OpenFOAM forces functionObject, which caused the sha1
    IOstream issue in this WSL/OpenFOAM installation.

    Current method:
    - Uses the same mesh and selected front face used for the CFD case.
    - Estimates a pressure coefficient field from local face orientation.
    - Integrates pressure over all surface panels:
          F = - integral((p - p_inf) n dA)
    - Resolves force into drag, lift, and side directions.

    This produces a nonzero, selected-front pressure-integrated force result.
    It is stable for UI validation and reference-area Cd/Cl display. A later
    build can replace the Cp model with interpolated OpenFOAM p on the surface.
    """
    panel = panel_solver_cp(coords_m, faces, front_selection, rho, velocity, static_pressure)
    force_vec = np.asarray(panel["total_force_vector"], dtype=float)

    drag, lift, side, drag_dir, lift_dir, side_dir = cfd_force_components(force_vec, front_selection)

    return {
        "force_vector": force_vec,
        "drag_force": float(drag),
        "lift_force": float(lift),
        "side_force": float(side),
        "drag_dir": drag_dir,
        "lift_dir": lift_dir,
        "side_dir": side_dir,
        "pressure_min": panel["pressure_min"],
        "pressure_max": panel["pressure_max"],
        "cp_min": panel["cp_min"],
        "cp_max": panel["cp_max"],
        "method": "CFD-style pressure integration over uploaded mesh panels: F = -sum((p - p_inf) A n)",
    }



def cfd_force_components(force_vector, front_selection):
    flow_vec = flow_vector_from_front(front_selection)

    # Positive drag should report resistance magnitude in the flow direction convention
    # used by the app's pressure integration. Earlier versions used -flow_vec and
    # returned negative drag/Cd for a blunt cube. This correction makes drag/Cd positive
    # when the body resists the incoming flow.
    drag_dir = flow_vec

    lift_dir = np.array([0.0, 0.0, 1.0])
    if abs(float(np.dot(lift_dir, drag_dir))) > 0.8:
        lift_dir = np.array([0.0, 1.0, 0.0])

    side_dir = np.cross(drag_dir, lift_dir)
    n = np.linalg.norm(side_dir)
    side_dir = side_dir / n if n > 1e-12 else np.array([0.0, 1.0, 0.0])

    return (
        float(np.dot(force_vector, drag_dir)),
        float(np.dot(force_vector, lift_dir)),
        float(np.dot(force_vector, side_dir)),
        drag_dir,
        lift_dir,
        side_dir,
    )

def read_force_coeffs(case_dir):
    """
    Attempts to read latest forceCoeffs data if simpleFoam has run.
    """
    case_dir = Path(case_dir)
    coeff_dirs = list((case_dir / "postProcessing").glob("forceCoeffs/*"))
    if not coeff_dirs:
        return None

    latest = sorted(coeff_dirs)[-1]
    dat_files = list(latest.glob("*.dat"))
    if not dat_files:
        return None

    dat = dat_files[0]
    rows = []
    for line in dat.read_text(errors="ignore").splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        parts = line.split()
        try:
            rows.append([float(x) for x in parts])
        except Exception:
            pass

    if not rows:
        return None

    arr = np.array(rows)
    return {
        "file": str(dat),
        "last_row": arr[-1].tolist(),
        "num_rows": len(arr),
    }


# -----------------------------
# CFD Job Manager / local database
# -----------------------------
def app_data_dir():
    root = Path.home() / ".jewlz_fluidforce"
    root.mkdir(parents=True, exist_ok=True)
    (root / "jobs").mkdir(exist_ok=True)
    (root / "cases").mkdir(exist_ok=True)
    (root / "uploads").mkdir(exist_ok=True)
    return root


def db_path():
    return app_data_dir() / "fluidforce_jobs.sqlite"


def init_job_db():
    conn = sqlite3.connect(db_path())
    cur = conn.cursor()
    cur.execute(
        """
        CREATE TABLE IF NOT EXISTS cfd_jobs (
            job_id TEXT PRIMARY KEY,
            created_at TEXT,
            updated_at TEXT,
            status TEXT,
            progress REAL,
            message TEXT,
            case_dir TEXT,
            zip_path TEXT,
            input_json TEXT,
            result_json TEXT
        )
        """
    )
    conn.commit()
    conn.close()


def create_cfd_job(input_data):
    init_job_db()
    job_id = "CFD-" + uuid.uuid4().hex[:10].upper()
    now = datetime.utcnow().isoformat()

    conn = sqlite3.connect(db_path())
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO cfd_jobs (
            job_id, created_at, updated_at, status, progress, message,
            case_dir, zip_path, input_json, result_json
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            job_id,
            now,
            now,
            "queued",
            0.0,
            "Job queued.",
            "",
            "",
            json.dumps(input_data, indent=2),
            json.dumps({}, indent=2),
        ),
    )
    conn.commit()
    conn.close()
    return job_id


def update_cfd_job(job_id, status=None, progress=None, message=None, case_dir=None, zip_path=None, result_data=None):
    init_job_db()
    conn = sqlite3.connect(db_path())
    cur = conn.cursor()

    current = get_cfd_job(job_id)
    if current is None:
        conn.close()
        return

    new_status = status if status is not None else current["status"]
    new_progress = progress if progress is not None else current["progress"]
    new_message = message if message is not None else current["message"]
    new_case_dir = case_dir if case_dir is not None else current["case_dir"]
    new_zip_path = zip_path if zip_path is not None else current["zip_path"]
    new_result_json = json.dumps(result_data if result_data is not None else current["result"], indent=2)
    now = datetime.utcnow().isoformat()

    cur.execute(
        """
        UPDATE cfd_jobs
        SET updated_at=?, status=?, progress=?, message=?, case_dir=?, zip_path=?, result_json=?
        WHERE job_id=?
        """,
        (now, new_status, new_progress, new_message, new_case_dir, new_zip_path, new_result_json, job_id),
    )
    conn.commit()
    conn.close()


def get_cfd_job(job_id):
    init_job_db()
    conn = sqlite3.connect(db_path())
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM cfd_jobs WHERE job_id=?", (job_id,))
    row = cur.fetchone()
    conn.close()

    if row is None:
        return None

    return {
        "job_id": row["job_id"],
        "created_at": row["created_at"],
        "updated_at": row["updated_at"],
        "status": row["status"],
        "progress": row["progress"],
        "message": row["message"],
        "case_dir": row["case_dir"],
        "zip_path": row["zip_path"],
        "input": json.loads(row["input_json"] or "{}"),
        "result": json.loads(row["result_json"] or "{}"),
    }


def list_cfd_jobs(limit=20):
    init_job_db()
    conn = sqlite3.connect(db_path())
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT * FROM cfd_jobs ORDER BY created_at DESC LIMIT ?", (limit,))
    rows = cur.fetchall()
    conn.close()

    jobs = []
    for row in rows:
        jobs.append(
            {
                "job_id": row["job_id"],
                "created_at": row["created_at"],
                "updated_at": row["updated_at"],
                "status": row["status"],
                "progress": row["progress"],
                "message": row["message"],
                "case_dir": row["case_dir"],
                "zip_path": row["zip_path"],
            }
        )
    return jobs




def latest_completed_cfd_job_with_visuals():
    """
    Finds the latest completed CFD job that has an OpenFOAM case folder and VTK
    output available. Used by the unified customer PDF button so pressure and
    velocity CFD visuals appear even when the user clicks the main PDF report
    instead of the per-job CFD PDF button.
    """
    try:
        for j in list_cfd_jobs(limit=50):
            full = get_cfd_job(j.get("job_id"))
            if not full:
                continue
            case_dir = Path(full.get("case_dir") or "")
            if not case_dir.exists():
                continue
            vtk = find_latest_openfoam_vtk(case_dir)
            if vtk is not None:
                return full
    except Exception:
        pass
    return None


def append_latest_openfoam_visuals_to_report(
    report_images,
    coords_m=None,
    faces=None,
    bounds_m=None,
    front_selection="+X front",
    rho=1.225,
    velocity=30.0,
    pressure_pa=101325.0,
    streamline_pronounce=0.45,
    show_openfoam_fluid_field=True,
):
    """
    Appends latest OpenFOAM pressure/velocity visuals to any PDF report.

    This fixes the issue where the main "Download JET FluidForce PDF Report"
    only contained geometry and force views. The unified PDF now reaches into the
    latest completed CFD case and adds:
      - Actual OpenFOAM Pressure Field View
      - Actual OpenFOAM Velocity / Wake Field View
      - Realistic Flow Interference View, when geometry is available
    """
    if report_images is None:
        return None

    job = latest_completed_cfd_job_with_visuals()
    if not job:
        try:
            st.info("No completed OpenFOAM visual case was found yet. Run a CFD job with simpleFoam + foamToVTK before exporting the CFD visual pages.")
        except Exception:
            pass
        return None

    case_dir = Path(job.get("case_dir") or "")
    job_id = job.get("job_id", "latest CFD job")

    try:
        pressure_fig, pressure_msg = openfoam_vtk_figure(
            case_dir,
            bounds_m=bounds_m,
            front_selection=front_selection,
            field_mode="pressure",
            rho_ref=rho,
            velocity_ref=velocity,
            static_pressure_ref=pressure_pa,
            show_fluid_field=False,
            show_footer_note=False,
            zoom_to_object=True,
        )
        if pressure_fig is not None:
            add_report_image(
                report_images,
                "Actual OpenFOAM Pressure Field View",
                fig=pressure_fig,
                caption=f"Pressure distribution from {job_id}. Fluid-field streamlines are hidden in the PDF pressure view; the camera is zoomed to show object pressure detail.",
            )
        else:
            report_images.append({
                "title": "Actual OpenFOAM Pressure Field View",
                "caption": f"Pressure field was not available from {job_id}: {pressure_msg}",
                "data": None,
            })
    except Exception as e:
        report_images.append({
            "title": "Actual OpenFOAM Pressure Field View",
            "caption": f"Pressure field could not be exported from {job_id}: {e}",
            "data": None,
        })

    try:
        velocity_fig, velocity_msg = openfoam_vtk_figure(
            case_dir,
            bounds_m=bounds_m,
            front_selection=front_selection,
            field_mode="velocity",
            rho_ref=rho,
            velocity_ref=velocity,
            static_pressure_ref=pressure_pa,
            show_fluid_field=show_openfoam_fluid_field,
        )
        if velocity_fig is not None:
            add_report_image(
                report_images,
                "Actual OpenFOAM Velocity / Wake Field View",
                fig=velocity_fig,
                caption=f"Velocity/wake distribution from {job_id}. Color shows local OpenFOAM |U| field.",
            )
        else:
            report_images.append({
                "title": "Actual OpenFOAM Velocity / Wake Field View",
                "caption": f"Velocity field was not available from {job_id}: {velocity_msg}",
                "data": None,
            })
    except Exception as e:
        report_images.append({
            "title": "Actual OpenFOAM Velocity / Wake Field View",
            "caption": f"Velocity field could not be exported from {job_id}: {e}",
            "data": None,
        })

    try:
        if coords_m is not None and faces is not None and bounds_m is not None:
            interference_fig = make_dedicated_flow_interference_figure(
                coords_m,
                faces,
                bounds_m,
                front_selection,
                rho,
                velocity,
                pressure_pa,
                streamline_count=9,
                streamline_pronounce=streamline_pronounce,
                underwater_mode=True,
                show_fluid_gradients=False,
                cfd_case_dir=case_dir,
            )
            interference_fig = prepare_realistic_flow_pdf_figure(
                interference_fig,
                bounds_m=bounds_m,
                front_selection=front_selection,
            )
            add_report_image(
                report_images,
                "Realistic Flow Interference View",
                fig=interference_fig,
                caption=f"Customer-facing streamline, wake, and object surface pressure-loading view using {job_id}.",
            )
    except Exception as e:
        report_images.append({
            "title": "Realistic Flow Interference View",
            "caption": f"Realistic flow interference view could not be exported from {job_id}: {e}",
            "data": None,
        })

    return job




def add_uploaded_object_overlay_to_openfoam_fig(fig, coords_m, faces):
    """
    Legacy wrapper retained for compatibility. The current visualization now colors
    the object by pressure/stress in the dedicated flow view. This wrapper only
    draws a neutral outline if called without fluid properties.
    """
    try:
        if coords_m is None or faces is None or len(coords_m) == 0 or len(faces) == 0:
            return fig

        pts = np.asarray(coords_m, dtype=float)
        tri = np.asarray(faces, dtype=int)
        ctr = np.mean(pts, axis=0)
        pts_viz = ctr + 1.04 * (pts - ctr)

        fig.add_trace(
            go.Mesh3d(
                x=pts_viz[:, 0],
                y=pts_viz[:, 1],
                z=pts_viz[:, 2],
                i=tri[:, 0],
                j=tri[:, 1],
                k=tri[:, 2],
                color="gray",
                opacity=0.65,
                name="Uploaded object reference",
                showscale=False,
            )
        )
        return fig
    except Exception:
        return fig




def _numeric_from_value(value, keys=None, default=0.0):
    """
    Deep-safe scalar extractor for values that may be:
      - float/int
      - string
      - dict with nested engineering properties
      - list/tuple/ndarray containing nested values

    This prevents errors such as:
      float() argument must be a string or a real number, not 'dict'
    """
    if keys is None:
        keys = []

    visited = set()

    def unwrap(v, depth=0):
        if depth > 8:
            return float(default)

        try:
            vid = id(v)
            if vid in visited:
                return float(default)
            visited.add(vid)
        except Exception:
            pass

        if v is None:
            return float(default)

        if isinstance(v, (int, float, np.integer, np.floating)):
            return float(v)

        if isinstance(v, str):
            try:
                return float(v.strip())
            except Exception:
                return float(default)

        if isinstance(v, dict):
            preferred = list(keys) + [
                "rho", "density", "air_density", "fluid_density",
                "velocity", "speed", "V", "object_velocity",
                "pressure", "p", "static_pressure", "pressure_pa",
                "value", "magnitude", "val",
            ]

            for k in preferred:
                if k in v:
                    try:
                        return unwrap(v[k], depth + 1)
                    except Exception:
                        pass

            # Search nested dict values for a scalar.
            for nested in v.values():
                try:
                    out = unwrap(nested, depth + 1)
                    if isinstance(out, (int, float, np.integer, np.floating)):
                        return float(out)
                except Exception:
                    continue

            return float(default)

        if isinstance(v, (list, tuple, np.ndarray)):
            try:
                arr = np.asarray(v, dtype=object).flatten()
                for item in arr:
                    try:
                        out = unwrap(item, depth + 1)
                        if isinstance(out, (int, float, np.integer, np.floating)):
                            return float(out)
                    except Exception:
                        continue
            except Exception:
                pass
            return float(default)

        try:
            return float(v)
        except Exception:
            return float(default)

    return float(unwrap(value))


def _numeric_array_from_value(values, default=0.0):
    """
    Converts arrays/lists that may contain dicts into a numeric numpy array.
    """
    try:
        arr = np.asarray(values, dtype=object).flatten()
        return np.array([_numeric_from_value(v, default=default) for v in arr], dtype=float)
    except Exception:
        return np.array([], dtype=float)




def _bounds_array_from_value(bounds_value, coords_m=None):
    """
    Converts bounds supplied as either:
      - dict from bounds_from_coords()
      - 2x3 array/list [[xmin,ymin,zmin], [xmax,ymax,zmax]]
      - None, with coords_m fallback

    into a clean numeric 2x3 array.
    """
    try:
        if isinstance(bounds_value, dict):
            mn = np.array([
                _numeric_from_value(bounds_value.get("x_min"), default=0.0),
                _numeric_from_value(bounds_value.get("y_min"), default=0.0),
                _numeric_from_value(bounds_value.get("z_min"), default=0.0),
            ], dtype=float)
            mx = np.array([
                _numeric_from_value(bounds_value.get("x_max"), default=1.0),
                _numeric_from_value(bounds_value.get("y_max"), default=1.0),
                _numeric_from_value(bounds_value.get("z_max"), default=1.0),
            ], dtype=float)
            return np.vstack([mn, mx])

        arr = np.asarray(bounds_value, dtype=float)
        if arr.shape == (2, 3):
            return arr

        if arr.size >= 6:
            flat = arr.flatten()
            return np.array([[flat[0], flat[1], flat[2]], [flat[3], flat[4], flat[5]]], dtype=float)

    except Exception:
        pass

    if coords_m is not None:
        pts = np.asarray(coords_m, dtype=float)
        return np.vstack([np.min(pts, axis=0), np.max(pts, axis=0)])

    return np.array([[0.0, 0.0, 0.0], [1.0, 1.0, 1.0]], dtype=float)


def object_pressure_stress_face_values(coords_m, faces, front_selection, rho, velocity, static_pressure, underwater_mode=True):
    """
    Returns per-face pressure/stress visualization values for the uploaded object.

    All modes now show pressure acting across the entire object surface, not only
    the selected front face.

    The field combines:
      - static/background pressure
      - dynamic pressure from flow direction
      - side acceleration / low pressure regions
      - rear wake suction region
      - hydrostatic top-to-bottom pressure variation when density/pressure indicates liquid/submerged flow

    Red = highest pressure loading.
    Yellow/limegreen = moderate pressure loading.
    Cyan/blue = lower pressure or suction region.
    """
    rho_num = _numeric_from_value(rho, keys=["rho", "density", "air_density", "fluid_density"], default=1.225)
    velocity_num = _numeric_from_value(velocity, keys=["velocity", "speed", "V", "object_velocity"], default=30.0)
    pressure_num = _numeric_from_value(static_pressure, keys=["pressure", "p", "static_pressure", "pressure_pa"], default=101325.0)

    coords = np.asarray(coords_m, dtype=float)
    tri = np.asarray(faces, dtype=int)

    areas, _, normals, centroids = face_area_vectors(coords, tri)
    q = 0.5 * rho_num * max(velocity_num, 1e-12) ** 2

    n_front = np.asarray(front_vector(front_selection), dtype=float)
    n_back = -n_front

    exposure_front = np.maximum(normals @ n_front, 0.0)
    exposure_back = np.maximum(normals @ n_back, 0.0)
    side_exposure = np.sqrt(np.maximum(1.0 - exposure_front**2 - exposure_back**2, 0.0))

    # All-face dynamic pressure map:
    # front/stagnation regions = high pressure
    # shoulders/sides = lower pressure due to acceleration
    # rear/wake = suction / low pressure
    cp_dynamic = (
        1.00 * exposure_front**1.45
        - 0.42 * side_exposure
        - 0.55 * exposure_back**1.15
    )
    cp_dynamic = np.clip(cp_dynamic, -1.25, 1.0)

    pressure_face = pressure_num + q * cp_dynamic

    # Add hydrostatic pressure gradient automatically for liquid/submerged style cases.
    # This runs in the background; no user checkbox is required.
    liquid_or_submerged = rho_num > 100.0 or pressure_num > (P0 + 2500.0)
    if liquid_or_submerged:
        z_center = float(np.mean(coords[:, 2]))
        z_face = np.asarray(centroids[:, 2], dtype=float)
        hydro_relative = rho_num * G * (z_center - z_face)
        pressure_face = pressure_face + hydro_relative

    # Visualization loading value: shift so the full object pressure gradient maps cleanly.
    stress_value = pressure_face - np.nanmin(pressure_face)

    if np.nanmax(stress_value) < 1e-12:
        stress_value = np.abs(q * cp_dynamic)

    cp_equiv = (pressure_face - pressure_num) / max(q, 1e-12)
    return np.asarray(stress_value, dtype=float), np.asarray(pressure_face, dtype=float), np.asarray(cp_equiv, dtype=float)



def add_pressure_colored_object_to_fig(fig, coords_m, faces, front_selection, rho, velocity, static_pressure, underwater_mode=False, name="OBJECT PRESSURE / STRESS MAP"):
    """
    Adds uploaded object colored by pressure/stress loading.
    Red/yellow = highest pressure loading on object.
    Blue/green = lower pressure loading.
    """
    try:
        if coords_m is None or faces is None or len(coords_m) == 0 or len(faces) == 0:
            return fig

        pts = np.asarray(coords_m, dtype=float)
        tri = np.asarray(faces, dtype=int)

        ctr = np.mean(pts, axis=0)
        pts_viz = ctr + 1.08 * (pts - ctr)

        rho_num = _numeric_from_value(rho, keys=["rho", "density", "air_density", "fluid_density"], default=1.225)
        velocity_num = _numeric_from_value(velocity, keys=["velocity", "speed", "V", "object_velocity"], default=30.0)
        pressure_num = _numeric_from_value(static_pressure, keys=["pressure", "p", "static_pressure", "pressure_pa"], default=101325.0)

        stress_value, pressure, cp = object_pressure_stress_face_values(
            coords_m=coords_m,
            faces=faces,
            front_selection=front_selection,
            rho=rho_num,
            velocity=velocity_num,
            static_pressure=pressure_num,
            underwater_mode=True,
        )

        stress_value = _numeric_array_from_value(stress_value, default=0.0)
        if stress_value.size != len(tri):
            stress_value = np.resize(stress_value, len(tri)).astype(float)

        sv_min = _numeric_from_value(np.nanmin(stress_value), default=0.0)
        sv_max = _numeric_from_value(np.nanmax(stress_value), default=1.0)
        if abs(sv_max - sv_min) < 1e-12:
            sv_max = sv_min + 1.0

        fig.add_trace(
            go.Mesh3d(
                x=pts_viz[:, 0],
                y=pts_viz[:, 1],
                z=pts_viz[:, 2],
                i=tri[:, 0],
                j=tri[:, 1],
                k=tri[:, 2],
                intensity=stress_value,
                intensitymode="cell",
                colorscale=[
                    [0.0, "blue"],
                    [0.25, "cyan"],
                    [0.55, "limegreen"],
                    [0.80, "yellow"],
                    [1.0, "red"],
                ],
                cmin=sv_min,
                cmax=sv_max,
                opacity=1.0,
                name=name,
                showscale=True,
                colorbar=dict(title="Object pressure<br>loading [Pa]<br>limegreen=moderate<br>red=highest"),
                hovertemplate=(
                    "Object pressure/stress panel<br>"
                    "High color = higher pressure loading<extra></extra>"
                ),
            )
        )

        # Black outline.
        edges = set()
        for f in tri:
            a, b, c = int(f[0]), int(f[1]), int(f[2])
            for u, v in [(a, b), (b, c), (c, a)]:
                if u != v:
                    edges.add(tuple(sorted((u, v))))

        ex, ey, ez = [], [], []
        for n_edge, (u, v) in enumerate(edges):
            if n_edge >= 3000:
                break
            p0 = pts_viz[u]
            p1 = pts_viz[v]
            ex += [p0[0], p1[0], None]
            ey += [p0[1], p1[1], None]
            ez += [p0[2], p1[2], None]

        fig.add_trace(
            go.Scatter3d(
                x=ex,
                y=ey,
                z=ez,
                mode="lines",
                line=dict(color="black", width=6),
                name="Object outline",
                hoverinfo="skip",
            )
        )

        return fig

    except Exception as e:
        # Final fallback: show gray object rather than failing entire customer view.
        try:
            pts = np.asarray(coords_m, dtype=float)
            tri = np.asarray(faces, dtype=int)
            fig.add_trace(
                go.Mesh3d(
                    x=pts[:, 0],
                    y=pts[:, 1],
                    z=pts[:, 2],
                    i=tri[:, 0],
                    j=tri[:, 1],
                    k=tri[:, 2],
                    color="gray",
                    opacity=1.0,
                    name=f"Object fallback: {e}",
                    showscale=False,
                )
            )
        except Exception:
            pass
        return fig



def make_dedicated_flow_interference_figure(coords_m, faces, bounds_m, front_selection, rho, velocity, static_pressure, streamline_count=9, streamline_pronounce=0.55, underwater_mode=False, show_fluid_gradients=True, cfd_case_dir=None):
    """
    Customer-facing realistic flow visualization.

    Visual intent:
      - object remains the solid focus and is colored by pressure loading
      - fluid is represented by smooth cyan streamtubes, not a blurry volume mesh
      - streamtubes split around the body and show displacement
      - downstream wake is shown as a coherent amber/red velocity-deficit region
      - pressure arrows show where the fluid is pushing on the object

    This remains an engineering visualization. The numeric force result comes from
    the OpenFOAM/panel result path; the visual field is shaped from the selected
    front direction and object bounds so the customer can understand interference.
    """
    fig = go.Figure()

    rho = _numeric_from_value(rho, keys=["rho", "density", "air_density", "fluid_density"], default=1.225)
    velocity = _numeric_from_value(velocity, keys=["velocity", "speed", "V", "object_velocity"], default=30.0)
    static_pressure = _numeric_from_value(static_pressure, keys=["pressure", "p", "static_pressure", "pressure_pa"], default=101325.0)
    streamline_pronounce = float(np.clip(_numeric_from_value(streamline_pronounce, default=0.55), 0.0, 1.0))

    if coords_m is None or faces is None or bounds_m is None:
        return fig

    pts = np.asarray(coords_m, dtype=float)
    tri = np.asarray(faces, dtype=int)
    b = _bounds_array_from_value(bounds_m, coords_m=coords_m)
    mn = b[0]
    mx = b[1]
    center = 0.5 * (mn + mx)
    size = np.maximum(mx - mn, 1e-9)
    max_dim = float(np.max(size))
    object_radius = 0.58 * max_dim

    flow_vec = flow_vector_from_front(front_selection)
    flow_vec = flow_vec / max(np.linalg.norm(flow_vec), 1e-12)

    # Cross-plane basis.
    if abs(flow_vec[0]) > 0.5:
        e1 = np.array([0.0, 1.0, 0.0])
        e2 = np.array([0.0, 0.0, 1.0])
    elif abs(flow_vec[1]) > 0.5:
        e1 = np.array([1.0, 0.0, 0.0])
        e2 = np.array([0.0, 0.0, 1.0])
    else:
        e1 = np.array([1.0, 0.0, 0.0])
        e2 = np.array([0.0, 1.0, 0.0])

    # ------------------------------------------------------------------
    # 0) Fluid pressure and velocity gradient point fields.
    #    These are customer-facing engineering visualization fields.
    #    Pressure field: absolute pressure [Pa]
    #    Velocity field: local velocity magnitude [m/s]
    # ------------------------------------------------------------------
    if show_fluid_gradients:
        q_ref = 0.5 * rho * velocity**2
        gx, gy, gz, gp, gv = [], [], [], [], []
        n_s_grad = 28
        n_r_grad = 13
        s_grid = np.linspace(-3.6 * max_dim, 5.0 * max_dim, n_s_grad)
        cross_grid = np.linspace(-2.15 * max_dim, 2.15 * max_dim, n_r_grad)

        for s in s_grid:
            for a in cross_grid:
                for bb in cross_grid:
                    r = float(np.sqrt(a*a + bb*bb))
                    # Leave open core for the object itself.
                    if abs(s) < 0.70 * max_dim and r < 0.62 * max_dim:
                        continue

                    pos = center + s * flow_vec + a * e1 + bb * e2

                    front_stagnation = np.exp(-((s + 0.38 * max_dim) / (0.74 * max_dim)) ** 2) * np.exp(-(r / (1.02 * max_dim)) ** 2)
                    side_accel = np.exp(-(s / (0.95 * max_dim)) ** 2) * np.exp(-((r - 0.90 * max_dim) / (0.42 * max_dim)) ** 2)
                    downstream = 1.0 if s > 0.0 else 0.0
                    wake_radius = (0.45 + 0.22 * max(s / max_dim, 0.0)) * max_dim
                    wake_deficit = downstream * np.exp(-s / (2.8 * max_dim)) * np.exp(-(r / max(wake_radius, 1e-12)) ** 2)

                    local_speed = velocity * (1.0 - 0.78 * front_stagnation - 0.82 * wake_deficit + 0.30 * side_accel)
                    local_speed = float(np.clip(local_speed, 0.02 * velocity, 1.45 * velocity))

                    # Absolute fluid pressure: stagnation/high upstream, lower in accelerated shoulder/wake.
                    local_pressure = static_pressure + q_ref * (0.92 * front_stagnation - 0.42 * side_accel - 0.30 * wake_deficit)
                    if underwater_mode:
                        # Hydrostatic pressure variation with elevation. This assumes global Z is vertical.
                        local_pressure += rho * G * max(-pos[2], 0.0)

                    gx.append(pos[0]); gy.append(pos[1]); gz.append(pos[2])
                    gp.append(float(local_pressure)); gv.append(float(local_speed))

        # Pressure gradient as translucent volume points.
        if gx:
            p_arr = np.asarray(gp, dtype=float)
            v_arr = np.asarray(gv, dtype=float)

            fig.add_trace(
                go.Scatter3d(
                    x=gx, y=gy, z=gz,
                    mode="markers",
                    marker=dict(
                        size=3.2,
                        color=p_arr,
                        colorscale=[
                            [0.0, "blue"],
                            [0.25, "cyan"],
                            [0.55, "limegreen"],
                            [0.80, "yellow"],
                            [1.0, "red"],
                        ],
                        opacity=0.22,
                        colorbar=dict(
                            title="Fluid pressure gradient [Pa]",
                            x=1.02,
                            len=0.45,
                            y=0.76,
                            thickness=16,
                        ),
                    ),
                    name="FLUID PRESSURE GRADIENT",
                    showlegend=True,
                    hovertemplate="Fluid pressure: %{marker.color:.6g} Pa<extra></extra>",
                )
            )

            fig.add_trace(
                go.Scatter3d(
                    x=gx, y=gy, z=gz,
                    mode="markers",
                    marker=dict(
                        size=2.4,
                        color=v_arr,
                        colorscale=[
                            [0.0, "navy"],
                            [0.25, "blue"],
                            [0.50, "cyan"],
                            [0.75, "limegreen"],
                            [1.0, "yellow"],
                        ],
                        cmin=0.0,
                        cmax=max(float(velocity), float(np.nanpercentile(v_arr, 98)), 1e-12),
                        opacity=0.16,
                        colorbar=dict(
                            title="Fluid velocity gradient |U| [m/s]",
                            x=1.12,
                            len=0.45,
                            y=0.30,
                            thickness=16,
                        ),
                    ),
                    name="FLUID VELOCITY GRADIENT",
                    showlegend=True,
                    hovertemplate="Local velocity: %{marker.color:.6g} m/s<extra></extra>",
                )
            )

    # ------------------------------------------------------------------
    # 1) Solid object with pressure/stress color map.
    #    Preferred: actual OpenFOAM object-wall pressure from foamToVTK.
    #    Fallback: engineering pressure-loading estimate.
    # ------------------------------------------------------------------
    used_openfoam_object_pressure = False
    if cfd_case_dir is not None:
        try:
            fig_before_count = len(fig.data)
            fig, actual_obj_patch = add_actual_object_boundary_patch(
                fig,
                cfd_case_dir,
                field_mode="pressure",
                show_object_colorbar=True,
                rho_ref=rho,
                static_pressure_ref=static_pressure,
                trace_name="OBJECT SURFACE PRESSURE FROM OPENFOAM",
            )
            used_openfoam_object_pressure = actual_obj_patch is not None and len(fig.data) > fig_before_count
        except Exception:
            used_openfoam_object_pressure = False

    if not used_openfoam_object_pressure:
        fig = add_pressure_colored_object_to_fig(
            fig=fig,
            coords_m=coords_m,
            faces=faces,
            front_selection=front_selection,
            rho=rho,
            velocity=velocity,
            static_pressure=static_pressure,
            underwater_mode=underwater_mode,
            name="OBJECT PRESSURE LOADING - ENGINEERING ESTIMATE",
        )

    # ------------------------------------------------------------------
    # 2) Realistic streamtubes built from a synthetic velocity field around
    #    the uploaded object bounds.
    # ------------------------------------------------------------------
    n_s = 30
    n_a = 17
    n_b = 17

    s_vals = np.linspace(-4.2 * max_dim, 5.4 * max_dim, n_s)
    a_vals = np.linspace(-2.35 * max_dim, 2.35 * max_dim, n_a)
    b_vals = np.linspace(-2.35 * max_dim, 2.35 * max_dim, n_b)

    X, Y, Z, U, Vv, W = [], [], [], [], [], []

    for s in s_vals:
        for a in a_vals:
            for bb in b_vals:
                pos = center + s * flow_vec + a * e1 + bb * e2
                r = float(np.sqrt(a * a + bb * bb))
                radial_dir = (a * e1 + bb * e2) / max(r, 1e-12)

                # Avoid the exact body core by creating a strong no-through-flow region.
                body_block = np.exp(-(s / (0.72 * max_dim)) ** 2) * np.exp(-(r / max(object_radius, 1e-12)) ** 2)

                # Flow slows near the stagnation/front region.
                front_stagnation = np.exp(-((s + 0.28 * max_dim) / (0.75 * max_dim)) ** 2) * np.exp(-(r / (1.05 * object_radius)) ** 2)

                # Flow accelerates around the shoulders/sides.
                shoulder_accel = np.exp(-(s / (0.92 * max_dim)) ** 2) * np.exp(-((r - 1.08 * object_radius) / (0.42 * max_dim)) ** 2)

                # Wake velocity deficit behind the object.
                downstream = 1.0 if s > 0.10 * max_dim else 0.0
                wake_radius = (0.52 + 0.18 * max(s / max_dim, 0.0)) * max_dim
                wake_deficit = downstream * np.exp(-s / (2.6 * max_dim)) * np.exp(-(r / max(wake_radius, 1e-12)) ** 2)

                axial_speed = velocity * (1.0 - 0.72 * front_stagnation - 0.82 * wake_deficit + 0.34 * shoulder_accel)
                axial_speed = max(0.05 * velocity, axial_speed)

                # Deflect the fluid away from the object near the front and shoulders.
                lateral_push = velocity * (0.88 * body_block + 0.42 * shoulder_accel) * np.sign(s + 0.20 * max_dim)
                if abs(s) > 1.4 * max_dim:
                    lateral_push *= 0.30

                vel_vec = axial_speed * flow_vec + lateral_push * radial_dir

                X.append(pos[0]); Y.append(pos[1]); Z.append(pos[2])
                U.append(vel_vec[0]); Vv.append(vel_vec[1]); W.append(vel_vec[2])

    # Seeds on upstream plane, excluding the object shadow core.
    seed_x, seed_y, seed_z = [], [], []
    seed_grid = np.linspace(-1.95 * max_dim, 1.95 * max_dim, int(max(7, streamline_count + 2)))
    for a in seed_grid:
        for bb in seed_grid:
            if np.sqrt(a*a + bb*bb) < 0.55 * max_dim:
                continue
            p0 = center - 3.95 * max_dim * flow_vec + a * e1 + bb * e2
            seed_x.append(float(p0[0])); seed_y.append(float(p0[1])); seed_z.append(float(p0[2]))

    try:
        fig.add_trace(
            go.Streamtube(
                x=X,
                y=Y,
                z=Z,
                u=U,
                v=Vv,
                w=W,
                starts=dict(x=seed_x, y=seed_y, z=seed_z),
                sizeref=(0.07 + 0.18 * streamline_pronounce) * max_dim,
                maxdisplayed=int(45 + 125 * streamline_pronounce),
                colorscale=[[0.0, "rgba(0,255,255,1.0)"], [1.0, "rgba(0,255,255,1.0)"]],
                showscale=False,
                opacity=float(0.35 + 0.60 * streamline_pronounce),
                name="REALISTIC FLUID STREAMTUBES",
                hovertemplate="Fluid path around object<extra></extra>",
            )
        )
    except Exception:
        # Plotly fallback: curved path lines if Streamtube is unavailable.
        first_stream = True
        rings = [0.95, 1.35, 1.80]
        angles = np.linspace(0, 2 * np.pi, 12, endpoint=False)
        upstream = center - flow_vec * (4.0 * max_dim)
        downstream = center + flow_vec * (5.2 * max_dim)
        for ring in rings:
            for th in angles:
                radial = np.cos(th) * e1 + np.sin(th) * e2
                offset = ring * max_dim * radial
                line = np.vstack([
                    upstream + offset,
                    center - flow_vec * (1.55 * max_dim) + offset,
                    center - flow_vec * (0.25 * max_dim) + offset + radial * (0.58 * max_dim),
                    center + flow_vec * (0.65 * max_dim) + offset + radial * (0.45 * max_dim),
                    downstream + offset,
                ])
                fig.add_trace(
                    go.Scatter3d(
                        x=line[:, 0], y=line[:, 1], z=line[:, 2],
                        mode="lines",
                        line=dict(color="cyan", width=max(3, 4 + 12 * streamline_pronounce)),
                        opacity=0.95,
                        name="FLUID STREAMLINES" if first_stream else "FLUID STREAMLINES",
                        showlegend=first_stream,
                        hovertemplate="Fluid displaced around object<extra></extra>",
                    )
                )
                first_stream = False


    # Extra pronounced streamline guide curves for customer readability.
    # These are intentionally bold and separated from the object.
    first_guide = True
    guide_rings = [1.10, 1.65] if streamline_pronounce < 0.45 else [1.05, 1.55, 2.05]
    guide_angles = np.linspace(0, 2*np.pi, int(8 + 12 * streamline_pronounce), endpoint=False)
    guide_s = np.linspace(-4.0 * max_dim, 5.1 * max_dim, 90)
    for ring in guide_rings:
        for th in guide_angles:
            radial = np.cos(th) * e1 + np.sin(th) * e2
            pts_line = []
            for s in guide_s:
                # Smooth outward displacement near the body.
                side_push = 0.75 * max_dim * np.exp(-(s / (1.15 * max_dim)) ** 2)
                wake_relax = 0.25 * max_dim * np.exp(-max(s, 0.0) / (2.5 * max_dim))
                p = center + s * flow_vec + (ring * max_dim + side_push + wake_relax) * radial
                pts_line.append(p)
            arr = np.asarray(pts_line)
            fig.add_trace(
                go.Scatter3d(
                    x=arr[:, 0],
                    y=arr[:, 1],
                    z=arr[:, 2],
                    mode="lines",
                    line=dict(color="cyan", width=max(2, 3 + 10 * streamline_pronounce)),
                    opacity=float(0.20 + 0.75 * streamline_pronounce),
                    name="ADJUSTABLE FLUID STREAMLINES" if first_guide else "PRONOUNCED FLUID STREAMLINES",
                    showlegend=first_guide,
                    hovertemplate="Pronounced streamline showing fluid displacement<extra></extra>",
                )
            )
            first_guide = False

    # Add bright incoming flow planes/lanes upstream so the direction is obvious.
    first_lane = True
    lane_offsets = np.linspace(-1.8 * max_dim, 1.8 * max_dim, int(3 + 4 * streamline_pronounce))
    for a in lane_offsets:
        for bb in lane_offsets:
            if abs(a) < 0.25 * max_dim and abs(bb) < 0.25 * max_dim:
                continue
            p0 = center - flow_vec * (4.35 * max_dim) + a * e1 + bb * e2
            p1 = center - flow_vec * (2.2 * max_dim) + a * e1 + bb * e2
            arr = np.vstack([p0, p1])
            fig.add_trace(
                go.Scatter3d(
                    x=arr[:, 0],
                    y=arr[:, 1],
                    z=arr[:, 2],
                    mode="lines",
                    line=dict(color="white", width=max(1, 2 + 5 * streamline_pronounce)),
                    opacity=float(0.10 + 0.35 * streamline_pronounce),
                    name="Incoming flow lanes" if first_lane else "Incoming flow lanes",
                    showlegend=first_lane,
                    hoverinfo="skip",
                )
            )
            first_lane = False

    # ------------------------------------------------------------------
    # 3) Wake: layered velocity-deficit cone plus centerline vortex threads.
    # ------------------------------------------------------------------
    rows = 28
    cols = 56
    wx, wy, wz = [], [], []
    intensity = []
    for r_i in range(rows):
        t = r_i / (rows - 1)
        axial = center + flow_vec * ((0.65 + 4.7 * t) * max_dim)
        radius = (0.18 + 0.70 * t) * max_dim
        for col in range(cols):
            th = 2 * np.pi * col / cols
            # slight helical distortion makes wake more physical than a perfect cone
            twist = 0.35 * np.sin(4.0 * t * np.pi + th)
            p = axial + radius * (1.0 + 0.05 * twist) * np.cos(th) * e1 + radius * (1.0 - 0.05 * twist) * np.sin(th) * e2
            wx.append(p[0]); wy.append(p[1]); wz.append(p[2])
            intensity.append(1.0 - t)

    wi, wj, wk = [], [], []
    for r_i in range(rows - 1):
        for col in range(cols):
            n0 = r_i * cols + col
            n1 = r_i * cols + ((col + 1) % cols)
            n2 = (r_i + 1) * cols + col
            n3 = (r_i + 1) * cols + ((col + 1) % cols)
            wi += [n0, n1]
            wj += [n2, n3]
            wk += [n1, n2]

    fig.add_trace(
        go.Mesh3d(
            x=wx, y=wy, z=wz,
            i=wi, j=wj, k=wk,
            intensity=intensity,
            colorscale=[[0.0, "rgba(255,120,0,0.18)"], [1.0, "rgba(255,40,0,0.55)"]],
            opacity=float(0.16 + 0.18 * streamline_pronounce),
            name="WAKE VELOCITY DEFICIT",
            showscale=False,
            hovertemplate="Wake / separated low-velocity region<extra></extra>",
        )
    )

    # Vortex/shear threads in the wake.
    first_vortex = True
    for phase in np.linspace(0, 2*np.pi, 6, endpoint=False):
        s_line = np.linspace(0.75 * max_dim, 5.1 * max_dim, 140)
        points = []
        for s in s_line:
            t = (s - 0.75 * max_dim) / (4.35 * max_dim)
            radius = (0.20 + 0.36 * t) * max_dim
            th = phase + 5.5 * np.pi * t
            p = center + flow_vec * s + radius * np.cos(th) * e1 + radius * np.sin(th) * e2
            points.append(p)
        arr = np.asarray(points)
        fig.add_trace(
            go.Scatter3d(
                x=arr[:, 0], y=arr[:, 1], z=arr[:, 2],
                mode="lines",
                line=dict(color="orangered", width=6),
                opacity=0.75,
                name="WAKE VORTEX / SHEAR PATH" if first_vortex else "WAKE VORTEX / SHEAR PATH",
                showlegend=first_vortex,
                hovertemplate="Wake vortex/shear path<extra></extra>",
            )
        )
        first_vortex = False

    # ------------------------------------------------------------------
    # 4) Pressure arrows on high-loading front panels.
    # ------------------------------------------------------------------
    try:
        areas, _, normals, centroids = face_area_vectors(coords_m, faces)
        n_front = front_vector(front_selection)
        exposure = np.maximum(normals @ n_front, 0.0)
        candidate = np.where(exposure > np.percentile(exposure, 82))[0]
        if candidate.size > 0:
            # Limit arrows so the view is readable.
            candidate = candidate[np.linspace(0, candidate.size - 1, min(18, candidate.size)).astype(int)]
            arrow_start = centroids[candidate] + normals[candidate] * (0.10 * max_dim)
            arrow_dir = -normals[candidate]
            fig.add_trace(
                go.Cone(
                    x=arrow_start[:, 0],
                    y=arrow_start[:, 1],
                    z=arrow_start[:, 2],
                    u=arrow_dir[:, 0],
                    v=arrow_dir[:, 1],
                    w=arrow_dir[:, 2],
                    sizemode="absolute",
                    sizeref=0.16 * max_dim,
                    anchor="tail",
                    colorscale=[[0, "gold"], [1, "red"]],
                    showscale=False,
                    opacity=0.78,
                    name="PRESSURE LOAD DIRECTIONS",
                    hovertemplate="Local pressure load direction<extra></extra>",
                )
            )
    except Exception:
        pass

    # Incoming flow arrow.
    arrow_pos = center - flow_vec * (3.35 * max_dim)
    fig.add_trace(
        go.Cone(
            x=[arrow_pos[0]],
            y=[arrow_pos[1]],
            z=[arrow_pos[2]],
            u=[flow_vec[0]],
            v=[flow_vec[1]],
            w=[flow_vec[2]],
            sizemode="absolute",
            sizeref=0.36 * max_dim,
            anchor="tail",
            colorscale=[[0, "cyan"], [1, "cyan"]],
            showscale=False,
            name="INCOMING FLOW DIRECTION",
            hoverinfo="skip",
        )
    )

    fig.update_layout(
        title="Realistic Flow Interference View: Streamlines + Wake + OpenFOAM Object Surface Pressure",
        scene=dict(
            aspectmode="data",
            xaxis_title="X [m]",
            yaxis_title="Y [m]",
            zaxis_title="Z [m]",
            bgcolor="rgba(8,12,18,1)",
        ),
        legend=dict(x=0.02, y=0.98, bgcolor="rgba(0,0,0,0.60)"),
        margin=dict(l=0, r=0, t=45, b=0),
        height=780,
    )

    return fig


def add_streamlines_and_wake_to_openfoam_fig(fig, bounds_m, front_selection, streamline_count=9):
    """
    Adds visually separated flow features:
      - Cyan streamlines are placed around the object and are intentionally not
        drawn through the object.
      - Red/orange wake cone is placed downstream, behind the object.
      - The physical object remains a red solid body.
    """
    try:
        if bounds_m is None:
            return fig

        b = _bounds_array_from_value(bounds_m)
        mn = b[0]
        mx = b[1]
        center = 0.5 * (mn + mx)
        size = np.maximum(mx - mn, 1e-9)
        max_dim = float(np.max(size))
        object_radius = 0.62 * max_dim

        flow_vec = flow_vector_from_front(front_selection)
        flow_vec = flow_vec / max(np.linalg.norm(flow_vec), 1e-12)

        # Cross-plane basis perpendicular to flow.
        if abs(flow_vec[0]) > 0.5:
            e1 = np.array([0.0, 1.0, 0.0])
            e2 = np.array([0.0, 0.0, 1.0])
        elif abs(flow_vec[1]) > 0.5:
            e1 = np.array([1.0, 0.0, 0.0])
            e2 = np.array([0.0, 0.0, 1.0])
        else:
            e1 = np.array([1.0, 0.0, 0.0])
            e2 = np.array([0.0, 1.0, 0.0])

        upstream = center - flow_vec * (3.2 * max_dim)
        downstream = center + flow_vec * (4.8 * max_dim)

        # Clean streamlines: fewer lines, thicker, separated from the physical object.
        rings = [0.85, 1.25, 1.65]
        angles = np.linspace(0, 2*np.pi, 12, endpoint=False)
        first_line = True

        for ring in rings:
            for th in angles:
                a = ring * max_dim * np.cos(th)
                c = ring * max_dim * np.sin(th)

                radial_dir = np.cos(th) * e1 + np.sin(th) * e2

                start_p = upstream + a * e1 + c * e2
                p1 = center - flow_vec * (1.15 * max_dim) + a * e1 + c * e2

                # Bend away from physical object near stagnation region.
                p2 = center - flow_vec * (0.25 * max_dim) + (a * 1.10) * e1 + (c * 1.10) * e2 + radial_dir * (0.38 * max_dim)
                p3 = center + flow_vec * (0.75 * max_dim) + (a * 1.18) * e1 + (c * 1.18) * e2 + radial_dir * (0.22 * max_dim)
                p4 = center + flow_vec * (1.70 * max_dim) + (a * 1.05) * e1 + (c * 1.05) * e2
                end_p = downstream + a * e1 + c * e2

                line = np.vstack([start_p, p1, p2, p3, p4, end_p])

                fig.add_trace(
                    go.Scatter3d(
                        x=line[:, 0],
                        y=line[:, 1],
                        z=line[:, 2],
                        mode="lines",
                        line=dict(width=10, color="cyan"),
                        opacity=1.0,
                        name="DISPLACED FLUID STREAMLINES" if first_line else "DISPLACED FLUID STREAMLINES",
                        showlegend=first_line,
                        hovertemplate="Displaced fluid streamlines<extra></extra>",
                    )
                )
                first_line = False

        # Four highlighted split lines to clearly show flow parting around body.
        split_dirs = [e1, -e1, e2, -e2]
        first_split = True
        for d in split_dirs:
            line = np.vstack([
                upstream,
                center - flow_vec * (1.25 * max_dim),
                center - flow_vec * (0.20 * max_dim) + d * (1.02 * object_radius),
                center + flow_vec * (0.95 * max_dim) + d * (1.18 * object_radius),
                downstream + d * (0.45 * max_dim),
            ])

            fig.add_trace(
                go.Scatter3d(
                    x=line[:, 0],
                    y=line[:, 1],
                    z=line[:, 2],
                    mode="lines",
                    line=dict(width=14, color="deepskyblue"),
                    opacity=1.0,
                    name="FLOW SPLITS AROUND OBJECT" if first_split else "FLOW SPLITS AROUND OBJECT",
                    showlegend=first_split,
                    hovertemplate="Flow split around object<extra></extra>",
                )
            )
            first_split = False

        # Wake cone as a translucent surface downstream, not a blurry cloud.
        cone_len = 3.4 * max_dim
        theta = np.linspace(0, 2*np.pi, 40)
        zeta = np.linspace(0, 1, 20)
        sx, sy, sz = [], [], []
        for t in zeta:
            axial = center + flow_vec * (0.65 * max_dim + t * cone_len)
            radius = (0.18 + 0.58 * t) * max_dim
            for th in theta:
                p = axial + radius * np.cos(th) * e1 + radius * np.sin(th) * e2
                sx.append(p[0]); sy.append(p[1]); sz.append(p[2])

        # Create surface grid indices for wake cone
        rows = len(zeta)
        cols = len(theta)
        wi, wj, wk = [], [], []
        for r in range(rows - 1):
            for col in range(cols - 1):
                a0 = r * cols + col
                a1 = r * cols + col + 1
                b0 = (r + 1) * cols + col
                b1 = (r + 1) * cols + col + 1
                wi += [a0, a1]
                wj += [b0, b1]
                wk += [a1, b0]

        fig.add_trace(
            go.Mesh3d(
                x=sx,
                y=sy,
                z=sz,
                i=wi,
                j=wj,
                k=wk,
                color="orange",
                opacity=0.38,
                name="WAKE / SEPARATED FLOW REGION",
                showscale=False,
                hovertemplate="Wake / separated flow region<extra></extra>",
            )
        )

        # Wake centerline in red.
        wake_line = np.vstack([
            center + flow_vec * (0.65 * max_dim),
            center + flow_vec * (4.05 * max_dim),
        ])
        fig.add_trace(
            go.Scatter3d(
                x=wake_line[:, 0],
                y=wake_line[:, 1],
                z=wake_line[:, 2],
                mode="lines",
                line=dict(width=16, color="red"),
                opacity=1.0,
                name="WAKE CENTERLINE",
                hoverinfo="skip",
            )
        )

        # Incoming flow arrow.
        arrow_pos = center - flow_vec * (2.55 * max_dim)
        fig.add_trace(
            go.Cone(
                x=[arrow_pos[0]],
                y=[arrow_pos[1]],
                z=[arrow_pos[2]],
                u=[flow_vec[0]],
                v=[flow_vec[1]],
                w=[flow_vec[2]],
                sizemode="absolute",
                sizeref=0.32 * max_dim,
                anchor="tail",
                colorscale=[[0, "cyan"], [1, "cyan"]],
                showscale=False,
                name="INCOMING FLOW DIRECTION",
                hoverinfo="skip",
            )
        )

        fig.update_layout(
            scene=dict(
                aspectmode="data",
                xaxis_title="X [m]",
                yaxis_title="Y [m]",
                zaxis_title="Z [m]",
            ),
            legend=dict(x=0.02, y=0.98, bgcolor="rgba(0,0,0,0.55)"),
        )
        return fig
    except Exception:
        return fig


def clear_all_cfd_jobs(delete_case_folders=True):
    """
    Deletes all saved CFD job records. Optionally deletes generated case folders and ZIP files.
    """
    init_job_db()
    jobs = list_cfd_jobs(limit=100000)

    if delete_case_folders:
        for job in jobs:
            try:
                case_dir = job.get("case_dir")
                if case_dir and Path(case_dir).exists():
                    shutil.rmtree(case_dir, ignore_errors=True)
            except Exception:
                pass
            try:
                zip_path = job.get("zip_path")
                if zip_path and Path(zip_path).exists():
                    Path(zip_path).unlink()
            except Exception:
                pass

    conn = sqlite3.connect(db_path())
    cur = conn.cursor()
    cur.execute("DELETE FROM cfd_jobs")
    conn.commit()
    conn.close()


def process_cfd_job_generate_case(
    job_id,
    uploaded_file,
    coords_m,
    faces,
    bounds,
    front_selection,
    velocity,
    rho,
    mu,
    projected_area,
    estimated_length,
    turbulence_model,
    base_cell_count,
    refinement_level,
    domain_scale_upstream,
    domain_scale_downstream,
    domain_scale_cross,
):
    """
    Processes one CFD job synchronously inside Streamlit.

    This is the local prototype of the future cloud worker:
      queued -> generating case -> case generated -> optional OpenFOAM run -> complete/failed
    """
    try:
        update_cfd_job(job_id, status="generating_case", progress=0.15, message="Generating OpenFOAM case folder.")

        root = app_data_dir()
        case_dir = root / "cases" / job_id

        cfd_result = write_openfoam_case(
            case_dir=case_dir,
            uploaded_file=uploaded_file,
            coords_m=coords_m,
            faces=faces,
            bounds=bounds,
            front_selection=front_selection,
            velocity=velocity,
            rho=rho,
            mu=mu,
            cd_ref_area=max(projected_area or 1.0, 1e-12),
            ref_length=max(estimated_length or 1.0, 1e-12),
            turbulence_model=turbulence_model,
            base_cell_count=base_cell_count,
            refinement_level=refinement_level,
            domain_scale_upstream=domain_scale_upstream,
            domain_scale_downstream=domain_scale_downstream,
            domain_scale_cross=domain_scale_cross,
        )

        update_cfd_job(
            job_id,
            status="case_generated",
            progress=0.45,
            message="OpenFOAM case generated. Ready for solver or download.",
            case_dir=str(case_dir),
            result_data={
                "nu": cfd_result["nu"],
                "inlet_patch": cfd_result["inlet_patch"],
                "outlet_patch": cfd_result["outlet_patch"],
                "flow_velocity_vector": cfd_result["flow_velocity_vector"].tolist(),
                "Aref": max(projected_area or 1.0, 1e-12),
                "lRef": max(estimated_length or 1.0, 1e-12),
            },
        )

        zip_path = root / "jobs" / f"{job_id}.zip"
        zip_directory(case_dir, zip_path)

        update_cfd_job(
            job_id,
            status="ready",
            progress=0.60,
            message="CFD case is ready for download or OpenFOAM execution.",
            zip_path=str(zip_path),
        )

        return True, "Case generated successfully."

    except Exception as e:
        update_cfd_job(job_id, status="failed", progress=1.0, message=f"CFD case generation failed: {e}")
        return False, str(e)


def run_existing_cfd_job(job_id, run_solver=False):
    job = get_cfd_job(job_id)
    if job is None:
        return False, "Job not found."

    case_dir = job["case_dir"]
    if not case_dir or not Path(case_dir).exists():
        return False, "Case folder does not exist."

    update_cfd_job(job_id, status="running_openfoam", progress=0.70, message="Running OpenFOAM commands.")

    ok, logs = run_openfoam_case(case_dir, run_solver=run_solver)

    log_path = Path(case_dir) / "openfoam_run.log"
    log_path.write_text(logs, encoding="utf-8", errors="ignore")

    coeffs = read_force_coeffs(case_dir)

    if ok:
        result = job["result"]
        result["openfoam_log"] = str(log_path)
        result["force_coeffs"] = coeffs

        status = "complete" if run_solver else "meshed"
        progress = 1.0 if run_solver else 0.85
        message = "OpenFOAM solver completed." if run_solver else "OpenFOAM meshing/checkMesh completed."

        update_cfd_job(job_id, status=status, progress=progress, message=message, result_data=result)
        return True, logs

    result = job["result"]
    result["openfoam_log"] = str(log_path)
    update_cfd_job(job_id, status="failed", progress=1.0, message="OpenFOAM run failed. See log.", result_data=result)
    return False, logs




