def ensure_pdf_visual_exporter():
    """
    Ensures Plotly static image export is available for PDF visuals.

    The PDF requires real PNG bytes from Plotly/Kaleido. Without this, ReportLab
    can only place a placeholder message. This helper attempts to install the
    stable Kaleido exporter in the active Streamlit Python environment.
    """
    if not globals().get("AUTO_INSTALL_PDF_EXPORTER", True):
        return False, "Automatic PDF visual exporter setup is disabled."

    try:
        import kaleido  # noqa: F401
        return True, "Kaleido is installed."
    except Exception:
        pass

    install_attempts = [
        [sys.executable, "-m", "pip", "install", "-U", "kaleido==0.2.1"],
        [sys.executable, "-m", "pip", "install", "-U", "kaleido"],
    ]

    last_error = ""
    for cmd in install_attempts:
        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=240,
            )
            if result.returncode == 0:
                try:
                    import kaleido  # noqa: F401
                    return True, "Kaleido was installed successfully."
                except Exception as import_error:
                    last_error = str(import_error)
            else:
                last_error = (result.stderr or result.stdout or "").strip()
        except Exception as install_error:
            last_error = str(install_error)

    return False, f"Kaleido installation was not completed: {last_error}"





def _candidate_browsers_for_screenshot():
    """
    Browser candidates for exact Plotly HTML screenshot export.
    Works on Windows, Linux, and Streamlit Cloud-style environments when a
    Chromium browser is available.
    """
    names = [
        "msedge", "microsoft-edge", "chrome", "google-chrome",
        "chromium", "chromium-browser",
    ]
    candidates = []
    for name in names:
        found = shutil.which(name)
        if found:
            candidates.append(found)

    # Common Windows paths when PowerShell PATH does not include Edge/Chrome.
    win_paths = [
        r"C:\Program Files\Microsoft\Edge\Application\msedge.exe",
        r"C:\Program Files (x86)\Microsoft\Edge\Application\msedge.exe",
        r"C:\Program Files\Google\Chrome\Application\chrome.exe",
        r"C:\Program Files (x86)\Google\Chrome\Application\chrome.exe",
    ]
    for p in win_paths:
        try:
            if os.path.exists(p):
                candidates.append(p)
        except Exception:
            pass

    # Deduplicate while preserving order.
    deduped = []
    for c in candidates:
        if c not in deduped:
            deduped.append(c)
    return deduped


def plotly_fig_to_png_bytes(fig, width=1700, height=1150, scale=2.0):
    """
    Converts a Plotly figure to PNG bytes for PDF insertion.

    Export order:
      1. Plotly/Kaleido exact export.
      2. Headless browser screenshot of the exact Plotly HTML view.
      3. Matplotlib fallback so the PDF is never blank.

    The browser route is the key fix for local Windows systems where Kaleido
    installation fails or requires a restart.
    """
    if fig is None:
        return None

    # 1) Preferred: Kaleido.
    try:
        return pio.to_image(fig, format="png", width=width, height=height, scale=scale)
    except Exception as first_error:
        try:
            st.session_state["pdf_visual_export_error"] = f"Kaleido export failed: {first_error}"
        except Exception:
            pass

    # 2) Try automatic Kaleido setup and retry.
    try:
        ok, msg = ensure_pdf_visual_exporter()
        if ok:
            try:
                return pio.to_image(fig, format="png", width=width, height=height, scale=scale)
            except Exception as retry_error:
                try:
                    st.session_state["pdf_visual_export_error"] = f"Kaleido retry failed: {retry_error}"
                except Exception:
                    pass
    except Exception:
        pass

    # 3) Exact browser screenshot from the Plotly HTML.
    try:
        with tempfile.TemporaryDirectory() as td:
            td_path = Path(td)
            html_path = td_path / "plotly_visual.html"
            png_path = td_path / "plotly_visual.png"

            html = fig.to_html(
                full_html=True,
                include_plotlyjs=True,
                config={"displayModeBar": False, "responsive": False},
                default_width=f"{width}px",
                default_height=f"{height}px",
            )
            # Dark body helps match the simulator views.
            html = html.replace(
                "<body>",
                '<body style="margin:0; background:#0e1117; overflow:hidden;">',
            )
            html_path.write_text(html, encoding="utf-8")

            browser_errors = []
            for browser in _candidate_browsers_for_screenshot():
                cmd = [
                    browser,
                    "--headless",
                    "--disable-gpu",
                    "--no-sandbox",
                    "--disable-dev-shm-usage",
                    f"--window-size={int(width)},{int(height)}",
                    f"--screenshot={str(png_path)}",
                    html_path.as_uri(),
                ]
                try:
                    result = subprocess.run(
                        cmd,
                        capture_output=True,
                        text=True,
                        timeout=90,
                    )
                    if png_path.exists() and png_path.stat().st_size > 1000:
                        return png_path.read_bytes()
                    browser_errors.append((browser, result.returncode, result.stderr[-300:]))
                except Exception as browser_error:
                    browser_errors.append((browser, "error", str(browser_error)[-300:]))

            if browser_errors:
                try:
                    st.session_state["pdf_visual_export_error"] = f"Browser screenshot export failed: {browser_errors[-1]}"
                except Exception:
                    pass
    except Exception as browser_outer_error:
        try:
            st.session_state["pdf_visual_export_error"] = f"Browser screenshot export unavailable: {browser_outer_error}"
        except Exception:
            pass

    # 4) Final non-blank engineering fallback. This is not as perfect as Plotly,
    # but it prevents empty PDF pages and preserves the actual trace data.
    try:
        import matplotlib
        matplotlib.use("Agg")
        import matplotlib.pyplot as plt
        from mpl_toolkits.mplot3d.art3d import Poly3DCollection
        from matplotlib import cm
        from matplotlib.colors import Normalize

        fig_mpl = plt.figure(figsize=(width / 160.0, height / 160.0), dpi=160)
        ax = fig_mpl.add_subplot(111, projection="3d")
        ax.set_facecolor("#0e1117")
        fig_mpl.patch.set_facecolor("#0e1117")
        all_x, all_y, all_z = [], [], []
        colorbar_added = False

        def _arr(v):
            try:
                return list(v) if v is not None else []
            except Exception:
                return []

        for tr in fig.data:
            tname = getattr(tr, "type", "")
            name = getattr(tr, "name", "") or ""

            if tname == "mesh3d":
                x = _arr(getattr(tr, "x", [])); y = _arr(getattr(tr, "y", [])); z = _arr(getattr(tr, "z", []))
                i = _arr(getattr(tr, "i", [])); j = _arr(getattr(tr, "j", [])); k = _arr(getattr(tr, "k", []))
                if not x or not y or not z or not i:
                    continue

                max_faces = min(len(i), 12000)
                step = max(1, len(i) // max_faces)
                verts = []
                for a, b, c in zip(i[::step], j[::step], k[::step]):
                    try:
                        verts.append([(x[int(a)], y[int(a)], z[int(a)]), (x[int(b)], y[int(b)], z[int(b)]), (x[int(c)], y[int(c)], z[int(c)])])
                    except Exception:
                        continue

                face_color = "#9acd32" if "object" in name.lower() or "pressure" in name.lower() else "#bdbdbd"
                try:
                    intensity = getattr(tr, "intensity", None)
                    if intensity is not None:
                        vals = _arr(intensity)
                        finite_vals = [float(v) for v in vals if v is not None]
                        if finite_vals:
                            norm = Normalize(vmin=min(finite_vals), vmax=max(finite_vals) if max(finite_vals) != min(finite_vals) else min(finite_vals)+1e-12)
                            cmap = cm.get_cmap("turbo")
                            facecolors = [cmap(norm(float(vals[min(n*step, len(vals)-1)]))) for n in range(len(verts))]
                            poly = Poly3DCollection(verts, facecolors=facecolors, edgecolors=(0,0,0,0.08), linewidths=0.02, alpha=0.92)
                        else:
                            poly = Poly3DCollection(verts, facecolors=face_color, edgecolors=(0,0,0,0.10), linewidths=0.02, alpha=0.82)
                    else:
                        color = getattr(tr, "color", None) or face_color
                        poly = Poly3DCollection(verts, facecolors=color, edgecolors=(0,0,0,0.10), linewidths=0.02, alpha=0.82)
                except Exception:
                    poly = Poly3DCollection(verts, facecolors=face_color, edgecolors=(0,0,0,0.10), linewidths=0.02, alpha=0.82)

                ax.add_collection3d(poly)
                all_x.extend(x); all_y.extend(y); all_z.extend(z)

            elif tname == "scatter3d":
                x = _arr(getattr(tr, "x", [])); y = _arr(getattr(tr, "y", [])); z = _arr(getattr(tr, "z", []))
                if not x or not y or not z:
                    continue
                marker = getattr(tr, "marker", None)
                size = 6; alpha = 0.55; colors = "#28c7d8"
                if marker is not None:
                    try: size = max(float(getattr(marker, "size", 4) or 4), 1.5)
                    except Exception: pass
                    try: alpha = float(getattr(marker, "opacity", 0.55) or 0.55)
                    except Exception: pass
                    try: colors = getattr(marker, "color", colors)
                    except Exception: pass
                try:
                    if colors is not None and not isinstance(colors, str):
                        sc = ax.scatter(x, y, z, c=list(colors), cmap="turbo", s=size, alpha=alpha, depthshade=False)
                        if not colorbar_added:
                            cbar = fig_mpl.colorbar(sc, ax=ax, shrink=0.65, pad=0.07)
                            cbar.ax.tick_params(colors="white", labelsize=7)
                            cbar.outline.set_edgecolor("white")
                            colorbar_added = True
                    else:
                        ax.scatter(x, y, z, c=colors or "#28c7d8", s=size, alpha=alpha, depthshade=False)
                except Exception:
                    ax.scatter(x, y, z, c="#28c7d8", s=size, alpha=alpha, depthshade=False)
                all_x.extend(x); all_y.extend(y); all_z.extend(z)

            elif tname == "cone":
                x = _arr(getattr(tr, "x", [])); y = _arr(getattr(tr, "y", [])); z = _arr(getattr(tr, "z", []))
                u = _arr(getattr(tr, "u", [])); v = _arr(getattr(tr, "v", [])); w = _arr(getattr(tr, "w", []))
                if x and y and z and u and v and w:
                    ax.quiver(x, y, z, u, v, w, length=0.08, normalize=True, color="#ffcc00")
                    all_x.extend(x); all_y.extend(y); all_z.extend(z)

        if not all_x or not all_y or not all_z:
            return None

        ax.set_xlabel("X [m]", color="white")
        ax.set_ylabel("Y [m]", color="white")
        ax.set_zlabel("Z [m]", color="white")
        ax.tick_params(colors="white", labelsize=7)
        ax.grid(True, alpha=0.22)

        xmin, xmax = min(all_x), max(all_x)
        ymin, ymax = min(all_y), max(all_y)
        zmin, zmax = min(all_z), max(all_z)
        cx, cy, cz = (xmin+xmax)/2, (ymin+ymax)/2, (zmin+zmax)/2
        r = max(xmax-xmin, ymax-ymin, zmax-zmin, 1e-9) / 2
        ax.set_xlim(cx-r, cx+r); ax.set_ylim(cy-r, cy+r); ax.set_zlim(cz-r, cz+r)
        ax.view_init(elev=24, azim=-55)

        try:
            title = fig.layout.title.text or ""
            if title:
                ax.set_title(title, color="white", fontsize=10)
        except Exception:
            pass

        out = BytesIO()
        fig_mpl.tight_layout()
        fig_mpl.savefig(out, format="png", facecolor=fig_mpl.get_facecolor(), bbox_inches="tight")
        plt.close(fig_mpl)
        return out.getvalue()
    except Exception as fallback_error:
        try:
            st.session_state["pdf_visual_export_error"] = f"All image export paths failed: {fallback_error}"
        except Exception:
            pass
        return None



def clean_pdf_visual_png_bytes(data, crop_bottom_fraction=0.14):
    """
    Removes dark footer/export bars beneath Plotly visuals by scanning for
    contiguous dark rows at the bottom of the exported PNG.
    """
    if not data:
        return data
    try:
        from PIL import Image as PILImage
        img = PILImage.open(BytesIO(data)).convert("RGBA")
        w, h = img.size
        arr = np.asarray(img)[..., :3].astype(float)

        row_brightness = arr.mean(axis=(1, 2))
        dark_threshold = 50.0
        last = h - 1
        while last >= 0 and row_brightness[last] < dark_threshold:
            last -= 1

        dark_rows = h - 1 - last
        if dark_rows > int(0.015 * h):
            cut = max(last + 1, int(0.58 * h))
            img = img.crop((0, 0, w, cut))
        else:
            sample_h = max(10, int(h * crop_bottom_fraction))
            bottom = img.crop((0, h - sample_h, w, h))
            px = np.asarray(bottom)[..., :3].astype(float)
            if float(px.mean()) < 35:
                img = img.crop((0, 0, w, max(h - sample_h, int(h * 0.70))))

        out = BytesIO()
        img.save(out, format="PNG")
        return out.getvalue()
    except Exception:
        return data




def prepare_realistic_flow_pdf_figure(fig, bounds_m=None, front_selection="+X front"):
    """
    Makes the Realistic Flow Interference View PDF-friendly:
    - removes excessive margins
    - uses a taller viewport
    - zooms to include the object and wake path
    - keeps the image from being cut off in the PDF
    """
    if fig is None:
        return fig
    try:
        fig.update_layout(
            height=980,
            width=1350,
            margin=dict(l=0, r=15, t=35, b=0),
            paper_bgcolor="white",
        )

        if bounds_m is not None:
            b = np.asarray(bounds_m, dtype=float)
            omin = b[0]
            omax = b[1]
            center = 0.5 * (omin + omax)
            span = np.maximum(omax - omin, 1e-9)
            max_len = float(np.max(span))
            flow_vec = flow_vector_from_front(front_selection)

            # Include object plus downstream wake region.
            wake_center = center + flow_vec * 2.2 * max_len
            view_center = 0.5 * (center + wake_center)
            r_cross = 3.3 * max_len
            r_flow = 4.8 * max_len

            # Use generous ranges so the wake is not clipped.
            x_range = [view_center[0] - r_cross, view_center[0] + r_cross]
            y_range = [view_center[1] - r_cross, view_center[1] + r_cross]
            z_range = [view_center[2] - r_cross, view_center[2] + r_cross]

            main_axis = int(np.argmax(np.abs(flow_vec)))
            if main_axis == 0:
                x_range = [min(center[0] - 1.4 * max_len, wake_center[0] - r_flow),
                           max(center[0] + 1.4 * max_len, wake_center[0] + r_flow)]
            elif main_axis == 1:
                y_range = [min(center[1] - 1.4 * max_len, wake_center[1] - r_flow),
                           max(center[1] + 1.4 * max_len, wake_center[1] + r_flow)]
            else:
                z_range = [min(center[2] - 1.4 * max_len, wake_center[2] - r_flow),
                           max(center[2] + 1.4 * max_len, wake_center[2] + r_flow)]

            fig.update_layout(
                scene=dict(
                    xaxis=dict(range=x_range),
                    yaxis=dict(range=y_range),
                    zaxis=dict(range=z_range),
                    aspectmode="data",
                    camera=dict(eye=dict(x=1.45, y=1.35, z=0.85), center=dict(x=0, y=0, z=0)),
                )
            )
    except Exception:
        pass
    return fig




def add_report_image(report_images, title, fig=None, data=None, caption=""):
    """
    Adds an exact Plotly/Kaleido report image. If image export fails, adds a
    placeholder note rather than inserting an inaccurate approximation.
    """
    if report_images is None:
        return
    img_data = data
    if img_data is None and fig is not None:
        img_data = plotly_fig_to_png_bytes(fig)
    if img_data:
        img_data = clean_pdf_visual_png_bytes(img_data)
        report_images.append({"title": title, "caption": caption, "data": img_data})
    else:
        report_images.append({
            "title": title,
            "caption": (caption + " Visual export used all available routes: Kaleido, headless browser, then data fallback. If this page is blank, install Microsoft Edge/Chrome or run: python -m pip install -U kaleido==0.2.1").strip(),
            "data": None,
        })




def cache_cfd_report_visual(key, title, data, caption=""):
    """
    Saves CFD visual PNG bytes in Streamlit session state so the main customer
    PDF can include them even after the app reruns.
    """
    try:
        if data:
            data = clean_pdf_visual_png_bytes(data)
            st.session_state[key] = {
                "title": title,
                "caption": caption,
                "data": data,
                "timestamp": datetime.now().isoformat(),
            }
    except Exception:
        pass


def append_session_cached_cfd_visuals(report_images):
    """
    Adds the most recently displayed/exported CFD visuals to the PDF.
    This avoids relying on local variables that disappear when Streamlit reruns.
    """
    if report_images is None:
        return 0

    keys = [
        "cached_cfd_pressure_visual",
        "cached_cfd_velocity_visual",
        "cached_cfd_interference_visual",
        "cached_cfd_error_visual",
    ]
    added = 0
    existing_titles = {img.get("title") for img in report_images if isinstance(img, dict)}

    for key in keys:
        item = st.session_state.get(key)
        if not isinstance(item, dict):
            continue
        data = item.get("data")
        title = item.get("title", key)
        if not data or title in existing_titles:
            continue
        report_images.append({
            "title": title,
            "caption": item.get("caption", ""),
            "data": data,
        })
        existing_titles.add(title)
        added += 1

    return added




def make_fluidforce_pdf_report(
    report_title,
    geometry_name,
    mode,
    fluid,
    front_selection,
    altitude_m,
    pressure_pa,
    temperature_k,
    rho,
    mu,
    velocity,
    area,
    length,
    volume,
    mass_kg,
    q_dynamic,
    re,
    fd,
    fl,
    net_force_down,
    terminal_result,
    turbulence_model,
    cfd_auto_settings=None,
    cfd_results=None,
    report_images=None,
):
    """
    Generates a branded Jewlz Technologies / JET FluidForce PDF report.

    The report is intentionally free-use/customer-facing:
      - summarizes inputs
      - documents geometry-derived values
      - lists governing equations
      - reports forces and coefficients
      - includes Jewlz Technologies branding
    """
    if not REPORTLAB_AVAILABLE:
        raise RuntimeError("ReportLab is not installed. Install with: python -m pip install reportlab")

    buffer = BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=letter,
        rightMargin=0.55 * inch,
        leftMargin=0.55 * inch,
        topMargin=0.55 * inch,
        bottomMargin=0.55 * inch,
    )

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "JETTitle",
        parent=styles["Title"],
        fontSize=20,
        leading=24,
        textColor=colors.HexColor("#1F4E79"),
        spaceAfter=8,
    )
    section_style = ParagraphStyle(
        "JETSection",
        parent=styles["Heading2"],
        fontSize=13,
        leading=16,
        textColor=colors.HexColor("#1F4E79"),
        spaceBefore=10,
        spaceAfter=6,
    )
    small_style = ParagraphStyle(
        "JETSmall",
        parent=styles["BodyText"],
        fontSize=8,
        leading=10,
        textColor=colors.HexColor("#444444"),
    )
    body_style = ParagraphStyle(
        "JETBody",
        parent=styles["BodyText"],
        fontSize=9,
        leading=11,
    )

    def fmt(x, digits=6):
        try:
            return f"{float(x):,.{digits}g}"
        except Exception:
            return str(x)

    def table_from_rows(rows, col_widths=None):
        if col_widths is None:
            col_widths = [2.55 * inch, 4.15 * inch]
        t = Table(rows, colWidths=col_widths, hAlign="LEFT")
        t.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#EAF2F8")),
            ("TEXTCOLOR", (0, 0), (-1, 0), colors.HexColor("#1F4E79")),
            ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
            ("FONTNAME", (0, 1), (0, -1), "Helvetica-Bold"),
            ("FONTSIZE", (0, 0), (-1, -1), 8),
            ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#B0B7C3")),
            ("VALIGN", (0, 0), (-1, -1), "TOP"),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#F8FAFC")]),
            ("LEFTPADDING", (0, 0), (-1, -1), 5),
            ("RIGHTPADDING", (0, 0), (-1, -1), 5),
            ("TOPPADDING", (0, 0), (-1, -1), 4),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
        ]))
        return t

    story = []

    # Branded cover page
    logo_bytes = jewlz_logo_bytes()
    if logo_bytes:
        try:
            logo_stream = BytesIO(logo_bytes)
            logo_img = Image(logo_stream, width=4.65 * inch, height=3.72 * inch)
            logo_img.hAlign = "CENTER"
            story.append(logo_img)
            story.append(Spacer(1, 0.18 * inch))
        except Exception:
            pass

    cover_title = ParagraphStyle(
        "JETCoverTitle",
        parent=styles["Title"],
        fontSize=24,
        leading=29,
        alignment=1,
        textColor=colors.HexColor("#A7C92A"),
        spaceAfter=8,
    )
    cover_subtitle = ParagraphStyle(
        "JETCoverSubtitle",
        parent=styles["Title"],
        fontSize=16,
        leading=20,
        alignment=1,
        textColor=colors.HexColor("#49B7C8"),
        spaceAfter=14,
    )
    cover_note = ParagraphStyle(
        "JETCoverNote",
        parent=styles["BodyText"],
        fontSize=10,
        leading=13,
        alignment=1,
        textColor=colors.HexColor("#333333"),
        spaceAfter=6,
    )

    story.append(Paragraph("CFD ANALYSIS REPORT", cover_title))
    story.append(Paragraph("JET FluidForce Simulator", cover_subtitle))
    story.append(Paragraph("Computational Fluid Dynamics Engineering Analysis", cover_note))
    story.append(Spacer(1, 0.10 * inch))

    cover_rows = [
        ["Field", "Value"],
        ["Report Title", report_title],
        ["Geometry File", geometry_name or "Not provided"],
        ["Generated", datetime.now().strftime("%Y-%m-%d %H:%M:%S")],
        ["Simulation Mode", mode],
        ["Fluid", fluid],
        ["Velocity", f"{fmt(velocity)} m/s"],
        ["Reynolds Number", fmt(re)],
        ["CFD / Turbulence Model", turbulence_model],
    ]
    story.append(table_from_rows(cover_rows))
    story.append(Spacer(1, 0.18 * inch))
    story.append(Paragraph("Jewlz Technologies - Empowering The Future Today", cover_note))
    story.append(PageBreak())

    story.append(Paragraph("Jewlz Technologies - JET FluidForce CFD Report", title_style))
    story.append(Paragraph("Generated by Jewlz Technologies | Jewlz Engineering Toolkit (JET) | www.jewlztech.com", small_style))
    story.append(Spacer(1, 0.12 * inch))

    story.append(Paragraph("Project Information", section_style))
    project_rows = [
        ["Field", "Value"],
        ["Report Title", report_title],
        ["Geometry File", geometry_name or "Not provided"],
        ["Generated", datetime.now().strftime("%Y-%m-%d %H:%M:%S")],
        ["Simulation Mode", mode],
        ["Fluid", fluid],
        ["Selected Front / Incoming Flow Reference", front_selection],
    ]
    story.append(table_from_rows(project_rows))

    story.append(Paragraph("Input Conditions", section_style))
    input_rows = [
        ["Quantity", "Value"],
        ["Velocity", f"{fmt(velocity)} m/s"],
        ["Altitude / Depth", f"{fmt(altitude_m)} m"],
        ["Static / Ambient Pressure", f"{fmt(pressure_pa)} Pa"],
        ["Temperature", f"{fmt(temperature_k)} K"],
        ["Density rho", f"{fmt(rho)} kg/m^3"],
        ["Dynamic Viscosity mu", f"{fmt(mu)} Pa*s"],
        ["Mass", f"{fmt(mass_kg)} kg"],
    ]
    story.append(table_from_rows(input_rows))

    story.append(Paragraph("Geometry Summary", section_style))
    geom_rows = [
        ["Quantity", "Value"],
        ["Reference Area Aref", f"{fmt(area)} m^2"],
        ["Characteristic Length L", f"{fmt(length)} m"],
        ["Displaced Object Volume", f"{fmt(volume)} m^3"],
    ]
    story.append(table_from_rows(geom_rows))

    story.append(Paragraph("Governing Equations", section_style))
    equations = [
        "Dynamic pressure: q = 1/2 rho V^2",
        "Reynolds number: Re = rho V L / mu",
        "Quadratic drag estimate: F_D = C_D q A",
        "CFD pressure integration: F = - sum((p - p_inf) A n)",
        "Drag coefficient after CFD: C_D = F_D / (q A_ref)",
        "Lift coefficient after CFD: C_L = F_L / (q A_ref)",
        "Hydrostatic pressure for submerged cases: P = P_atm + rho g h",
    ]
    for eq in equations:
        story.append(Paragraph(f"- {eq}", body_style))

    story.append(Paragraph("Simulation Results", section_style))
    result_rows = [
        ["Quantity", "Value"],
        ["Dynamic Pressure q", f"{fmt(q_dynamic)} Pa"],
        ["Reynolds Number", fmt(re)],
        ["Drag Force", f"{fmt(fd)} N"],
        ["Lift / Downforce", f"{fmt(fl)} N"],
        ["Net Force at Current Velocity", f"{fmt(net_force_down)} N"],
        ["Terminal Velocity", f"{fmt(terminal_result.get('terminal_velocity', 0))} m/s"],
        ["Effective Weight W-B", f"{fmt(terminal_result.get('effective_weight_n', 0))} N"],
        ["Buoyancy Force", f"{fmt(terminal_result.get('buoyancy_n', 0))} N"],
        ["Auto Turbulence Model", turbulence_model],
    ]
    story.append(table_from_rows(result_rows))

    if cfd_auto_settings is not None:
        story.append(Paragraph("Automated CFD Setup", section_style))
        cfd_rows = [
            ["Quantity", "Value"],
            ["Max Object Dimension", f"{fmt(cfd_auto_settings.get('max_object_dimension_m', 0))} m"],
            ["Object Face Count", f"{cfd_auto_settings.get('face_count', 0):,}"],
            ["Base Domain Cells per Direction", str(cfd_auto_settings.get("base_cell_count", "auto"))],
            ["Surface Refinement Level", str(cfd_auto_settings.get("refinement_level", "auto"))],
            ["Upstream Domain Length", f"{cfd_auto_settings.get('domain_scale_upstream', 'auto')} x object size"],
            ["Downstream Domain Length", f"{cfd_auto_settings.get('domain_scale_downstream', 'auto')} x object size"],
            ["Crossflow Padding", f"{cfd_auto_settings.get('domain_scale_cross', 'auto')} x object size"],
        ]
        story.append(table_from_rows(cfd_rows))

    if cfd_results is not None:
        story.append(Paragraph("CFD Pressure-Integrated Coefficients", section_style))
        cfd_result_rows = [
            ["Quantity", "Value"],
            ["Reference Dynamic Pressure q", f"{fmt(cfd_results.get('q_ref', 0))} Pa"],
            ["Reference Area Aref", f"{fmt(cfd_results.get('area_ref', 0))} m^2"],
            ["Drag Force Fd", f"{fmt(cfd_results.get('drag_force', 0))} N"],
            ["Lift Force Fl", f"{fmt(cfd_results.get('lift_force', 0))} N"],
            ["Side Force Fs", f"{fmt(cfd_results.get('side_force', 0))} N"],
            ["Cd = Fd/(q*Aref)", fmt(cfd_results.get("cd", 0))],
            ["Cl = Fl/(q*Aref)", fmt(cfd_results.get("cl", 0))],
            ["Cs = Fs/(q*Aref)", fmt(cfd_results.get("cs", 0))],
            ["Area Basis", cfd_results.get("area_note", "")],
            ["Error Section Quality", cfd_results.get("convergence_quality", "N/A")],
            ["Worst Latest Final Residual", fmt(cfd_results.get("max_final_residual", "N/A"))],
            ["All-Run Max Final Residual", fmt(cfd_results.get("all_run_max_final_residual", "N/A"))],
        ]
        story.append(table_from_rows(cfd_result_rows))

    if report_images:
        story.append(PageBreak())
        story.append(Paragraph("CFD and Engineering Visualizations", section_style))
        story.append(Paragraph(
            "The following figures are captured directly from the simulator views. "
            "They document the geometry, OpenFOAM pressure field, OpenFOAM velocity field, realistic flow interference, force vectors, and error/convergence status when available.",
            body_style
        ))
        for idx_img, img in enumerate(report_images, start=1):
            try:
                title = img.get("title", f"Visualization {idx_img}") if isinstance(img, dict) else f"Visualization {idx_img}"
                data = img.get("data") if isinstance(img, dict) else None
                caption = img.get("caption", "") if isinstance(img, dict) else ""
                if idx_img > 1:
                    story.append(PageBreak())
                story.append(Paragraph(f"Figure {idx_img}. {title}", section_style))
                if caption:
                    story.append(Paragraph(caption, body_style))
                    story.append(Spacer(1, 0.035 * inch))
                if data:
                    image_stream = BytesIO(data)
                    try:
                        from PIL import Image as PILImage
                        pil_img = PILImage.open(BytesIO(data))
                        px_w, px_h = pil_img.size
                        max_w = 7.35 * inch
                        max_h = 6.75 * inch
                        aspect = px_h / max(px_w, 1)
                        draw_w = max_w
                        draw_h = draw_w * aspect
                        if draw_h > max_h:
                            draw_h = max_h
                            draw_w = draw_h / max(aspect, 1e-12)
                        image_stream = BytesIO(data)
                        report_img = Image(image_stream, width=draw_w, height=draw_h)
                    except Exception:
                        image_stream = BytesIO(data)
                        report_img = Image(image_stream, width=7.35 * inch, height=5.90 * inch)
                    report_img.hAlign = "CENTER"
                    story.append(report_img)
                else:
                    story.append(Paragraph(
                        "Exact visual image was not available for this report export. Run this in the same PowerShell environment used for Streamlit if needed: python -m pip install -U kaleido==0.2.1",
                        body_style
                    ))
                story.append(Spacer(1, 0.12 * inch))
            except Exception:
                pass

    story.append(Spacer(1, 0.18 * inch))
    story.append(Paragraph("Engineering Note", section_style))
    story.append(Paragraph(
        "This report is generated by the free Jewlz Engineering Toolkit FluidForce app. "
        "Results are intended for engineering screening, design iteration, and decision support. "
        "For certified design, safety-critical release, or customer deliverables, Jewlz Technologies recommends professional engineering review and validation.",
        body_style
    ))

    story.append(Spacer(1, 0.16 * inch))
    story.append(Paragraph("Generated by Jewlz Technologies - JET FluidForce CFD Simulator - www.jewlztech.com", small_style))

    def _footer(canvas, doc_obj):
        canvas.saveState()
        canvas.setFont("Helvetica", 7)
        canvas.setFillColor(colors.HexColor("#555555"))
        footer_text = "Jewlz Technologies | Empowering The Future Today | Generated by JET FluidForce Simulator | www.jewlztech.com"
        canvas.drawCentredString(letter[0] / 2.0, 0.30 * inch, footer_text)
        canvas.drawRightString(letter[0] - 0.55 * inch, 0.30 * inch, f"Page {doc_obj.page}")
        canvas.restoreState()

    doc.build(story, onFirstPage=_footer, onLaterPages=_footer)
    pdf_bytes = buffer.getvalue()
    buffer.close()
    return pdf_bytes



