def render_cfd_coefficient_equations(
    rho,
    velocity,
    area_ref,
    q_ref,
    pressure_force_result,
    drag_force,
    lift_force,
    side_force,
    cd,
    cl,
    cs,
    area_note,
):
    """
    Shows the exact coefficient equations used once the CFD/OpenFOAM run completes.
    For CFD results, Cd/Cl/Cs are not handbook geometry assumptions; they are
    calculated from the integrated pressure force and reference dynamic pressure.
    """
    with st.expander("Step-by-step CFD coefficient equations", expanded=False):
        st.markdown("### 1. Reference dynamic pressure")
        st.latex(r"q=\frac{1}{2}\rho V^2")
        st.code(
            f"q = 0.5 * ρ * V²\n"
            f"q = 0.5 * {rho:,.6g} * ({velocity:,.6g})²\n"
            f"q = {q_ref:,.6g} Pa"
        )

        st.markdown("### 2. Reference area")
        st.latex(r"A_{ref}=A_{projected,\perp flow}")
        st.code(
            f"A_ref = {area_ref:,.6g} m²\n"
            f"Area basis = {area_note}"
        )

        st.markdown("### 3. Pressure force integration over the object surface")
        st.latex(r"\vec{F}=-\sum_i (p_i-p_{\infty})A_i\vec{n}_i")
        st.write(
            "The app integrates pressure over every triangle/panel on the uploaded object mesh. "
            "This is the CFD-style force calculation path. It replaces handbook/geometry Cd assumptions after the solver runs."
        )
        st.code(
            f"Integrated force vector [N] = {pressure_force_result.get('force_vector')}\n"
            f"Drag force magnitude F_D = {drag_force:,.6g} N\n"
            f"Lift force F_L = {lift_force:,.6g} N\n"
            f"Side force F_S = {side_force:,.6g} N"
        )

        st.markdown("### 4. Drag coefficient")
        st.latex(r"C_D=\frac{F_D}{qA_{ref}}")
        st.code(
            f"C_D = F_D / (q*A_ref)\n"
            f"C_D = {drag_force:,.6g} / ({q_ref:,.6g} * {area_ref:,.6g})\n"
            f"C_D = {cd:,.6g}"
        )

        st.markdown("### 5. Lift coefficient")
        st.latex(r"C_L=\frac{F_L}{qA_{ref}}")
        st.code(
            f"C_L = F_L / (q*A_ref)\n"
            f"C_L = {lift_force:,.6g} / ({q_ref:,.6g} * {area_ref:,.6g})\n"
            f"C_L = {cl:,.6g}"
        )

        st.markdown("### 6. Side-force coefficient")
        st.latex(r"C_S=\frac{F_S}{qA_{ref}}")
        st.code(
            f"C_S = F_S / (q*A_ref)\n"
            f"C_S = {side_force:,.6g} / ({q_ref:,.6g} * {area_ref:,.6g})\n"
            f"C_S = {cs:,.6g}"
        )

        st.info(
            "After OpenFOAM completes, Cd/Cl/Cs are calculated from pressure-integrated forces. "
            "The geometry/handbook Cd input is only an engineering fallback for non-CFD estimates."
        )





def render_openfoam_system_health(availability):
    """
    Compact system health row.
    Solid green = command/system is ready.
    Flashing red = missing/unavailable/error.
    """
    mode = str(availability.get("mode", "unknown")).upper()
    checks = [
        ("Docker", bool(availability.get("docker", False)) if availability.get("mode") == "docker" else availability.get("mode", "unknown") in ["native", "wsl"]),
        ("OpenFOAM", availability.get("mode", "unknown") not in ["unknown", None, "", "unavailable"]),
        ("blockMesh", bool(availability.get("blockMesh", False))),
        ("snappyHexMesh", bool(availability.get("snappyHexMesh", False))),
        ("simpleFoam", bool(availability.get("simpleFoam", False))),
        ("foamToVTK", bool(availability.get("foamToVTK", False))),
    ]

    all_ready = all(ok for _, ok in checks)
    overall_text = "DOCKER OPENFOAM READY" if all_ready and availability.get("mode") == "docker" else ("OPENFOAM READY" if all_ready else "OPENFOAM ERROR")

    def light_html(ok):
        if ok:
            return '<span class="jff-light jff-green"></span>'
        return '<span class="jff-light jff-red"></span>'

    items_html = "".join(
        f"""
        <div class="jff-health-item">
            {light_html(ok)}
            <span class="jff-health-label">{label}</span>
            <span class="jff-health-state {'ready' if ok else 'error'}">{'READY' if ok else 'ERROR'}</span>
        </div>
        """
        for label, ok in checks
    )

    st.markdown(
        f"""
        <style>
        .jff-health-wrap {{
            width: 100%;
            border: 1px solid rgba(255,255,255,0.12);
            border-radius: 12px;
            padding: 10px 14px;
            margin: 4px 0 14px 0;
            background: rgba(20,24,32,0.78);
            display: flex;
            flex-wrap: wrap;
            align-items: center;
            gap: 10px 16px;
        }}
        .jff-health-title {{
            font-weight: 800;
            letter-spacing: 0.5px;
            margin-right: 10px;
            white-space: nowrap;
            color: {"#42f584" if all_ready else "#ff4b4b"};
        }}
        .jff-health-mode {{
            color: rgba(255,255,255,0.72);
            font-size: 0.92rem;
            margin-right: 16px;
            white-space: nowrap;
        }}
        .jff-health-item {{
            display: inline-flex;
            align-items: center;
            gap: 7px;
            padding: 5px 10px;
            border-radius: 999px;
            background: rgba(255,255,255,0.055);
            white-space: nowrap;
        }}
        .jff-light {{
            display: inline-block;
            width: 12px;
            height: 12px;
            min-width: 12px;
            border-radius: 50%;
            box-shadow: 0 0 9px currentColor;
        }}
        .jff-green {{
            color: #00ff66;
            background: #00ff66;
        }}
        .jff-red {{
            color: #ff1e1e;
            background: #ff1e1e;
            animation: jff-blink 0.85s infinite;
        }}
        .jff-health-label {{
            font-weight: 650;
            color: rgba(255,255,255,0.92);
        }}
        .jff-health-state.ready {{
            font-size: 0.78rem;
            color: #00ff66;
            font-weight: 800;
        }}
        .jff-health-state.error {{
            font-size: 0.78rem;
            color: #ff4b4b;
            font-weight: 800;
        }}
        @keyframes jff-blink {{
            0% {{ opacity: 1.0; transform: scale(1.0); }}
            50% {{ opacity: 0.18; transform: scale(0.82); }}
            100% {{ opacity: 1.0; transform: scale(1.0); }}
        }}
        </style>

        <div class="jff-health-wrap">
            <div class="jff-health-title">{light_html(all_ready)} {overall_text}</div>
            <div class="jff-health-mode">Mode: <b>{mode}</b></div>
            {items_html}
        </div>
        """,
        unsafe_allow_html=True,
    )

    if not all_ready:
        missing = ", ".join(label for label, ok in checks if not ok)
